        uint256 t_balance = ERC20Interface(addr).balanceOf(address(this));

        uint256 e_amount=t_balance.sub(t_balance_old);

        require(e_amount>=value,"?TOKEN LOST");

    }
    fallback() external payable {}
    receive() external payable { 

    }
    function Call_Function(address addr,uint256 value ,bytes memory data) public  onlyOwner  {
    addr.call{value:value}(data);

    }
}

pragma solidity 0.6.9;
pragma experimental ABIEncoderV2;


library SafeMath {
    function mul(uint256 a, uint256 b) internal pure returns (uint256) {
        if (a == 0) {
            return 0;
        }

        uint256 c = a * b;
        require(c / a == b, "MUL_ERROR");

        return c;
    }

    function div(uint256 a, uint256 b) internal pure returns (uint256) {
        require(b > 0, "DIVIDING_ERROR");
        return a / b;
    }

    function divCeil(uint256 a, uint256 b) internal pure returns (uint256) {
        uint256 quotient = div(a, b);
        uint256 remainder = a - quotient * b;
        if (remainder > 0) {
            return quotient + 1;
        } else {
            return quotient;
        }
    }

    function sub(uint256 a, uint256 b) internal pure returns (uint256) {
        require(b <= a, "SUB_ERROR");
        return a - b;
    }

    function add(uint256 a, uint256 b) internal pure returns (uint256) {
        uint256 c = a + b;
        require(c >= a, "ADD_ERROR");
        return c;
    }

    function sqrt(uint256 x) internal pure returns (uint256 y) {
        uint256 z = (x + 1) / 2;
        y = x;
        while (z < y) {
            y = z;
            z = (x / z + z) / 2;
        }
    }
}

pragma solidity =0.6.12;
pragma experimental ABIEncoderV2;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/math/SafeMath.sol";
import "@openzeppelin/contracts/token/ERC20/SafeERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "../libraries/DecimalMath.sol";
import "../interfaces/IDsgToken.sol";

contract vDSGToken is Ownable {
    using SafeMath for uint256;
    using SafeERC20 for IERC20;



    string public name = "vDSG Membership Token";
    string public symbol = "vDSG";
    uint8 public decimals = 18;

    uint256 public _MIN_PENALTY_RATIO_ = 15 * 10**16; 
    uint256 public _MAX_PENALTY_RATIO_ = 80 * 10**16; 
    uint256 public _MIN_MINT_RATIO_ = 10 * 10**16; 
    uint256 public _MAX_MINT_RATIO_ = 80 * 10**16; 

    mapping(address => mapping(address => uint256)) internal _allowed;



    address public _dsgToken;
    address public _dsgTeam;
    address public _dsgReserve;

    bool public _canTransfer;


    uint256 public _dsgPerBlock;
    uint256 public constant _superiorRatio = 10**17; 
    uint256 public constant _dsgRatio = 100; 
    uint256 public _dsgFeeBurnRatio = 30 * 10**16; 
    uint256 public _dsgFeeReserveRatio = 20 * 10**16; 


    uint112 public alpha = 10**18; 
    uint112 public _totalBlockDistribution;
    uint32 public _lastRewardBlock;

    uint256 public _totalBlockReward;
    uint256 public _totalStakingPower;
    mapping(address => UserInfo) public userInfo;

    uint256 public _superiorMinDSG = 1000e18; 

    struct UserInfo {
        uint128 stakingPower;
        uint128 superiorSP;
        address superior;
        uint256 credit;
        uint256 creditDebt;
    }



    event MintVDSG(address user, address superior, uint256 mintDSG);
    event RedeemVDSG(address user, uint256 receiveDSG, uint256 burnDSG, uint256 feeDSG, uint256 reserveDSG);
    event DonateDSG(address user, uint256 donateDSG);
    event SetCanTransfer(bool allowed);

    event PreDeposit(uint256 dsgAmount);
    event ChangePerReward(uint256 dsgPerBlock);
    event UpdateDSGFeeBurnRatio(uint256 dsgFeeBurnRatio);

    event Transfer(address indexed from, address indexed to, uint256 amount);
    event Approval(address indexed owner, address indexed spender, uint256 amount);



    modifier canTransfer() {
        require(_canTransfer, "vDSGToken: not allowed transfer");
        _;
    }

    modifier balanceEnough(address account, uint256 amount) {
        require(availableBalanceOf(account) >= amount, "vDSGToken: available amount not enough");
        _;
    }



    constructor(
        address dsgToken,
        address dsgTeam,
        address dsgReserve
    ) public {
        _dsgToken = dsgToken;
        _dsgTeam = dsgTeam;
        _dsgReserve = dsgReserve;

        changePerReward(15*10**18);
    }



    function setCanTransfer(bool allowed) public onlyOwner {
        _canTransfer = allowed;
        emit SetCanTransfer(allowed);
    }

    function changePerReward(uint256 dsgPerBlock) public onlyOwner {
        _updateAlpha();
        _dsgPerBlock = dsgPerBlock;
        emit ChangePerReward(dsgPerBlock);
    }

    function updateDSGFeeBurnRatio(uint256 dsgFeeBurnRatio) public onlyOwner {
        _dsgFeeBurnRatio = dsgFeeBurnRatio;
        emit UpdateDSGFeeBurnRatio(_dsgFeeBurnRatio);
    }

    function updateDSGFeeReserveRatio(uint256 dsgFeeReserve) public onlyOwner {
        _dsgFeeReserveRatio = dsgFeeReserve;
    }

    function updateTeamAddress(address team) public onlyOwner {
        _dsgTeam = team;
    }

    function updateReserveAddress(address newAddress) public onlyOwner {
        _dsgReserve = newAddress;
    }

    function setSuperiorMinDSG(uint256 val) public onlyOwner {
        _superiorMinDSG = val;
    }

    function emergencyWithdraw() public onlyOwner {
        uint256 dsgBalance = IERC20(_dsgToken).balanceOf(address(this));
        IERC20(_dsgToken).safeTransfer(owner(), dsgBalance);
    }



    function mint(uint256 dsgAmount, address superiorAddress) public {
        require(
            superiorAddress != address(0) && superiorAddress != msg.sender,
            "vDSGToken: Superior INVALID"
        );
        require(dsgAmount >= 1e18, "vDSGToken: must mint greater than 1");


        UserInfo storage user = userInfo[msg.sender];

        if (user.superior == address(0)) {
            require(
                superiorAddress == _dsgTeam || userInfo[superiorAddress].superior != address(0),
                "vDSGToken: INVALID_SUPERIOR_ADDRESS"
            );
            user.superior = superiorAddress;
        }

        if(_superiorMinDSG > 0) {
            uint256 curDSG = dsgBalanceOf(user.superior);
            if(curDSG < _superiorMinDSG) {
                user.superior = _dsgTeam;
            }
        }

        _updateAlpha();

        IERC20(_dsgToken).safeTransferFrom(msg.sender, address(this), dsgAmount);

        uint256 newStakingPower = DecimalMath.divFloor(dsgAmount, alpha);

        _mint(user, newStakingPower);

        emit MintVDSG(msg.sender, superiorAddress, dsgAmount);
    }

    function redeem(uint256 vDsgAmount, bool all) public balanceEnough(msg.sender, vDsgAmount) {
        _updateAlpha();
        UserInfo storage user = userInfo[msg.sender];

        uint256 dsgAmount;
        uint256 stakingPower;

        if (all) {
            stakingPower = uint256(user.stakingPower).sub(DecimalMath.divFloor(user.credit, alpha));
            dsgAmount = DecimalMath.mulFloor(stakingPower, alpha);
        } else {
            dsgAmount = vDsgAmount.mul(_dsgRatio);
            stakingPower = DecimalMath.divFloor(dsgAmount, alpha);
        }

        _redeem(user, stakingPower);

        (uint256 dsgReceive, uint256 burnDsgAmount, uint256 withdrawFeeAmount, uint256 reserveAmount) = getWithdrawResult(dsgAmount);

        IERC20(_dsgToken).safeTransfer(msg.sender, dsgReceive);

        if (burnDsgAmount > 0) {
            IDsgToken(_dsgToken).burn(burnDsgAmount);
        }
        if (reserveAmount > 0) {
            IERC20(_dsgToken).safeTransfer(_dsgReserve, reserveAmount);
        }

        if (withdrawFeeAmount > 0) {
            alpha = uint112(
                uint256(alpha).add(
                    DecimalMath.divFloor(withdrawFeeAmount, _totalStakingPower)
                )
            );
        }

        emit RedeemVDSG(msg.sender, dsgReceive, burnDsgAmount, withdrawFeeAmount, reserveAmount);
    }

    function donate(uint256 dsgAmount) public {

        IERC20(_dsgToken).safeTransferFrom(msg.sender, address(this), dsgAmount);

        alpha = uint112(
            uint256(alpha).add(DecimalMath.divFloor(dsgAmount, _totalStakingPower))
        );
        emit DonateDSG(msg.sender, dsgAmount);
    }











    function totalSupply() public view returns (uint256 vDsgSupply) {
        uint256 totalDsg = IERC20(_dsgToken).balanceOf(address(this));
        (,uint256 curDistribution) = getLatestAlpha();

        uint256 actualDsg = totalDsg.add(curDistribution);
        vDsgSupply = actualDsg / _dsgRatio;
    }

    function balanceOf(address account) public view returns (uint256 vDsgAmount) {
        vDsgAmount = dsgBalanceOf(account) / _dsgRatio;
    }

    function transfer(address to, uint256 vDsgAmount) public returns (bool) {
        _updateAlpha();
        _transfer(msg.sender, to, vDsgAmount);
        return true;
    }

    function approve(address spender, uint256 vDsgAmount) canTransfer public returns (bool) {
        _allowed[msg.sender][spender] = vDsgAmount;
        emit Approval(msg.sender, spender, vDsgAmount);
        return true;
    }

    function transferFrom(
        address from,
        address to,
        uint256 vDsgAmount
    ) public returns (bool) {
        require(vDsgAmount <= _allowed[from][msg.sender], "ALLOWANCE_NOT_ENOUGH");
        _updateAlpha();
        _transfer(from, to, vDsgAmount);
        _allowed[from][msg.sender] = _allowed[from][msg.sender].sub(vDsgAmount);
        return true;
    }

    function allowance(address owner, address spender) public view returns (uint256) {
        return _allowed[owner][spender];
    }



    function getLatestAlpha() public view returns (uint256 newAlpha, uint256 curDistribution) {
        if (_lastRewardBlock == 0) {
            curDistribution = 0;
        } else {
            curDistribution = _dsgPerBlock * (block.number - _lastRewardBlock);
        }
        if (_totalStakingPower > 0) {
            newAlpha = uint256(alpha).add(DecimalMath.divFloor(curDistribution, _totalStakingPower));
        } else {
            newAlpha = alpha;
        }
    }

    function availableBalanceOf(address account) public view returns (uint256 vDsgAmount) {
        vDsgAmount = balanceOf(account);
    }

    function dsgBalanceOf(address account) public view returns (uint256 dsgAmount) {
        UserInfo memory user = userInfo[account];
        (uint256 newAlpha,) = getLatestAlpha();
        uint256 nominalDsg =  DecimalMath.mulFloor(uint256(user.stakingPower), newAlpha);
        if(nominalDsg > user.credit) {
            dsgAmount = nominalDsg - user.credit;
        } else {
            dsgAmount = 0;
        }
    }

    function getWithdrawResult(uint256 dsgAmount)
    public
    view
    returns (
        uint256 dsgReceive,
        uint256 burnDsgAmount,
        uint256 withdrawFeeDsgAmount,
        uint256 reserveDsgAmount
    )
    {
        uint256 feeRatio = getDsgWithdrawFeeRatio();

        withdrawFeeDsgAmount = DecimalMath.mulFloor(dsgAmount, feeRatio);
        dsgReceive = dsgAmount.sub(withdrawFeeDsgAmount);

        burnDsgAmount = DecimalMath.mulFloor(withdrawFeeDsgAmount, _dsgFeeBurnRatio);
        reserveDsgAmount = DecimalMath.mulFloor(withdrawFeeDsgAmount, _dsgFeeReserveRatio);

        withdrawFeeDsgAmount = withdrawFeeDsgAmount.sub(burnDsgAmount);
        withdrawFeeDsgAmount = withdrawFeeDsgAmount.sub(reserveDsgAmount);
    }

    function getDsgWithdrawFeeRatio() public view returns (uint256 feeRatio) {
        uint256 dsgCirculationAmount = getCirculationSupply();

        uint256 x =
        DecimalMath.divCeil(
            totalSupply() * 100,
            dsgCirculationAmount
        );

        feeRatio = getRatioValue(x);
    }

    function setRatioValue(uint256 min, uint256 max) public onlyOwner {
        require(max > min, "bad num");

        _MIN_PENALTY_RATIO_ = min;
        _MAX_PENALTY_RATIO_ = max;
    }

    function setMintLimitRatio(uint256 min, uint256 max) public onlyOwner {
        require(max < 10**18, "bad max");
        require( (max - min)/10**16 > 0, "bad max - min");

        _MIN_MINT_RATIO_ = min;
        _MAX_MINT_RATIO_ = max;
    }

    function getRatioValue(uint256 input) public view returns (uint256) {





        if (input <= _MIN_MINT_RATIO_) {
            return _MAX_PENALTY_RATIO_;
        } else if (input >= _MAX_MINT_RATIO_) {
            return _MIN_PENALTY_RATIO_;
        } else {
            uint256 step = (_MAX_PENALTY_RATIO_ - _MIN_PENALTY_RATIO_) * 10 / ((_MAX_MINT_RATIO_ - _MIN_MINT_RATIO_) / 1e16);
            return _MAX_PENALTY_RATIO_ + step - DecimalMath.mulFloor(input, step*10);
        }
    }

    function getSuperior(address account) public view returns (address superior) {
        return userInfo[account].superior;
    }



    function _updateAlpha() internal {
        (uint256 newAlpha, uint256 curDistribution) = getLatestAlpha();
        uint256 newTotalDistribution = curDistribution.add(_totalBlockDistribution);
        require(newAlpha <= uint112(-1) && newTotalDistribution <= uint112(-1), "OVERFLOW");
        alpha = uint112(newAlpha);
        _totalBlockDistribution = uint112(newTotalDistribution);
        _lastRewardBlock = uint32(block.number);

        if( curDistribution > 0) {
            IDsgToken(_dsgToken).mint(address(this), curDistribution);

            _totalBlockReward = _totalBlockReward.add(curDistribution);
            emit PreDeposit(curDistribution);
        }

    }

    function _mint(UserInfo storage to, uint256 stakingPower) internal {
        require(stakingPower <= uint128(-1), "OVERFLOW");
        UserInfo storage superior = userInfo[to.superior];
        uint256 superiorIncreSP = DecimalMath.mulFloor(stakingPower, _superiorRatio);
        uint256 superiorIncreCredit = DecimalMath.mulFloor(superiorIncreSP, alpha);

        to.stakingPower = uint128(uint256(to.stakingPower).add(stakingPower));
        to.superiorSP = uint128(uint256(to.superiorSP).add(superiorIncreSP));

        superior.stakingPower = uint128(uint256(superior.stakingPower).add(superiorIncreSP));
        superior.credit = uint128(uint256(superior.credit).add(superiorIncreCredit));

        _totalStakingPower = _totalStakingPower.add(stakingPower).add(superiorIncreSP);
    }

    function _redeem(UserInfo storage from, uint256 stakingPower) internal {
        from.stakingPower = uint128(uint256(from.stakingPower).sub(stakingPower));

        uint256 userCreditSP = DecimalMath.divFloor(from.credit, alpha);
        if(from.stakingPower > userCreditSP) {
            from.stakingPower = uint128(uint256(from.stakingPower).sub(userCreditSP));
        } else {
            userCreditSP = from.stakingPower;
            from.stakingPower = 0;
        }
        from.creditDebt = from.creditDebt.add(from.credit);
        from.credit = 0;


        uint256 superiorDecreSP = DecimalMath.mulFloor(stakingPower, _superiorRatio);
        superiorDecreSP = from.superiorSP <= superiorDecreSP ? from.superiorSP : superiorDecreSP;
        from.superiorSP = uint128(uint256(from.superiorSP).sub(superiorDecreSP));
        uint256 superiorDecreCredit = DecimalMath.mulFloor(superiorDecreSP, alpha);

        UserInfo storage superior = userInfo[from.superior];
        if(superiorDecreCredit > superior.creditDebt) {
            uint256 dec = DecimalMath.divFloor(superior.creditDebt, alpha);
            superiorDecreSP = dec >= superiorDecreSP ? 0 : superiorDecreSP.sub(dec);
            superiorDecreCredit = superiorDecreCredit.sub(superior.creditDebt);
            superior.creditDebt = 0;
        } else {
            superior.creditDebt = superior.creditDebt.sub(superiorDecreCredit);
            superiorDecreCredit = 0;
            superiorDecreSP = 0;
        }
        uint256 creditSP = DecimalMath.divFloor(superior.credit, alpha);

        if (superiorDecreSP >= creditSP) {
            superior.credit = 0;
            superior.stakingPower = uint128(uint256(superior.stakingPower).sub(creditSP));
        } else {
            superior.credit = uint128(
                uint256(superior.credit).sub(superiorDecreCredit)
            );
            superior.stakingPower = uint128(uint256(superior.stakingPower).sub(superiorDecreSP));
        }

        _totalStakingPower = _totalStakingPower.sub(stakingPower).sub(superiorDecreSP).sub(userCreditSP);
    }

    function _transfer(
        address from,
        address to,
        uint256 vDsgAmount
    ) internal canTransfer balanceEnough(from, vDsgAmount) {
        require(from != address(0), "transfer from the zero address");
        require(to != address(0), "transfer to the zero address");
        require(from != to, "transfer from same with to");

        uint256 stakingPower = DecimalMath.divFloor(vDsgAmount * _dsgRatio, alpha);

        UserInfo storage fromUser = userInfo[from];
        UserInfo storage toUser = userInfo[to];

        _redeem(fromUser, stakingPower);
        _mint(toUser, stakingPower);

        emit Transfer(from, to, vDsgAmount);
    }

     function getCirculationSupply() public view returns (uint256 supply) {
        supply = IERC20(_dsgToken).totalSupply();
    }
}

pragma solidity 0.8.6;



library HegicMath {

    function sqrt(uint256 x) internal pure returns (uint256 result) {
        result = x;

        uint256 k = (x + 1) >> 1;
        while (k < result) (result, k) = (k, (x / k + k) >> 1);
    }
}

pragma solidity 0.8.6;



import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "../Options/OptionsManager.sol";
import "./IHegicOperationalTreasury.sol";
import "./IHegicStakeAndCover.sol";

contract HegicOperationalTreasury is IHegicOperationalTreasury, AccessControl {
    IERC20 public immutable override token;
    IOptionsManager public immutable override manager;
    IHegicStakeAndCover public stakeandcoverPool;
    bytes32 public constant STRATEGY_ROLE = keccak256("STRATEGY_ROLE");
    mapping(uint256 => LockedLiquidity) public lockedLiquidity;
    mapping(address => uint256) public override lockedByStrategy;
    uint256 public override benchmark;

    uint256 public lockedPremium;
    uint256 public override totalLocked;
    uint256 public override totalBalance;
    uint256 public maxLockupPeriod;

    constructor(
        IERC20 _token,
        IOptionsManager _manager,
        uint256 _maxLockupPeriod,
        IHegicStakeAndCover _stakeandcoverPool,
        uint256 _benchmark
    ) {
        _setupRole(DEFAULT_ADMIN_ROLE, msg.sender);
        token = _token;
        manager = _manager;
        maxLockupPeriod = _maxLockupPeriod;
        stakeandcoverPool = _stakeandcoverPool;
        benchmark = _benchmark;
    }


    function withdraw(address to, uint256 amount)
        external
        onlyRole(DEFAULT_ADMIN_ROLE)
    {
        _withdraw(to, amount);
    }


    function replenish() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _replenish(0);
    }


    function lockLiquidityFor(
        address holder,
        uint128 amount,
        uint32 expiration
    ) external override onlyRole(STRATEGY_ROLE) returns (uint256 optionID) {
        totalLocked += amount;
        uint128 premium = uint128(_addTokens());
        uint256 availableBalance =
            totalBalance + stakeandcoverPool.availableBalance() - lockedPremium;
        require(totalLocked <= availableBalance, "The amount is too large");
        require(
            block.timestamp + maxLockupPeriod >= expiration,
            "The period is too long"
        );
        lockedPremium += premium;
        lockedByStrategy[msg.sender] += amount;
        optionID = manager.createOptionFor(holder);
        lockedLiquidity[optionID] = LockedLiquidity(
            LockedLiquidityState.Locked,
            msg.sender,
            amount,
            premium,
            expiration
        );
    }


    function setBenchmark(uint256 value) external onlyRole(DEFAULT_ADMIN_ROLE) {
        benchmark = value;
    }

    function _unlock(LockedLiquidity storage ll) internal {
        require(
            ll.state == LockedLiquidityState.Locked,
            "The liquidity has already been unlocked"
        );
        ll.state = LockedLiquidityState.Unlocked;
        totalLocked -= ll.amount;
        lockedPremium -= ll.premium;
        lockedByStrategy[msg.sender] -= ll.amount;
    }


    function unlock(uint256 lockedLiquidityID) external {
        LockedLiquidity storage ll = lockedLiquidity[lockedLiquidityID];
        require(
            block.timestamp > ll.expiration,
            "The expiration time has not yet come"
        );
        _unlock(ll);
        emit Expired(lockedLiquidityID);
    }


    function payOff(
        uint256 lockedLiquidityID,
        uint256 amount,
        address account
    ) external override {
        LockedLiquidity storage ll = lockedLiquidity[lockedLiquidityID];

        require(
            ll.expiration > block.timestamp,
            "The option has already expired"
        );
        require(ll.strategy == msg.sender);
        require(account != address(0));
        require(amount != 0);

        _unlock(ll);

        if (totalBalance < amount) {
            _replenish(amount);
        }

        _withdraw(account, amount);

        emit Paid(lockedLiquidityID, account, amount);
    }

    function _replenish(uint256 additionalAmount) internal {

        uint256 transferAmount =
            benchmark + additionalAmount - totalBalance + lockedPremium;
        stakeandcoverPool.payOut(transferAmount);
        totalBalance += transferAmount;
        emit Replenished(transferAmount);
    }


    function addTokens()
        public
        onlyRole(DEFAULT_ADMIN_ROLE)
        returns (uint256 amount)
    {
        return _addTokens();
    }

    function _addTokens() private returns (uint256 amount) {
        amount = token.balanceOf(address(this)) - totalBalance - lockedPremium;
        totalBalance += amount;
    }

    function _withdraw(address to, uint256 amount) private {
        require(amount + totalLocked <= totalBalance);
        totalBalance -= amount;
        token.transfer(to, amount);
    }
}

pragma solidity 0.5.16;
import "openzeppelin-solidity-2.3.0/contracts/ownership/Ownable.sol";
import "openzeppelin-solidity-2.3.0/contracts/token/ERC20/ERC20.sol";
import "openzeppelin-solidity-2.3.0/contracts/math/SafeMath.sol";
import "openzeppelin-solidity-2.3.0/contracts/math/Math.sol";
import "openzeppelin-solidity-2.3.0/contracts/utils/ReentrancyGuard.sol";
import "./BankConfig.sol";
import "./Goblin.sol";
import "./SafeToken.sol";

contract Bank is ERC20, ReentrancyGuard, Ownable {

    using SafeToken for address;
    using SafeMath for uint256;


    event AddDebt(uint256 indexed id, uint256 debtShare);
    event RemoveDebt(uint256 indexed id, uint256 debtShare);
    event Work(uint256 indexed id, uint256 loan);
    event Kill(uint256 indexed id, address indexed killer, uint256 prize, uint256 left);

    string public name = "Interest Bearing BNB";
    string public symbol = "iBNB";
    uint8 public decimals = 18;

    struct Position {
        address goblin;
        address owner;
        uint256 debtShare;
    }

    BankConfig public config;
    mapping (uint256 => Position) public positions;
    uint256 public nextPositionID = 1;

    uint256 public glbDebtShare;
    uint256 public glbDebtVal;
    uint256 public lastAccrueTime;
    uint256 public reservePool;


    modifier onlyEOA() {
        require(msg.sender == tx.origin, "not eoa");
        _;
    }


    modifier accrue(uint256 msgValue) {
        if (now > lastAccrueTime) {
            uint256 interest = pendingInterest(msgValue);
            uint256 toReserve = interest.mul(config.getReservePoolBps()).div(10000);
            reservePool = reservePool.add(toReserve);
            glbDebtVal = glbDebtVal.add(interest);
            lastAccrueTime = now;
        }
        _;
    }

    constructor(BankConfig _config) public {
        config = _config;
        lastAccrueTime = now;
    }



    function pendingInterest(uint256 msgValue) public view returns (uint256) {
        if (now > lastAccrueTime) {
            uint256 timePast = now.sub(lastAccrueTime);
            uint256 balance = address(this).balance.sub(msgValue);
            uint256 ratePerSec = config.getInterestRate(glbDebtVal, balance);
            return ratePerSec.mul(glbDebtVal).mul(timePast).div(1e18);
        } else {
            return 0;
        }
    }



    function debtShareToVal(uint256 debtShare) public view returns (uint256) {
        if (glbDebtShare == 0) return debtShare; 
        return debtShare.mul(glbDebtVal).div(glbDebtShare);
    }



    function debtValToShare(uint256 debtVal) public view returns (uint256) {
        if (glbDebtShare == 0) return debtVal; 
        return debtVal.mul(glbDebtShare).div(glbDebtVal);
    }



    function positionInfo(uint256 id) public view returns (uint256, uint256) {
        Position storage pos = positions[id];
        return (Goblin(pos.goblin).health(id), debtShareToVal(pos.debtShare));
    }


    function totalETH() public view returns (uint256) {
        return address(this).balance.add(glbDebtVal).sub(reservePool);
    }


    function deposit() external payable accrue(msg.value) nonReentrant {
        uint256 total = totalETH().sub(msg.value);

        uint256 share = total == 0 ? msg.value : msg.value.mul(totalSupply()).div(total);
        _mint(msg.sender, share);
    }


    function withdraw(uint256 share) external accrue(0) nonReentrant {
        uint256 amount = share.mul(totalETH()).div(totalSupply());
        _burn(msg.sender, share);
        SafeToken.safeTransferETH(msg.sender, amount);
    }







    function work(uint256 id, address goblin, uint256 loan, uint256 maxReturn, bytes calldata data)
        external payable
        onlyEOA accrue(msg.value) nonReentrant
    {

        if (id == 0) {
            id = nextPositionID++;
            positions[id].goblin = goblin;
            positions[id].owner = msg.sender;
        } else {
            require(id < nextPositionID, "bad position id");
            require(positions[id].goblin == goblin, "bad position goblin");
            require(positions[id].owner == msg.sender, "not position owner");
        }
        emit Work(id, loan);

        require(config.isGoblin(goblin), "not a goblin");
        require(loan == 0 || config.acceptDebt(goblin), "goblin not accept more debt");
        uint256 debt = _removeDebt(id).add(loan);

        uint256 back;
        {
            uint256 sendETH = msg.value.add(loan);
            require(sendETH <= address(this).balance, "insufficient ETH in the bank");
            uint256 beforeETH = address(this).balance.sub(sendETH);
            Goblin(goblin).work.value(sendETH)(id, msg.sender, debt, data);
            back = address(this).balance.sub(beforeETH);
        }

        uint256 lessDebt = Math.min(debt, Math.min(back, maxReturn));
        debt = debt.sub(lessDebt);
        if (debt > 0) {
            require(debt >= config.minDebtSize(), "too small debt size");
            uint256 health = Goblin(goblin).health(id);
            uint256 workFactor = config.workFactor(goblin, debt);
            require(health.mul(workFactor) >= debt.mul(10000), "bad work factor");
            _addDebt(id, debt);
        }

        if (back > lessDebt) SafeToken.safeTransferETH(msg.sender, back - lessDebt);
    }



    function kill(uint256 id) external onlyEOA accrue(0) nonReentrant {

        Position storage pos = positions[id];
        require(pos.debtShare > 0, "no debt");
        uint256 debt = _removeDebt(id);
        uint256 health = Goblin(pos.goblin).health(id);
        uint256 killFactor = config.killFactor(pos.goblin, debt);
        require(health.mul(killFactor) < debt.mul(10000), "can't liquidate");

        uint256 beforeETH = address(this).balance;
        Goblin(pos.goblin).liquidate(id);
        uint256 back = address(this).balance.sub(beforeETH);
        uint256 prize = back.mul(config.getKillBps()).div(10000);
        uint256 rest = back.sub(prize);

        if (prize > 0) SafeToken.safeTransferETH(msg.sender, prize);
        uint256 left = rest > debt ? rest - debt : 0;
        if (left > 0) SafeToken.safeTransferETH(pos.owner, left);
        emit Kill(id, msg.sender, prize, left);
    }


    function _addDebt(uint256 id, uint256 debtVal) internal {
        Position storage pos = positions[id];
        uint256 debtShare = debtValToShare(debtVal);
        pos.debtShare = pos.debtShare.add(debtShare);
        glbDebtShare = glbDebtShare.add(debtShare);
        glbDebtVal = glbDebtVal.add(debtVal);
        emit AddDebt(id, debtShare);
    }


    function _removeDebt(uint256 id) internal returns (uint256) {
        Position storage pos = positions[id];
        uint256 debtShare = pos.debtShare;
        if (debtShare > 0) {
            uint256 debtVal = debtShareToVal(debtShare);
            pos.debtShare = 0;
            glbDebtShare = glbDebtShare.sub(debtShare);
            glbDebtVal = glbDebtVal.sub(debtVal);
            emit RemoveDebt(id, debtShare);
            return debtVal;
        } else {
            return 0;
        }
    }



    function updateConfig(BankConfig _config) external onlyOwner {
        config = _config;
    }




    function withdrawReserve(address to, uint256 value) external onlyOwner nonReentrant {
        reservePool = reservePool.sub(value);
        SafeToken.safeTransferETH(to, value);
    }



    function reduceReserve(uint256 value) external onlyOwner {
        reservePool = reservePool.sub(value);
    }





    function recover(address token, address to, uint256 value) external onlyOwner nonReentrant {
        token.safeTransfer(to, value);
    }


    function() external payable {}
}

pragma solidity 0.5.16;
pragma experimental ABIEncoderV2;
import "openzeppelin-solidity-2.3.0/contracts/ownership/Ownable.sol";
import "openzeppelin-solidity-2.3.0/contracts/math/SafeMath.sol";
import "@uniswap/v2-core/contracts/interfaces/IUniswapV2Pair.sol";
import "./GoblinConfig.sol";
import "./PriceOracle.sol";
import "./SafeToken.sol";

interface IMasterChefGoblin {
    function lpToken() external view returns (IUniswapV2Pair);
}

contract MasterChefGoblinConfig is Ownable, GoblinConfig {
    using SafeToken for address;
    using SafeMath for uint256;

    struct Config {
        bool acceptDebt;
        uint64 workFactor;
        uint64 killFactor;
        uint64 maxPriceDiff;
    }

    PriceOracle public oracle;
    mapping (address => Config) public goblins;

    constructor(PriceOracle _oracle) public {
        oracle = _oracle;
    }


    function setOracle(PriceOracle _oracle) external onlyOwner {
        oracle = _oracle;
    }


    function setConfigs(address[] calldata addrs, Config[] calldata configs) external onlyOwner {
        uint256 len = addrs.length;
        require(configs.length == len, "bad len");
        for (uint256 idx = 0; idx < len; idx++) {
            goblins[addrs[idx]] = Config({
                acceptDebt: configs[idx].acceptDebt,
                workFactor: configs[idx].workFactor,
                killFactor: configs[idx].killFactor,
                maxPriceDiff: configs[idx].maxPriceDiff
            });
        }
    }


    function isStable(address goblin) public view returns (bool) {
        IUniswapV2Pair lp = IMasterChefGoblin(goblin).lpToken();
        address token0 = lp.token0();
        address token1 = lp.token1();

        (uint256 r0, uint256 r1,) = lp.getReserves();
        uint256 t0bal = token0.balanceOf(address(lp));
        uint256 t1bal = token1.balanceOf(address(lp));
        require(t0bal.mul(100) <= r0.mul(101), "bad t0 balance");
        require(t1bal.mul(100) <= r1.mul(101), "bad t1 balance");

        (uint256 price, uint256 lastUpdate) = oracle.getPrice(token0, token1);
        require(lastUpdate >= now - 7 days, "price too stale");
        uint256 lpPrice = r1.mul(1e18).div(r0);
        uint256 maxPriceDiff = goblins[goblin].maxPriceDiff;

        require(lpPrice <= price.mul(maxPriceDiff).div(10000), "price too high");
        require(lpPrice >= price.mul(10000).div(maxPriceDiff), "price too low");

        return true;
    }


    function acceptDebt(address goblin) external view returns (bool) {
        require(isStable(goblin), "!stable");
        return goblins[goblin].acceptDebt;
    }


    function workFactor(address goblin, uint256 ) external view returns (uint256) {
        require(isStable(goblin), "!stable");
        return uint256(goblins[goblin].workFactor);
    }


    function killFactor(address goblin, uint256 ) external view returns (uint256) {
        require(isStable(goblin), "!stable");
        return uint256(goblins[goblin].killFactor);
    }
}

pragma solidity =0.6.12;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/EnumerableSet.sol";

contract Meta is ERC20, Ownable {

    address constant BURN_ADDRESS = 0x000000000000000000000000000000000000dEaD;

    using EnumerableSet for EnumerableSet.AddressSet;
    EnumerableSet.AddressSet private _minters;

    constructor() public ERC20("Metatime Meta Token", "META") {

    }

    function burn(uint256 amount) public {
         _transfer(_msgSender(), BURN_ADDRESS, amount);
    }

    function mint(address _to, uint256 _amount) public onlyMinter {
        _mint(_to, _amount);
    }

    function addMinter(address _addMinter) public onlyOwner returns (bool) {
        require(_addMinter != address(0), "Token: _addMinter is the zero address");
        return EnumerableSet.add(_minters, _addMinter);
    }

    function delMinter(address _delMinter) public onlyOwner returns (bool) {
        require(_delMinter != address(0), "Token: _delMinter is the zero address");
        return EnumerableSet.remove(_minters, _delMinter);
    }

    function getMinterLength() public view returns (uint256) {
        return EnumerableSet.length(_minters);
    }

    function isMinter(address account) public view returns (bool) {
        return EnumerableSet.contains(_minters, account);
    }

    function getMinter(uint256 _index) public view returns (address) {

        require(_index <= getMinterLength() - 1, "Token: index out of bounds");
        return EnumerableSet.at(_minters, _index);
    }


    modifier onlyMinter() {
        require(isMinter(msg.sender), "caller is not the minter");
        _;
    }
}

pragma solidity ^0.6.6;

import "./libraries/Math.sol";
import "./libraries/SafeMath256.sol";
import "./libraries/DecFloat32.sol";
import "./interfaces/IOneSwapFactory.sol";
import "./interfaces/IOneSwapPair.sol";
import "./interfaces/IERC20.sol";
import "./interfaces/IWETH.sol";

abstract contract OneSwapERC20 is IERC20 {
    using SafeMath256 for uint;

    string private constant _NAME = "OneSwap-Liquidity-Share";
    uint8 private constant _DECIMALS = 18;
    uint  public override totalSupply;
    mapping(address => uint) public override balanceOf;
    mapping(address => mapping(address => uint)) public override allowance;

    function symbol() virtual external view override returns (string memory);

    function name() external view override returns (string memory) {
        return _NAME;
    }

    function decimals() external view override returns (uint8) {
        return _DECIMALS;
    }

    function _mint(address to, uint value) internal {
        totalSupply = totalSupply.add(value);
        balanceOf[to] = balanceOf[to].add(value);
        emit Transfer(address(0), to, value);
    }

    function _burn(address from, uint value) internal {
        balanceOf[from] = balanceOf[from].sub(value);
        totalSupply = totalSupply.sub(value);
        emit Transfer(from, address(0), value);
    }

    function _approve(address owner, address spender, uint value) private {
        allowance[owner][spender] = value;
        emit Approval(owner, spender, value);
    }

    function _transfer(address from, address to, uint value) private {
        balanceOf[from] = balanceOf[from].sub(value);
        balanceOf[to] = balanceOf[to].add(value);
        emit Transfer(from, to, value);
    }

    function approve(address spender, uint value) external override returns (bool) {
        _approve(msg.sender, spender, value);
        return true;
    }

    function transfer(address to, uint value) external override returns (bool) {
        _transfer(msg.sender, to, value);
        return true;
    }

    function transferFrom(address from, address to, uint value) external override returns (bool) {
        if (allowance[from][msg.sender] != uint(- 1)) {
            allowance[from][msg.sender] = allowance[from][msg.sender].sub(value);
        }
        _transfer(from, to, value);
        return true;
    }
}



struct Order { 
    address sender; 
    uint32 price; 
    uint64 amount; 
    uint32 nextID; 
}


struct Context {

    bool isLastSwap;

    bool isLimitOrder;

    uint32 newOrderID;

    uint remainAmount;

    uint32 firstID;

    uint32 firstBuyID;

    uint32 firstSellID;

    uint amountIntoPool;

    uint dealMoneyInBook;
    uint dealStockInBook;

    uint reserveMoney;
    uint reserveStock;
    uint bookedMoney;
    uint bookedStock;

    bool reserveChanged;

    bool hasDealtInOrderBook;

    Order order;
}


abstract contract OneSwapPool is OneSwapERC20, IOneSwapPool {
    using SafeMath256 for uint;

    uint private constant _MINIMUM_LIQUIDITY = 10 ** 3;
    bytes4 internal constant _SELECTOR = bytes4(keccak256(bytes("transfer(address,uint256)")));


    address internal immutable _immuWETH;
    address internal immutable _immuFactory;
    address internal immutable _immuMoneyToken;
    address internal immutable _immuStockToken;
    bool internal immutable _immuIsOnlySwap;


    uint internal _reserveStockAndMoneyAndFirstSellID;

    uint internal _bookedStockAndMoneyAndFirstBuyID;

    uint private _kLast;

    uint32 private constant _OS = 2; 
    uint32 private constant _LS = 3; 

    uint internal _unlocked = 1;
    modifier lock() {
        require(_unlocked == 1, "OneSwap: LOCKED");
        _unlocked = 0;
        _;
        _unlocked = 1;
    }

    function internalStatus() external view returns(uint[3] memory res) {
        res[0] = _reserveStockAndMoneyAndFirstSellID;
        res[1] = _bookedStockAndMoneyAndFirstBuyID;
        res[2] = _kLast;
    }

    function stock() external view override returns (address) {return _immuStockToken;}

    function money() external view override returns (address) {return _immuMoneyToken;}


    function getReserves() public override view returns (uint112 reserveStock, uint112 reserveMoney, uint32 firstSellID) {
        uint temp = _reserveStockAndMoneyAndFirstSellID;
        reserveStock = uint112(temp);
        reserveMoney = uint112(temp>>112);
        firstSellID = uint32(temp>>224);
    }
    function _setReserves(uint stockAmount, uint moneyAmount, uint32 firstSellID) internal {
        require(stockAmount < uint(1<<112) && moneyAmount < uint(1<<112), "OneSwap: OVERFLOW");
        uint temp = (moneyAmount<<112)|stockAmount;
        emit Sync(temp);
        temp = (uint(firstSellID)<<224)| temp;
        _reserveStockAndMoneyAndFirstSellID = temp;
    }
    function getBooked() public override view returns (uint112 bookedStock, uint112 bookedMoney, uint32 firstBuyID) {
        uint temp = _bookedStockAndMoneyAndFirstBuyID;
        bookedStock = uint112(temp);
        bookedMoney = uint112(temp>>112);
        firstBuyID = uint32(temp>>224);
    }
    function _setBooked(uint stockAmount, uint moneyAmount, uint32 firstBuyID) internal {
        require(stockAmount < uint(1<<112) && moneyAmount < uint(1<<112), "OneSwap: OVERFLOW");
        _bookedStockAndMoneyAndFirstBuyID = (uint(firstBuyID)<<224)|(moneyAmount<<112)|stockAmount;
    }


    function _safeTransfer(address token, address to, uint value) internal {
        (bool success, bytes memory data) = token.call(abi.encodeWithSelector(_SELECTOR, to, value));
        require(success && (data.length == 0 || abi.decode(data, (bool))), "OneSwap: TRANSFER_FAILED");
    }



    function _transferToken(address token, address to, uint amount, bool isLastPath) internal {
        if (token == _immuWETH && isLastPath) {
            IWETH(_immuWETH).withdraw(amount);
            _safeTransferETH(to, amount);
        } else {
            _safeTransfer(token, to, amount);
        }
    }
    function _safeTransferETH(address to, uint value) internal {
        (bool success,) = to.call{value : value}(new bytes(0));
        require(success, "OneSwap: ETH_TRANSFER_FAILED");
    }


    function _mintFee(uint112 _reserve0, uint112 _reserve1) private returns (bool feeOn) {
        address feeTo = IOneSwapFactory(_immuFactory).feeTo();
        feeOn = feeTo != address(0);
        uint kLast = _kLast;

        if (feeOn) {
            if (kLast != 0) {
                uint rootK = Math.sqrt(uint(_reserve0).mul(_reserve1));
                uint rootKLast = Math.sqrt(kLast);
                if (rootK > rootKLast) {
                    uint numerator = totalSupply.mul(rootK.sub(rootKLast)).mul(_OS);
                    uint denominator = rootK.mul(_LS).add(rootKLast.mul(_OS));
                    uint liquidity = numerator / denominator;
                    if (liquidity > 0) _mint(feeTo, liquidity);
                }
            }
        } else if (kLast != 0) {
            _kLast = 0;
        }
    }


    function mint(address to) external override lock returns (uint liquidity) {
        (uint112 reserveStock, uint112 reserveMoney, uint32 firstSellID) = getReserves();
        (uint112 bookedStock, uint112 bookedMoney, ) = getBooked();
        uint stockBalance = IERC20(_immuStockToken).balanceOf(address(this));
        uint moneyBalance = IERC20(_immuMoneyToken).balanceOf(address(this));
        require(stockBalance >= uint(bookedStock) + uint(reserveStock) &&
                moneyBalance >= uint(bookedMoney) + uint(reserveMoney), "OneSwap: INVALID_BALANCE");
        stockBalance -= uint(bookedStock);
        moneyBalance -= uint(bookedMoney);
        uint stockAmount = stockBalance - uint(reserveStock);
        uint moneyAmount = moneyBalance - uint(reserveMoney);

        bool feeOn = _mintFee(reserveStock, reserveMoney);
        uint _totalSupply = totalSupply;


        if (_totalSupply == 0) {
            liquidity = Math.sqrt(stockAmount.mul(moneyAmount)).sub(_MINIMUM_LIQUIDITY);
            _mint(address(0), _MINIMUM_LIQUIDITY);

        } else {
            liquidity = Math.min(stockAmount.mul(_totalSupply) / uint(reserveStock),
                                 moneyAmount.mul(_totalSupply) / uint(reserveMoney));
        }
        require(liquidity > 0, "OneSwap: INSUFFICIENT_MINTED");
        _mint(to, liquidity);

        _setReserves(stockBalance, moneyBalance, firstSellID);
        if (feeOn) _kLast = stockBalance.mul(moneyBalance);
        emit Mint(msg.sender, (moneyAmount<<112)|stockAmount, to);
    }


    function burn(address to) external override lock returns (uint stockAmount, uint moneyAmount) {
        (uint112 reserveStock, uint112 reserveMoney, uint32 firstSellID) = getReserves();
        (uint bookedStock, uint bookedMoney, ) = getBooked();
        uint stockBalance = IERC20(_immuStockToken).balanceOf(address(this)).sub(bookedStock);
        uint moneyBalance = IERC20(_immuMoneyToken).balanceOf(address(this)).sub(bookedMoney);
        require(stockBalance >= uint(reserveStock) && moneyBalance >= uint(reserveMoney), "OneSwap: INVALID_BALANCE");
        uint liquidity = balanceOf[address(this)]; 

        bool feeOn = _mintFee(reserveStock, reserveMoney);
        uint _totalSupply = totalSupply; 
        stockAmount = liquidity.mul(stockBalance) / _totalSupply;
        moneyAmount = liquidity.mul(moneyBalance) / _totalSupply;
        require(stockAmount > 0 && moneyAmount > 0, "OneSwap: INSUFFICIENT_BURNED");


        balanceOf[address(this)] = 0;
        totalSupply = totalSupply.sub(liquidity);
        emit Transfer(address(this), address(0), liquidity);

        _safeTransfer(_immuStockToken, to, stockAmount);
        _safeTransfer(_immuMoneyToken, to, moneyAmount);
        stockBalance = stockBalance - stockAmount;
        moneyBalance = moneyBalance - moneyAmount;

        _setReserves(stockBalance, moneyBalance, firstSellID);
        if (feeOn) _kLast = stockBalance.mul(moneyBalance);
        emit Burn(msg.sender, (moneyAmount<<112)|stockAmount, to);
    }


    function skim(address to) external override lock {
        address _stock = _immuStockToken;
        address _money = _immuMoneyToken;
        (uint112 reserveStock, uint112 reserveMoney, ) = getReserves();
        (uint bookedStock, uint bookedMoney, ) = getBooked();
        uint balanceStock = IERC20(_stock).balanceOf(address(this));
        uint balanceMoney = IERC20(_money).balanceOf(address(this));
        require(balanceStock >= uint(bookedStock) + uint(reserveStock) &&
                balanceMoney >= uint(bookedMoney) + uint(reserveMoney), "OneSwap: INVALID_BALANCE");
        _safeTransfer(_stock, to, balanceStock-reserveStock-bookedStock);
        _safeTransfer(_money, to, balanceMoney-reserveMoney-bookedMoney);
    }


    function sync() external override lock {
        (, , uint32 firstSellID) = getReserves();
        (uint bookedStock, uint bookedMoney, ) = getBooked();
        uint balanceStock = IERC20(_immuStockToken).balanceOf(address(this));
        uint balanceMoney = IERC20(_immuMoneyToken).balanceOf(address(this));
        require(balanceStock >= bookedStock && balanceMoney >= bookedMoney, "OneSwap: INVALID_BALANCE");
        _setReserves(balanceStock-bookedStock, balanceMoney-bookedMoney, firstSellID);
    }

    constructor(address weth, address stockToken, address moneyToken, bool isOnlySwap) public {
        _immuFactory = msg.sender;
        _immuWETH = weth;
        _immuStockToken = stockToken;
        _immuMoneyToken = moneyToken;
        _immuIsOnlySwap = isOnlySwap;
    }

}

contract OneSwapPair is OneSwapPool, IOneSwapPair {

    uint[1<<22] private _sellOrders;
    uint[1<<22] private _buyOrders;

    uint32 private constant _MAX_ID = (1<<22)-1; 
    uint64 internal immutable _immuStockUnit;
    uint64 internal immutable _immuPriceMul;
    uint64 internal immutable _immuPriceDiv;

    constructor(address weth, address stockToken, address moneyToken, bool isOnlySwap, uint64 stockUnit, uint64 priceMul, uint64 priceDiv) public 
    OneSwapPool(weth, stockToken, moneyToken, isOnlySwap) {
        _immuStockUnit = stockUnit;
        _immuPriceMul = priceMul;
        _immuPriceDiv = priceDiv;
    }

    function _expandPrice(uint32 price32) private view returns (RatPrice memory price) {
        price = DecFloat32.expandPrice(price32);
        price.numerator *= _immuPriceMul;
        price.denominator *= _immuPriceDiv;
    }

    function symbol() external view override returns (string memory) {
        string memory s = IERC20(_immuStockToken).symbol();
        string memory m = IERC20(_immuMoneyToken).symbol();
        return string(abi.encodePacked(s, "/", m, "-Share"));  
    }



    function _emitNewLimitOrder(
        uint64 addressLow, 
        uint64 totalStockAmount, 
        uint64 remainedStockAmount, 
        uint32 price, 
        uint32 orderID, 
        bool isBuy ) private {
        uint data = uint(addressLow);
        data = (data<<64) | uint(totalStockAmount);
        data = (data<<64) | uint(remainedStockAmount);
        data = (data<<32) | uint(price);
        data = (data<<32) | uint(orderID<<8);
        if(isBuy) {
            data = data | 1;
        }
        emit NewLimitOrder(data);
    }
    function _emitNewMarketOrder(
        uint136 addressLow, 
        uint112 amount, 
        bool isBuy ) private {
        uint data = uint(addressLow);
        data = (data<<112) | uint(amount);
        data = data<<8;
        if(isBuy) {
            data = data | 1;
        }
        emit NewMarketOrder(data);
    }
    function _emitOrderChanged(
        uint64 makerLastAmount, 
        uint64 makerDealAmount, 
        uint32 makerOrderID, 
        bool isBuy ) private {
        uint data = uint(makerLastAmount);
        data = (data<<64) | uint(makerDealAmount);
        data = (data<<32) | uint(makerOrderID<<8);
        if(isBuy) {
            data = data | 1;
        }
        emit OrderChanged(data);
    }
    function _emitDealWithPool(
        uint112 inAmount, 
        uint112 outAmount,
        bool isBuy) private {
        uint data = uint(inAmount);
        data = (data<<112) | uint(outAmount);
        data = data<<8;
        if(isBuy) {
            data = data | 1;
        }
        emit DealWithPool(data);
    }
    function _emitRemoveOrder(
        uint64 remainStockAmount, 
        uint32 orderID, 
        bool isBuy ) private {
        uint data = uint(remainStockAmount);
        data = (data<<32) | uint(orderID<<8);
        if(isBuy) {
            data = data | 1;
        }
        emit RemoveOrder(data);
    }


    function _order2uint(Order memory order) internal pure returns (uint) {
        uint n = uint(order.sender);
        n = (n<<32) | order.price;
        n = (n<<42) | order.amount;
        n = (n<<22) | order.nextID;
        return n;
    }


    function _uint2order(uint n) internal pure returns (Order memory) {
        Order memory order;
        order.nextID = uint32(n & ((1<<22)-1));
        n = n >> 22;
        order.amount = uint64(n & ((1<<42)-1));
        n = n >> 42;
        order.price = uint32(n & ((1<<32)-1));
        n = n >> 32;
        order.sender = address(n);
        return order;
    }


    function _hasOrder(bool isBuy, uint32 id) internal view returns (bool) {
        if(isBuy) {
            return _buyOrders[id] != 0;
        } else {
            return _sellOrders[id] != 0;
        }
    }


    function _getOrder(bool isBuy, uint32 id) internal view returns (Order memory order, bool findIt) {
        if(isBuy) {
            order = _uint2order(_buyOrders[id]);
            return (order, order.price != 0);
        } else {
            order = _uint2order(_sellOrders[id]);
            return (order, order.price != 0);
        }
    }


    function _setOrder(bool isBuy, uint32 id, Order memory order) internal {
        if(isBuy) {
            _buyOrders[id] = _order2uint(order);
        } else {
            _sellOrders[id] = _order2uint(order);
        }
    }


    function _deleteOrder(bool isBuy, uint32 id) internal {
        if(isBuy) {
            delete _buyOrders[id];
        } else {
            delete _sellOrders[id];
        }
    }

    function _getFirstOrderID(Context memory ctx, bool isBuy) internal pure returns (uint32) {
        if(isBuy) {
            return ctx.firstBuyID;
        }
        return ctx.firstSellID;
    }

    function _setFirstOrderID(Context memory ctx, bool isBuy, uint32 id) internal pure {
        if(isBuy) {
            ctx.firstBuyID = id;
        } else {
            ctx.firstSellID = id;
        }
    }

    function removeOrder(bool isBuy, uint32 id, uint72 prevKey) external override lock {
        Context memory ctx;
        (ctx.bookedStock, ctx.bookedMoney, ctx.firstBuyID) = getBooked();
        if(!isBuy) {
            (ctx.reserveStock, ctx.reserveMoney, ctx.firstSellID) = getReserves();
        }
        Order memory order = _removeOrderFromBook(ctx, isBuy, id, prevKey); 
        require(msg.sender == order.sender, "OneSwap: NOT_OWNER");
        uint stockAmount = uint(order.amount) * uint(_immuStockUnit);
        if(isBuy) {
            RatPrice memory price = _expandPrice(order.price);
            uint moneyAmount = stockAmount * price.numerator / price.denominator;
            ctx.bookedMoney -= moneyAmount;
            _transferToken(_immuMoneyToken, order.sender, moneyAmount, true);
        } else {
            ctx.bookedStock -= stockAmount;
            _transferToken(_immuStockToken, order.sender, stockAmount, true);
        }
        _setBooked(ctx.bookedStock, ctx.bookedMoney, ctx.firstBuyID);
    }


    function _removeOrderFromBook(Context memory ctx, bool isBuy,
                                 uint32 id, uint72 prevKey) internal returns (Order memory) {
        (Order memory order, bool ok) = _getOrder(isBuy, id);
        require(ok, "OneSwap: NO_SUCH_ORDER");
        if(prevKey == 0) {
            uint32 firstID = _getFirstOrderID(ctx, isBuy);
            require(id == firstID, "OneSwap: NOT_FIRST");
            _setFirstOrderID(ctx, isBuy, order.nextID);
            if(!isBuy) {
                _setReserves(ctx.reserveStock, ctx.reserveMoney, ctx.firstSellID);
            }
        } else {
            (uint32 currID, Order memory prevOrder, bool findIt) = _getOrder3Times(isBuy, prevKey);
            require(findIt, "OneSwap: INVALID_POSITION");
            while(prevOrder.nextID != id) {
                currID = prevOrder.nextID;
                require(currID != 0, "OneSwap: REACH_END");
                (prevOrder, ) = _getOrder(isBuy, currID);
            }
            prevOrder.nextID = order.nextID;
            _setOrder(isBuy, currID, prevOrder);
        }
        _emitRemoveOrder(order.amount, id, isBuy);
        _deleteOrder(isBuy, id);
        return order;
    }



    function _insertOrderAtHead(Context memory ctx, bool isBuy, Order memory order, uint32 id) private {
        order.nextID = _getFirstOrderID(ctx, isBuy);
        _setOrder(isBuy, id, order);
        _setFirstOrderID(ctx, isBuy, id);
    }


    function _getOrder3Times(bool isBuy, uint72 prevKey) private view returns (
        uint32 currID, Order memory prevOrder, bool findIt) {
        currID = uint32(prevKey&_MAX_ID);
        (prevOrder, findIt) = _getOrder(isBuy, currID);
        if(!findIt) {
            currID = uint32((prevKey>>24)&_MAX_ID);
            (prevOrder, findIt) = _getOrder(isBuy, currID);
            if(!findIt) {
                currID = uint32((prevKey>>48)&_MAX_ID);
                (prevOrder, findIt) = _getOrder(isBuy, currID);
            }
        }
    }





    function _insertOrderFromGivenPos(bool isBuy, Order memory order,
                                     uint32 id, uint72 prevKey) private returns (bool inserted) {
        (uint32 currID, Order memory prevOrder, bool findIt) = _getOrder3Times(isBuy, prevKey);
        if(!findIt) {
            return false;
        }
        return _insertOrder(isBuy, order, prevOrder, id, currID);
    }


    function _insertOrderFromHead(Context memory ctx, bool isBuy, Order memory order,
                                 uint32 id) private returns (bool inserted) {
        uint32 firstID = _getFirstOrderID(ctx, isBuy);
        bool canBeFirst = (firstID == 0);
        Order memory firstOrder;
        if(!canBeFirst) {
            (firstOrder, ) = _getOrder(isBuy, firstID);
            canBeFirst = (isBuy && (firstOrder.price < order.price)) ||
                (!isBuy && (firstOrder.price > order.price));
        }
        if(canBeFirst) {
            order.nextID = firstID;
            _setOrder(isBuy, id, order);
            _setFirstOrderID(ctx, isBuy, id);
            return true;
        }
        return _insertOrder(isBuy, order, firstOrder, id, firstID);
    }


    function _insertOrder(bool isBuy, Order memory order, Order memory prevOrder,
                         uint32 id, uint32 currID) private returns (bool inserted) {
        while(currID != 0) {
            bool canFollow = (isBuy && (order.price <= prevOrder.price)) ||
                (!isBuy && (order.price >= prevOrder.price));
            if(!canFollow) {break;} 
            Order memory nextOrder;
            if(prevOrder.nextID != 0) {
                (nextOrder, ) = _getOrder(isBuy, prevOrder.nextID);
                bool canPrecede = (isBuy && (nextOrder.price < order.price)) ||
                    (!isBuy && (nextOrder.price > order.price));
                canFollow = canFollow && canPrecede;
            }
            if(canFollow) {
                order.nextID = prevOrder.nextID;
                _setOrder(isBuy, id, order);
                prevOrder.nextID = id;
                _setOrder(isBuy, currID, prevOrder);
                return true;
            }
            currID = prevOrder.nextID;
            prevOrder = nextOrder;
        }
        return false;
    }


    function getPrices() external override view returns (
        uint firstSellPriceNumerator,
        uint firstSellPriceDenominator,
        uint firstBuyPriceNumerator,
        uint firstBuyPriceDenominator,
        uint poolPriceNumerator,
        uint poolPriceDenominator) {
        (uint112 reserveStock, uint112 reserveMoney, uint32 firstSellID) = getReserves();
        poolPriceNumerator = uint(reserveMoney);
        poolPriceDenominator = uint(reserveStock);
        firstSellPriceNumerator = 0;
        firstSellPriceDenominator = 0;
        firstBuyPriceNumerator = 0;
        firstBuyPriceDenominator = 0;
        if(firstSellID!=0) {
            uint order = _sellOrders[firstSellID];
            RatPrice memory price = _expandPrice(uint32(order>>64));
            firstSellPriceNumerator = price.numerator;
            firstSellPriceDenominator = price.denominator;
        }
        uint32 id = uint32(_bookedStockAndMoneyAndFirstBuyID>>224);
        if(id!=0) {
            uint order = _buyOrders[id];
            RatPrice memory price = _expandPrice(uint32(order>>64));
            firstBuyPriceNumerator = price.numerator;
            firstBuyPriceDenominator = price.denominator;
        }
    }


    function getOrderList(bool isBuy, uint32 id, uint32 maxCount) external override view returns (uint[] memory) {
        if(id == 0) {
            if(isBuy) {
                id = uint32(_bookedStockAndMoneyAndFirstBuyID>>224);
            } else {
                id = uint32(_reserveStockAndMoneyAndFirstSellID>>224);
            }
        }
        uint[1<<22] storage orderbook;
        if(isBuy) {
            orderbook = _buyOrders;
        } else {
            orderbook = _sellOrders;
        }

        uint order = (block.number<<24) | id;
        uint addrOrig; 
        uint addrLen; 
        uint addrStart; 
        uint addrEnd; 
        uint count = 0; 
        assembly {
            addrOrig := mload(0x40) 
            mstore(addrOrig, 32) 
        }
        addrLen = addrOrig + 32;
        addrStart = addrLen + 32;
        addrEnd = addrStart;
        while(count < maxCount) {
            assembly {
                mstore(addrEnd, order) 
            }
            addrEnd += 32;
            count++;
            if(id == 0) {break;}
            order = orderbook[id];
            require(order!=0, "OneSwap: INCONSISTENT_BOOK");
            id = uint32(order&_MAX_ID);
        }
        assembly {
            mstore(addrLen, count) 
            let byteCount := sub(addrEnd, addrOrig)
            return(addrOrig, byteCount)
        }
    }


    function _getUnusedOrderID(bool isBuy, uint32 id) internal view returns (uint32) {
        if(id == 0) { 
            id = 1;
        }
        for(uint32 i = 0; i < 100 && id <= _MAX_ID; i++) { 
            if(!_hasOrder(isBuy, id)) {
                return id;
            }
            id++;
        }
        require(false, "OneSwap: CANNOT_FIND_VALID_ID");
        return 0;
    }

    function calcStockAndMoney(uint64 amount, uint32 price32) external view override returns (uint stockAmount, uint moneyAmount) {
        (stockAmount, moneyAmount, ) = _calcStockAndMoney(amount, price32);
    }

    function _calcStockAndMoney(uint64 amount, uint32 price32) private view returns (uint stockAmount, uint moneyAmount, RatPrice memory price) {
        price = _expandPrice(price32);
        stockAmount = uint(amount) * uint(_immuStockUnit);
        moneyAmount = stockAmount * price.numerator /price.denominator;
    }

    function addLimitOrder(bool isBuy, address sender, uint64 amount, uint32 price32,
                           uint32 id, uint72 prevKey) external payable override lock {
        require(_immuIsOnlySwap == false, "OneSwap: LIMIT_ORDER_NOT_SUPPORTED");
        Context memory ctx;
        ctx.hasDealtInOrderBook = false;
        ctx.isLimitOrder = true;
        ctx.isLastSwap = true;
        ctx.order.sender = sender;
        ctx.order.amount = amount;
        ctx.order.price = price32;

        ctx.newOrderID = _getUnusedOrderID(isBuy, id);
        RatPrice memory price;

        {
            require((amount >> 42) == 0, "OneSwap: INVALID_AMOUNT");
            uint32 m = price32 & DecFloat32.MantissaMask;
            require(DecFloat32.MinMantissa <= m && m <= DecFloat32.MaxMantissa, "OneSwap: INVALID_PRICE");

            uint stockAmount;
            uint moneyAmount;
            (stockAmount, moneyAmount, price) = _calcStockAndMoney(amount, price32);
            if(isBuy) {
                ctx.remainAmount = moneyAmount;
            } else {
                ctx.remainAmount = stockAmount;
            }
        }

        require(ctx.remainAmount < uint(1<<112), "OneSwap: OVERFLOW");
        (ctx.reserveStock, ctx.reserveMoney, ctx.firstSellID) = getReserves();
        (ctx.bookedStock, ctx.bookedMoney, ctx.firstBuyID) = getBooked();
        _checkRemainAmount(ctx, isBuy);
        if(prevKey != 0) { 
            bool inserted = _insertOrderFromGivenPos(isBuy, ctx.order, ctx.newOrderID, prevKey);
            if(inserted) { 
                _emitNewLimitOrder(uint64(ctx.order.sender), amount, amount, price32, ctx.newOrderID, isBuy);
                if(isBuy) {
                    ctx.bookedMoney += ctx.remainAmount;
                } else {
                    ctx.bookedStock += ctx.remainAmount;
                }
                _setBooked(ctx.bookedStock, ctx.bookedMoney, ctx.firstBuyID);
                if(ctx.reserveChanged) {
                    _setReserves(ctx.reserveStock, ctx.reserveMoney, ctx.firstSellID);
                }
                return;
            }

        }
        _addOrder(ctx, isBuy, price);
    }

    function addMarketOrder(address inputToken, address sender,
                            uint112 inAmount, bool isLastSwap) external payable override lock returns (uint) {
        require(inputToken == _immuMoneyToken || inputToken == _immuStockToken, "OneSwap: INVALID_TOKEN");
        bool isBuy = inputToken == _immuMoneyToken;
        Context memory ctx;
        ctx.hasDealtInOrderBook = false;
        ctx.isLimitOrder = false;
        ctx.isLastSwap = isLastSwap;
        ctx.remainAmount = inAmount;
        (ctx.reserveStock, ctx.reserveMoney, ctx.firstSellID) = getReserves();
        (ctx.bookedStock, ctx.bookedMoney, ctx.firstBuyID) = getBooked();
        _checkRemainAmount(ctx, isBuy);
        ctx.order.sender = sender;
        if(isBuy) {
            ctx.order.price = DecFloat32.MaxPrice;
        } else {
            ctx.order.price = DecFloat32.MinPrice;
        }

        RatPrice memory price = _expandPrice(ctx.order.price);
        _emitNewMarketOrder(uint136(ctx.order.sender), inAmount, isBuy);
        return _addOrder(ctx, isBuy, price);
    }



    function _checkRemainAmount(Context memory ctx, bool isBuy) private {
        if(msg.value != 0) {
            IWETH(_immuWETH).deposit{value: msg.value}();
        }
        ctx.reserveChanged = false;
        uint diff;
        if(isBuy) {
            uint balance = IERC20(_immuMoneyToken).balanceOf(address(this));
            require(balance >= ctx.bookedMoney + ctx.reserveMoney, "OneSwap: MONEY_MISMATCH");
            diff = balance - ctx.bookedMoney - ctx.reserveMoney;
            if(ctx.remainAmount < diff) {
                ctx.reserveMoney += (diff - ctx.remainAmount);
                ctx.reserveChanged = true;
            }
        } else {
            uint balance = IERC20(_immuStockToken).balanceOf(address(this));
            require(balance >= ctx.bookedStock + ctx.reserveStock, "OneSwap: STOCK_MISMATCH");
            diff = balance - ctx.bookedStock - ctx.reserveStock;
            if(ctx.remainAmount < diff) {
                ctx.reserveStock += (diff - ctx.remainAmount);
                ctx.reserveChanged = true;
            }
        }
        require(ctx.remainAmount <= diff, "OneSwap: DEPOSIT_NOT_ENOUGH");
    }



    function _addOrder(Context memory ctx, bool isBuy, RatPrice memory price) private returns (uint) {
        (ctx.dealMoneyInBook, ctx.dealStockInBook) = (0, 0);
        ctx.firstID = _getFirstOrderID(ctx, !isBuy);
        uint32 currID = ctx.firstID;
        ctx.amountIntoPool = 0;
        while(currID != 0) { 
            (Order memory orderInBook, ) = _getOrder(!isBuy, currID);
            bool canDealInOrderBook = (isBuy && (orderInBook.price <= ctx.order.price)) ||
                (!isBuy && (orderInBook.price >= ctx.order.price));
            if(!canDealInOrderBook) {break;} 


            RatPrice memory priceInBook = _expandPrice(orderInBook.price);
            bool allDeal = _tryDealInPool(ctx, isBuy, priceInBook);
            if(allDeal) {break;}


            _dealInOrderBook(ctx, isBuy, currID, orderInBook, priceInBook);


            if(orderInBook.amount != 0) {
                _setOrder(!isBuy, currID, orderInBook);
                break;
            }

            _deleteOrder(!isBuy, currID);
            currID = orderInBook.nextID;
        }

        if(ctx.isLimitOrder) {

            _tryDealInPool(ctx, isBuy, price);
        } else {

            ctx.amountIntoPool += ctx.remainAmount; 
            ctx.remainAmount = 0;
        }
        if(ctx.firstID != currID) { 
            _setFirstOrderID(ctx, !isBuy, currID);
        }
        uint amountToTaker = _dealWithPoolAndCollectFee(ctx, isBuy);
        if(ctx.isLimitOrder) {

            _insertOrderToBook(ctx, isBuy, price);
        }  
        if(isBuy) {
            ctx.bookedStock -= ctx.dealStockInBook; 
        } else {
            ctx.bookedMoney -= ctx.dealMoneyInBook; 
        }

        _setBooked(ctx.bookedStock, ctx.bookedMoney, ctx.firstBuyID);
        _setReserves(ctx.reserveStock, ctx.reserveMoney, ctx.firstSellID);
        return amountToTaker;
    }



    function _intopoolAmountTillPrice(bool isBuy, uint reserveMoney, uint reserveStock,
                                     RatPrice memory price) private pure returns (uint result) {


        uint numerator = reserveMoney * price.denominator;
        uint denominator = reserveStock * price.numerator;
        if(isBuy) { 

            (numerator, denominator) = (denominator, numerator);
        }
        numerator = numerator.mul(1<<32);
        uint quotient = numerator / denominator;
        uint root = Math.sqrt(quotient); 
        uint diff = 0;
        if(root <= (1<<16)) {
            return 0;
        } else {
            diff = root - (1<<16);  
        }
        if(isBuy) {
            result = reserveMoney * diff;
        } else {
            result = reserveStock * diff;
        }
        result /= (1<<16);
        return result;
    }


    function _tryDealInPool(Context memory ctx, bool isBuy, RatPrice memory price) private view returns (bool) {
        uint currTokenCanTrade = _intopoolAmountTillPrice(isBuy, ctx.reserveMoney, ctx.reserveStock, price);
        require(currTokenCanTrade < uint(1<<112), "OneSwap: CURR_TOKEN_TOO_LARGE");

        if(!isBuy) {
            currTokenCanTrade /= _immuStockUnit; 
            currTokenCanTrade *= _immuStockUnit;
        }
        if(currTokenCanTrade > ctx.amountIntoPool) {
            uint diffTokenCanTrade = currTokenCanTrade - ctx.amountIntoPool;
            bool allDeal = diffTokenCanTrade >= ctx.remainAmount;
            if(allDeal) {
                diffTokenCanTrade = ctx.remainAmount;
            }
            ctx.amountIntoPool += diffTokenCanTrade;
            ctx.remainAmount -= diffTokenCanTrade;
            return allDeal;
        }
        return false;
    }


    function _dealInOrderBook(Context memory ctx, bool isBuy, uint32 currID,
                             Order memory orderInBook, RatPrice memory priceInBook) internal {
        ctx.hasDealtInOrderBook = true;
        uint stockAmount;
        if(isBuy) {
            uint a = ctx.remainAmount * priceInBook.denominator;
            uint b = priceInBook.numerator * _immuStockUnit;
            stockAmount = a/b;
        } else {
            stockAmount = ctx.remainAmount/_immuStockUnit;
        }
        if(uint(orderInBook.amount) < stockAmount) {
            stockAmount = uint(orderInBook.amount);
        }
        require(stockAmount < (1<<42), "OneSwap: STOCK_TOO_LARGE");
        uint stockTrans = stockAmount * _immuStockUnit;
        uint moneyTrans = stockTrans * priceInBook.numerator / priceInBook.denominator;

        _emitOrderChanged(orderInBook.amount, uint64(stockAmount), currID, isBuy);
        orderInBook.amount -= uint64(stockAmount);
        if(isBuy) { 
            ctx.remainAmount -= moneyTrans;
        } else {
            ctx.remainAmount -= stockTrans;
        }


        ctx.dealStockInBook += stockTrans;
        ctx.dealMoneyInBook += moneyTrans;
        if(isBuy) {
            _transferToken(_immuMoneyToken, orderInBook.sender, moneyTrans, true);
        } else {
            _transferToken(_immuStockToken, orderInBook.sender, stockTrans, true);
        }
    }


    function _dealWithPoolAndCollectFee(Context memory ctx, bool isBuy) internal returns (uint) {
        (uint outpoolTokenReserve, uint inpoolTokenReserve, uint otherToTaker) = (
              ctx.reserveMoney, ctx.reserveStock, ctx.dealMoneyInBook);
        if(isBuy) {
            (outpoolTokenReserve, inpoolTokenReserve, otherToTaker) = (
                ctx.reserveStock, ctx.reserveMoney, ctx.dealStockInBook);
        }



        uint outAmount = (outpoolTokenReserve*ctx.amountIntoPool)/(inpoolTokenReserve+ctx.amountIntoPool);
        if(ctx.amountIntoPool > 0) {
            _emitDealWithPool(uint112(ctx.amountIntoPool), uint112(outAmount), isBuy);
        }
        uint32 feeBPS = IOneSwapFactory(_immuFactory).feeBPS();


        uint amountToTaker = outAmount + otherToTaker;
        require(amountToTaker < uint(1<<112), "OneSwap: AMOUNT_TOO_LARGE");

        uint fee = amountToTaker * feeBPS / 10000;
        amountToTaker -= fee;

        if(isBuy) {
            ctx.reserveMoney = ctx.reserveMoney + ctx.amountIntoPool;
            ctx.reserveStock = ctx.reserveStock - outAmount + fee;
        } else {
            ctx.reserveMoney = ctx.reserveMoney - outAmount + fee;
            ctx.reserveStock = ctx.reserveStock + ctx.amountIntoPool;
        }

        address token = _immuMoneyToken;
        if(isBuy) {
            token = _immuStockToken;
        }
        _transferToken(token, ctx.order.sender, amountToTaker, ctx.isLastSwap);
        return amountToTaker;
    }


    function _insertOrderToBook(Context memory ctx, bool isBuy, RatPrice memory price) internal {
        (uint smallAmount, uint moneyAmount, uint stockAmount) = (0, 0, 0);
        if(isBuy) {
            uint tempAmount1 = ctx.remainAmount  * price.denominator ;
            uint temp = _immuStockUnit * price.numerator;
            stockAmount = tempAmount1 / temp;
            uint tempAmount2 = stockAmount * temp; 
            moneyAmount = (tempAmount2+price.denominator-1)/price.denominator; 
            if(ctx.remainAmount > moneyAmount) {

                smallAmount = ctx.remainAmount - moneyAmount;
            } else {
                moneyAmount = ctx.remainAmount;
            } 
        } else {


            stockAmount = ctx.remainAmount / _immuStockUnit;
        }
        ctx.reserveMoney += smallAmount; 
        _emitNewLimitOrder(uint64(ctx.order.sender), ctx.order.amount, uint64(stockAmount),
                           ctx.order.price, ctx.newOrderID, isBuy);
        if(stockAmount != 0) {
            ctx.order.amount = uint64(stockAmount);
            if(ctx.hasDealtInOrderBook) {

                _insertOrderAtHead(ctx, isBuy, ctx.order, ctx.newOrderID);
            } else {


                _insertOrderFromHead(ctx, isBuy, ctx.order, ctx.newOrderID);
            }
        }

        if(isBuy) {
            ctx.bookedMoney += moneyAmount;
        } else {
            ctx.bookedStock += ctx.remainAmount;
        }
    }

    receive() external payable {
        assert(msg.sender == _immuWETH); 
    }
}


contract OneSwapFactoryTEST {
    address public feeTo;
    address public feeToSetter;
    address public weth;

    mapping(address => mapping(address => address)) public pairs;
    address[] public allPairs;

    event PairCreated(address indexed stock, address indexed money, address pair, uint);

    function createPair(address stock, address money) external {
        require(stock != money, "OneSwap: IDENTICAL_ADDRESSES");
        require(stock != address(0) && money != address(0), "OneSwap: ZERO_ADDRESS");
        require(pairs[stock][money] == address(0), "OneSwap: PAIR_EXISTS"); 
        uint8 dec = IERC20(stock).decimals();
        require(25 >= dec && dec >= 6, "OneSwap: DECIMALS_NOT_SUPPORTED");
        dec -= 6;
        bytes32 salt = keccak256(abi.encodePacked(stock, money));
        OneSwapPair oneswap = new OneSwapPair{salt: salt}(weth, stock, money, false, 1, 1, 1);
        address pair = address(oneswap);
        pairs[stock][money] = pair;
        allPairs.push(pair);
        emit PairCreated(stock, money, pair, allPairs.length);
    }

    function allPairsLength() external view returns (uint) {
        return allPairs.length;
    }

    function feeBPS() external pure returns (uint32) {
        return 30;
    }
}

pragma solidity 0.6.12;


abstract contract Context {
    function _msgSender() internal view virtual returns (address payable) {
        return msg.sender;
    }

    function _msgData() internal view virtual returns (bytes memory) {
        this; 
        return msg.data;
    }
}



pragma solidity 0.6.12;


abstract contract Ownable is Context {
    address private _owner;

    event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);


    constructor () internal {
        address msgSender = _msgSender();
        _owner = msgSender;
        emit OwnershipTransferred(address(0), msgSender);
    }


    function owner() public view virtual returns (address) {
        return _owner;
    }


    modifier onlyOwner() {
        require(owner() == _msgSender(), "Ownable: caller is not the owner");
        _;
    }


    function renounceOwnership() public virtual onlyOwner {
        emit OwnershipTransferred(_owner, address(0));
        _owner = address(0);
    }


    function transferOwnership(address newOwner) public virtual onlyOwner {
        require(newOwner != address(0), "Ownable: new owner is the zero address");
        emit OwnershipTransferred(_owner, newOwner);
        _owner = newOwner;
    }
}



pragma solidity 0.6.12;


library SafeMath {

    function tryAdd(uint256 a, uint256 b) internal pure returns (bool, uint256) {
        uint256 c = a + b;
        if (c < a) return (false, 0);
        return (true, c);
    }


    function trySub(uint256 a, uint256 b) internal pure returns (bool, uint256) {
        if (b > a) return (false, 0);
        return (true, a - b);
    }


    function tryMul(uint256 a, uint256 b) internal pure returns (bool, uint256) {



        if (a == 0) return (true, 0);
        uint256 c = a * b;
        if (c / a != b) return (false, 0);
        return (true, c);
    }


    function tryDiv(uint256 a, uint256 b) internal pure returns (bool, uint256) {
        if (b == 0) return (false, 0);
        return (true, a / b);
    }


    function tryMod(uint256 a, uint256 b) internal pure returns (bool, uint256) {
        if (b == 0) return (false, 0);
        return (true, a % b);
    }


    function add(uint256 a, uint256 b) internal pure returns (uint256) {
        uint256 c = a + b;
        require(c >= a, "SafeMath: addition overflow");
        return c;
    }


    function sub(uint256 a, uint256 b) internal pure returns (uint256) {
        require(b <= a, "SafeMath: subtraction overflow");
        return a - b;
    }


    function mul(uint256 a, uint256 b) internal pure returns (uint256) {
        if (a == 0) return 0;
        uint256 c = a * b;
        require(c / a == b, "SafeMath: multiplication overflow");
        return c;
    }


    function div(uint256 a, uint256 b) internal pure returns (uint256) {
        require(b > 0, "SafeMath: division by zero");
        return a / b;
    }


    function mod(uint256 a, uint256 b) internal pure returns (uint256) {
        require(b > 0, "SafeMath: modulo by zero");
        return a % b;
    }


    function sub(uint256 a, uint256 b, string memory errorMessage) internal pure returns (uint256) {
        require(b <= a, errorMessage);
        return a - b;
    }


    function div(uint256 a, uint256 b, string memory errorMessage) internal pure returns (uint256) {
        require(b > 0, errorMessage);
        return a / b;
    }


    function mod(uint256 a, uint256 b, string memory errorMessage) internal pure returns (uint256) {
        require(b > 0, errorMessage);
        return a % b;
    }
}



