import "../interfaces/MGovernance.sol";
import "../libraries/Common.sol";


abstract contract ApprovalChain is MainStorage, MApprovalChain, MGovernance, MFreezable {
    using Addresses for address;

    event LogRemovalIntent(address entry, string entryId);
    event LogRegistered(address entry, string entryId);
    event LogRemoved(address entry, string entryId);

    function addEntry(
        StarkExTypes.ApprovalChainData storage chain,
        address entry,
        uint256 maxLength,
        string memory identifier
    ) internal override onlyGovernance notFrozen {
        address[] storage list = chain.list;
        require(entry.isContract(), "ADDRESS_NOT_CONTRACT");
        bytes32 hash_real = keccak256(abi.encodePacked(Identity(entry).identify()));
        bytes32 hash_identifier = keccak256(abi.encodePacked(identifier));
        require(hash_real == hash_identifier, "UNEXPECTED_CONTRACT_IDENTIFIER");
        require(list.length < maxLength, "CHAIN_AT_MAX_CAPACITY");
        require(findEntry(list, entry) == ENTRY_NOT_FOUND, "ENTRY_ALREADY_EXISTS");



        require(
            list.length == 0 || IQueryableFactRegistry(entry).hasRegisteredFact(),
            "ENTRY_NOT_ENABLED"
        );
        chain.list.push(entry);
        emit LogRegistered(entry, identifier);
    }

    function findEntry(address[] storage list, address entry)
        internal
        view
        override
        returns (uint256)
    {
        uint256 n_entries = list.length;
        for (uint256 i = 0; i < n_entries; i++) {
            if (list[i] == entry) {
                return i;
            }
        }

        return ENTRY_NOT_FOUND;
    }

    function safeFindEntry(address[] storage list, address entry)
        internal
        view
        override
        returns (uint256 idx)
    {
        idx = findEntry(list, entry);

        require(idx != ENTRY_NOT_FOUND, "ENTRY_DOES_NOT_EXIST");
    }


    function announceRemovalIntent(
        StarkExTypes.ApprovalChainData storage chain,
        address entry,
        uint256 removalDelay
    ) internal override onlyGovernance notFrozen {
        safeFindEntry(chain.list, entry);
        require(block.timestamp + removalDelay > block.timestamp, "INVALID_REMOVAL_DELAY");
        require(chain.unlockedForRemovalTime[entry] == 0, "ALREADY_ANNOUNCED");

        chain.unlockedForRemovalTime[entry] = block.timestamp + removalDelay;
        emit LogRemovalIntent(entry, Identity(entry).identify());
    }

    function removeEntry(StarkExTypes.ApprovalChainData storage chain, address entry)
        internal
        override
        onlyGovernance
        notFrozen
    {
        address[] storage list = chain.list;

        uint256 idx = safeFindEntry(list, entry);
        uint256 unlockedForRemovalTime = chain.unlockedForRemovalTime[entry];

        require(unlockedForRemovalTime > 0, "REMOVAL_NOT_ANNOUNCED");
        require(block.timestamp >= unlockedForRemovalTime, "REMOVAL_NOT_ENABLED_YET");

        uint256 n_entries = list.length;


        require(n_entries > 1, "LAST_ENTRY_MAY_NOT_BE_REMOVED");

        if (idx != n_entries - 1) {
            list[idx] = list[n_entries - 1];
        }
        list.pop();
        delete chain.unlockedForRemovalTime[entry];
        emit LogRemoved(entry, Identity(entry).identify());
    }
}

pragma solidity ^0.8.0;

import "../interfaces/IStakingModel.sol";











contract StakingModel is IStakingModel {

    struct User {
        uint104 balance; 
        uint104 energy;  
        uint48 lastUpdatedTime;
    }

    mapping(address => User) private users;

    modifier restrict(uint256 amount) {
        require(amount <= type(uint104).max, "value should <= type(uint104).max");
        _;
    }

    function addVET(address addr, uint256 amount) restrict(amount) internal {
        _update(addr);
        users[addr].balance += uint104(amount);
    }


    function removeVET(address addr, uint256 amount) restrict(amount) internal {
        _update(addr);
        require(users[addr].balance >= uint104(amount), "insuffcient vet");
        users[addr].balance -= uint104(amount);
    }

    function vetBalance(address addr) public override view returns (uint256 amount) {
        return users[addr].balance;
    }

    function addVTHO(address addr, uint256 amount) restrict(amount) internal {
        _update(addr);
        users[addr].energy += uint104(amount);
    }

    function removeVTHO(address addr, uint256 amount) restrict(amount) internal {
        _update(addr);
        require(users[addr].energy >= uint104(amount), "insuffcient vtho");
        users[addr].energy -= uint104(amount);
    }

    function vthoBalance(address addr) public override view returns (uint256 amount) {
        User memory user = users[addr];
        if (user.lastUpdatedTime == 0) {
            return 0;
        }
        return user.energy + calculateVTHO(user.lastUpdatedTime, uint48(block.timestamp), user.balance);
    }


    function _update(address addr) internal {
        uint48 currentTime = uint48(block.timestamp);
        if (users[addr].lastUpdatedTime > 0) {
            assert(users[addr].lastUpdatedTime <= currentTime);
            users[addr].energy += calculateVTHO(
                users[addr].lastUpdatedTime,
                currentTime,
                users[addr].balance
            );
        }

        users[addr].lastUpdatedTime = currentTime;
    }







    function calculateVTHO(
        uint48 t1,
        uint48 t2,
        uint104 vetAmount
    ) public pure returns (uint104 vtho) {
        require(t1 <= t2, "t1 should be <= t2");

        return ((vetAmount * 5) / (10**9)) * (t2 - t1);
    }
}

pragma solidity ^0.5.4;

import './DSLibrary/DSAuth.sol';
import './interface/IERC20Token.sol';
import './interface/ILendFMe.sol';
import './interface/IChai.sol';

library DSMath {
    function add(uint x, uint y) internal pure returns (uint z) {
        require((z = x + y) >= x, "ds-math-add-overflow");
    }
    function sub(uint x, uint y) internal pure returns (uint z) {
        require((z = x - y) <= x, "ds-math-sub-underflow");
    }
    function mul(uint x, uint y) internal pure returns (uint z) {
        require(y == 0 || (z = x * y) / y == x, "ds-math-mul-overflow");
    }
    function div(uint x, uint y) internal pure returns (uint z) {
        require(y > 0, "ds-math-div-overflow");
        z = x / y;
    }
}

contract XSwap is DSAuth {
	using DSMath for uint256;

	uint256 constant internal OFFSET = 10 ** 18;





	address private chai = 0x8a5C1BD4D75e168a4f65eB902c289400B90FD980;
	address private dai  = 0xA3A59273494BB5B8F0a8FAcf21B3f666A47d6140;

	bool private actived;
	address public lendFMe;
	bool public isOpen;
	mapping(address => mapping(address => uint256)) public prices; 
	mapping(address => mapping(address => uint256)) public fee;   
	mapping(address => bool) public supportLending;
	mapping(address => uint256) public decimals;

	constructor() public {
	}

	function active(address _lendFMe) public {
		require(actived == false, "already actived.");
		owner = msg.sender;
		isOpen = true;
		lendFMe = _lendFMe;
		actived = true;
	}


	function trade(address _input, address _output, uint256 _inputAmount) public returns (bool) {
		return trade(_input, _output, _inputAmount, msg.sender);
	}

	function trade(address _input, address _output, uint256 _inputAmount, address _receiver) public returns (bool) {
		require(isOpen, "not open");
		require(prices[_input][_output] != 0, "invalid token address");
		require(decimals[_input] != 0, "input decimal not setteled");
		require(decimals[_output] != 0, "output decimal not setteled");

		NonStandardIERC20Token(_input).transferFrom(msg.sender, address(this), _inputAmount);
		if(supportLending[_input]) {
			if (_input == dai) {
				IChai(chai).join(address(this), _inputAmount);
				ILendFMe(lendFMe).supply(chai, IERC20Token(chai).balanceOf(address(this)));
			}
			else
				ILendFMe(lendFMe).supply(_input, _inputAmount);
		}
		uint256 _tokenAmount = normalizeToken(_input, _inputAmount).mul(prices[_input][_output]).div(OFFSET);
		uint256 _fee = _tokenAmount.mul(fee[_input][_output]).div(OFFSET);
		uint256 _amountToUser = _tokenAmount.sub(_fee);

		if(supportLending[_output]) {
			if (_output == dai) {
				ILendFMe(lendFMe).withdraw(chai, _amountToUser); 
				IChai(chai).draw(address(this), _amountToUser);
			}
			else
				ILendFMe(lendFMe).withdraw(_output, denormalizedToken(_output, _amountToUser));
		}
		NonStandardIERC20Token(_output).transfer(_receiver, denormalizedToken(_output, _amountToUser));
		return true;
	}

	function getTokenLiquidation(address _token) public view returns (uint256) {
		uint256 balanceInDefi = ILendFMe(lendFMe).getSupplyBalance(address(this), _token);
		return balanceInDefi.add(NonStandardIERC20Token(_token).balanceOf(address(this)));
	}

	function setLendFMe(address _lendFMe) public auth returns (bool) {
		lendFMe = _lendFMe;
		return true;
	}

	function enableLending(address _token) public auth returns (bool) {
		require(!supportLending[_token], "the token is already supported lending");
		supportLending[_token] = true;

		if (_token == dai) {
			IERC20Token(_token).approve(chai, uint256(-1));
			IERC20Token(chai).approve(lendFMe, uint256(-1));
		}
		else {
			NonStandardIERC20Token(_token).approve(lendFMe, uint256(-1));
		}

		uint256 _balance = NonStandardIERC20Token(_token).balanceOf(address(this));
		if(_balance > 0) {
			if (_token == dai) {
				IChai(chai).join(address(this), _balance);
				ILendFMe(lendFMe).supply(chai, IERC20Token(chai).balanceOf(address(this)));
			}
			else
				ILendFMe(lendFMe).supply(_token, _balance);
		}
		return true;
	}

	function disableLending(address _token) public auth returns (bool) {
		require(supportLending[_token], "the token doesnt support lending");
		supportLending[_token] = false;

		if (_token == dai) {
			ILendFMe(lendFMe).withdraw(chai, uint256(-1));
			IChai(chai).exit(address(this), IERC20Token(chai).balanceOf(address(this)));
		}
		else
			ILendFMe(lendFMe).withdraw(_token, uint256(-1));

		return true;
	}


	function createPair(address _input, address _output, uint256 _priceInOut, uint256 _priceOutIn, uint256 _fee) external auth returns (bool) {
		setPrices(_input, _output, _priceInOut, _priceOutIn);
		setFee(_input, _output, _fee);
		return true;
	}

	function setPrices(address _input, address _output, uint256 _priceInOut, uint256 _priceOutIn) public auth returns (bool) {
		setPrices(_input, _output, _priceInOut);
		setPrices(_output, _input, _priceOutIn);
		return true;
	}

	function setPrices(address _input, address _output, uint256 _price) public auth returns (bool) {
		prices[_input][_output] = _price;
		return true;
	}

	function setFee(address _input, address _output, uint256 _fee) public auth returns (bool) {
		fee[_input][_output] = _fee;
		fee[_output][_input] = _fee;
		return true;
	}

	function setTokenDecimals(address _token, uint256 _decimals) public auth returns (bool){
		require(_decimals <= 18, "not supported decimal");
		decimals[_token] = _decimals;
		return true;
	}

	function emergencyStop(bool _open) external auth returns (bool) {
		isOpen = _open;
		return true;
	}

	function transferOut(address _token, address _receiver, uint256 _amount) external auth returns (bool) {
		if(supportLending[_token]) {
			if (_token == dai) {
				ILendFMe(lendFMe).withdraw(chai, _amount);
				IChai(chai).draw(address(this), _amount);
			}
			else
				ILendFMe(lendFMe).withdraw(_token, _amount);
		}
		uint256 _balance = NonStandardIERC20Token(_token).balanceOf(address(this));
		if(_balance >= _amount) {
			NonStandardIERC20Token(_token).transfer(_receiver, _amount);
			return true;
		}
		return false;
	}

	function transferOutALL(address _token, address _receiver) external auth returns (bool) {
		if(supportLending[_token]) {
			if (_token == dai) {
				ILendFMe(lendFMe).withdraw(chai, uint256(-1));
				IChai(chai).exit(address(this), IERC20Token(chai).balanceOf(address(this)));
			}
			else
				ILendFMe(lendFMe).withdraw(_token, uint256(-1));
		}
		uint256 _balance = NonStandardIERC20Token(_token).balanceOf(address(this));
		if(_balance > 0) {
			NonStandardIERC20Token(_token).transfer(_receiver, _balance);
		}

		return true;
	}

	function transferIn(address _token, uint256 _amount) external auth returns (bool) {
		NonStandardIERC20Token(_token).transferFrom(msg.sender, address(this), _amount);
		if(supportLending[_token]) {
			if (_token == dai) {
				IChai(chai).join(address(this), NonStandardIERC20Token(dai).balanceOf(address(this)));
				ILendFMe(lendFMe).supply(chai, IERC20Token(chai).balanceOf(address(this)));
			}
			else
				ILendFMe(lendFMe).supply(_token, NonStandardIERC20Token(_token).balanceOf(address(this)));
		}
	    return true;
	}

	function normalizeToken(address _token, uint256 _amount) internal view returns (uint256) {
		uint256 n = 18;
		return _amount.mul((10 ** (n.sub(decimals[_token]))));
	}

	function denormalizedToken(address _token, uint256 _amount) internal view returns (uint256) {
		uint256 n = 18;
		return _amount.div((10 ** (n.sub(decimals[_token]))));
	}
}

pragma solidity ^0.4.24;

import './LighthouseAPI.sol';
import './LighthouseABI.sol';
import './LiabilityFactory.sol';

contract LighthouseLib is LighthouseAPI, LighthouseABI {

    function refill(uint256 _value) external {
        require(xrt.transferFrom(msg.sender, this, _value));
        require(_value >= minimalFreeze);

        if (balances[msg.sender] == 0) {
            indexOf[msg.sender] = members.length;
            members.push(msg.sender);
        }
        balances[msg.sender] += _value;
    }

    function withdraw(uint256 _value) external {
        require(balances[msg.sender] >= _value);

        require(xrt.transfer(msg.sender, _value));
        balances[msg.sender] -= _value;


        if (quotaOf(msg.sender) == 0) {
            require(xrt.transfer(msg.sender, balances[msg.sender])); 
            balances[msg.sender] = 0;

            uint256 senderIndex = indexOf[msg.sender];
            uint256 lastIndex = members.length - 1;
            if (senderIndex < lastIndex)
                members[senderIndex] = members[lastIndex];
            members.length -= 1;
        }
    }

    function nextMember() internal
    { marker = (marker + 1) % members.length; }

    modifier quoted {
        if (quota == 0) {

            nextMember();


            quota = quotaOf(members[marker]);
        }



        quota -= 1;

        _;
    }

    modifier keepalive {
        if (timeoutBlocks < block.number - keepaliveBlock) {

            while (msg.sender != members[marker])
                nextMember();


            quota = quotaOf(members[marker]);
        }

        _;
    }

    modifier member {

        require(members.length > 0);


        require(msg.sender == members[marker]);


        keepaliveBlock = block.number;

        _;
    }

    function to(address _to, bytes _data) external keepalive quoted member
    { require(_to.call(_data)); }

    function () external keepalive quoted member
    { require(factory.call(msg.data)); }
}

pragma solidity ^0.4.23;

import "authos-solidity/contracts/core/Contract.sol";
import "authos-solidity/contracts/interfaces/GetterInterface.sol";
import "authos-solidity/contracts/lib/ArrayUtils.sol";

library DutchCrowdsaleIdx {

  using Contract for *;
  using SafeMath for uint;
  using ArrayUtils for bytes32[];

  bytes32 internal constant EXEC_PERMISSIONS = keccak256('script_exec_permissions');


  function execPermissions(address _exec) internal pure returns (bytes32)
    { return keccak256(_exec, EXEC_PERMISSIONS); }




  function admin() internal pure returns (bytes32)
    { return keccak256('sale_admin'); }


  function isConfigured() internal pure returns (bytes32)
    { return keccak256("sale_is_configured"); }


  function isFinished() internal pure returns (bytes32)
    { return keccak256("sale_is_completed"); }


  function burnExcess() internal pure returns (bytes32)
    { return keccak256("burn_excess_unsold"); }


  function startTime() internal pure returns (bytes32)
    { return keccak256("sale_start_time"); }


  function totalDuration() internal pure returns (bytes32)
    { return keccak256("sale_total_duration"); }


  function tokensRemaining() internal pure returns (bytes32)
    { return keccak256("sale_tokens_remaining"); }


  function maxSellCap() internal pure returns (bytes32)
    { return keccak256("token_sell_cap"); }


  function startRate() internal pure returns (bytes32)
    { return keccak256("sale_start_rate"); }


  function endRate() internal pure returns (bytes32)
    { return keccak256("sale_end_rate"); }


  function tokensSold() internal pure returns (bytes32)
    { return keccak256("sale_tokens_sold"); }


  function globalMinPurchaseAmt() internal pure returns (bytes32)
    { return keccak256("sale_min_purchase_amt"); }


  function contributors() internal pure returns (bytes32)
    { return keccak256("sale_contributors"); }


  function hasContributed(address _purchaser) internal pure returns (bytes32)
    { return keccak256(_purchaser, contributors()); }




  function wallet() internal pure returns (bytes32)
    { return keccak256("sale_destination_wallet"); }


  function totalWeiRaised() internal pure returns (bytes32)
    { return keccak256("sale_tot_wei_raised"); }




  function isWhitelisted() internal pure returns (bytes32)
    { return keccak256('sale_is_whitelisted'); }


  function saleWhitelist() internal pure returns (bytes32)
    { return keccak256("sale_whitelist"); }


  function whitelistMaxTok(address _spender) internal pure returns (bytes32)
    { return keccak256(_spender, "max_tok", saleWhitelist()); }


  function whitelistMinTok(address _spender) internal pure returns (bytes32)
    { return keccak256(_spender, "min_tok", saleWhitelist()); }




  function tokenName() internal pure returns (bytes32)
    { return keccak256("token_name"); }


  function tokenSymbol() internal pure returns (bytes32)
    { return keccak256("token_symbol"); }


  function tokenDecimals() internal pure returns (bytes32)
    { return keccak256("token_decimals"); }


  function tokenTotalSupply() internal pure returns (bytes32)
    { return keccak256("token_total_supply"); }


  bytes32 internal constant TOKEN_BALANCES = keccak256("token_balances");

  function balances(address _owner) internal pure returns (bytes32)
    { return keccak256(_owner, TOKEN_BALANCES); }


  bytes32 internal constant TOKEN_ALLOWANCES = keccak256("token_allowances");

  function allowed(address _owner, address _spender) internal pure returns (bytes32)
    { return keccak256(_spender, keccak256(_owner, TOKEN_ALLOWANCES)); }



  bytes32 internal constant TOKEN_TRANSFER_AGENTS = keccak256("token_transfer_agents");

  function transferAgents(address _agent) internal pure returns (bytes32)
    { return keccak256(_agent, TOKEN_TRANSFER_AGENTS); }




  function init(
    address _wallet, uint _total_supply, uint _max_amount_to_sell, uint _starting_rate,
    uint _ending_rate, uint _duration, uint _start_time, bool _sale_is_whitelisted,
    address _admin, bool _burn_excess
  ) external view {

    if (
      _wallet == 0
      || _max_amount_to_sell == 0
      || _max_amount_to_sell > _total_supply
      || _starting_rate <= _ending_rate
      || _ending_rate == 0
      || _start_time <= now
      || _duration + _start_time <= _start_time
      || _admin == 0
    ) revert("Improper Initialization");


    Contract.initialize();


    Contract.storing();

    Contract.set(execPermissions(msg.sender)).to(true);

    Contract.set(wallet()).to(_wallet);
    Contract.set(admin()).to(_admin);
    Contract.set(totalDuration()).to(_duration);
    Contract.set(startTime()).to(_start_time);

    Contract.set(startRate()).to(_starting_rate);
    Contract.set(endRate()).to(_ending_rate);
    Contract.set(tokenTotalSupply()).to(_total_supply);
    Contract.set(maxSellCap()).to(_max_amount_to_sell);
    Contract.set(tokensRemaining()).to(_max_amount_to_sell);

    Contract.set(isWhitelisted()).to(_sale_is_whitelisted);
    Contract.set(balances(_admin)).to(_total_supply - _max_amount_to_sell);
    Contract.set(burnExcess()).to(_burn_excess);


    Contract.commit();
  }




  function getAdmin(address _storage, bytes32 _exec_id) external view returns (address)
    { return address(GetterInterface(_storage).read(_exec_id, admin())); }


  function getCrowdsaleInfo(address _storage, bytes32 _exec_id) external view
  returns (uint wei_raised, address team_wallet, uint minimum_contribution, bool is_initialized, bool is_finalized, bool burn_excess) {

    bytes32[] memory seed_arr = new bytes32[](6);


    seed_arr[0] = totalWeiRaised();
    seed_arr[1] = wallet();
    seed_arr[2] = globalMinPurchaseAmt();
    seed_arr[3] = isConfigured();
    seed_arr[4] = isFinished();
    seed_arr[5] = burnExcess();


    bytes32[] memory values_arr = GetterInterface(_storage).readMulti(_exec_id, seed_arr);


    wei_raised = uint(values_arr[0]);
    team_wallet = address(values_arr[1]);
    minimum_contribution = uint(values_arr[2]);
    is_initialized = (values_arr[3] != 0 ? true : false);
    is_finalized = (values_arr[4] != 0 ? true : false);
    burn_excess = values_arr[5] != 0 ? true : false;
  }


  function isCrowdsaleFull(address _storage, bytes32 _exec_id) external view returns (bool is_crowdsale_full, uint max_sellable) {

    bytes32[] memory seed_arr = new bytes32[](2);
    seed_arr[0] = tokensRemaining();
    seed_arr[1] = maxSellCap();


    uint[] memory values_arr = GetterInterface(_storage).readMulti(_exec_id, seed_arr).toUintArr();


    is_crowdsale_full = (values_arr[0] == 0 ? true : false);
    max_sellable = values_arr[1];


    seed_arr = new bytes32[](5);
    seed_arr[0] = startTime();
    seed_arr[1] = startRate();
    seed_arr[2] = totalDuration();
    seed_arr[3] = endRate();
    seed_arr[4] = tokenDecimals();

    uint num_remaining = values_arr[0];

    values_arr = GetterInterface(_storage).readMulti(_exec_id, seed_arr).toUintArr();

    uint current_rate;
    (current_rate, ) = getRateAndTimeRemaining(values_arr[0], values_arr[2], values_arr[1], values_arr[3]);


    if (current_rate.mul(num_remaining).div(10 ** values_arr[4]) == 0)
      return (true, max_sellable);
  }


  function getCrowdsaleUniqueBuyers(address _storage, bytes32 _exec_id) external view returns (uint)
    { return uint(GetterInterface(_storage).read(_exec_id, contributors())); }


  function getCrowdsaleStartAndEndTimes(address _storage, bytes32 _exec_id) external view returns (uint start_time, uint end_time) {

    bytes32[] memory seed_arr = new bytes32[](2);
    seed_arr[0] = startTime();
    seed_arr[1] = totalDuration();


    uint[] memory values_arr = GetterInterface(_storage).readMulti(_exec_id, seed_arr).toUintArr();


    start_time = values_arr[0];
    end_time = values_arr[1] + start_time;
  }


  function getCrowdsaleStatus(address _storage, bytes32 _exec_id) external view
  returns (uint start_rate, uint end_rate, uint current_rate, uint sale_duration, uint time_remaining, uint tokens_remaining, bool is_whitelisted) {

    bytes32[] memory seed_arr = new bytes32[](6);


    seed_arr[0] = startRate();
    seed_arr[1] = endRate();
    seed_arr[2] = startTime();
    seed_arr[3] = totalDuration();
    seed_arr[4] = tokensRemaining();
    seed_arr[5] = isWhitelisted();


    uint[] memory values_arr = GetterInterface(_storage).readMulti(_exec_id, seed_arr).toUintArr();


    start_rate = values_arr[0];
    end_rate = values_arr[1];
    uint start_time = values_arr[2];
    sale_duration = values_arr[3];
    tokens_remaining = values_arr[4];
    is_whitelisted = values_arr[5] == 0 ? false : true;

    (current_rate, time_remaining) =
      getRateAndTimeRemaining(start_time, sale_duration, start_rate, end_rate);
  }



  function getRateAndTimeRemaining(uint _start_time, uint _duration, uint _start_rate, uint _end_rate) internal view
  returns (uint current_rate, uint time_remaining)  {

    if (now <= _start_time)
      return (_start_rate, (_duration + _start_time - now));

    uint time_elapsed = now - _start_time;

    if (time_elapsed >= _duration)
      return (0, 0);


    time_remaining = _duration - time_elapsed;

    time_elapsed *= (10 ** 18);
    current_rate = ((_start_rate - _end_rate) * time_elapsed) / _duration;
    current_rate /= (10 ** 18); 
    current_rate = _start_rate - current_rate;
  }


  function getTokensSold(address _storage, bytes32 _exec_id) external view returns (uint)
    { return uint(GetterInterface(_storage).read(_exec_id, tokensSold())); }


  function getWhitelistStatus(address _storage, bytes32 _exec_id, address _buyer) external view
  returns (uint minimum_purchase_amt, uint max_tokens_remaining) {
    bytes32[] memory seed_arr = new bytes32[](2);
    seed_arr[0] = whitelistMinTok(_buyer);
    seed_arr[1] = whitelistMaxTok(_buyer);


    uint[] memory values_arr = GetterInterface(_storage).readMulti(_exec_id, seed_arr).toUintArr();


    minimum_purchase_amt = values_arr[0];
    max_tokens_remaining = values_arr[1];
  }


  function getCrowdsaleWhitelist(address _storage, bytes32 _exec_id) external view returns (uint num_whitelisted, address[] whitelist) {

    num_whitelisted = uint(GetterInterface(_storage).read(_exec_id, saleWhitelist()));

    if (num_whitelisted == 0)
      return (num_whitelisted, whitelist);


    bytes32[] memory seed_arr = new bytes32[](num_whitelisted);


    for (uint i = 0; i < num_whitelisted; i++)
    	seed_arr[i] = bytes32(32 * (i + 1) + uint(saleWhitelist()));


    whitelist = GetterInterface(_storage).readMulti(_exec_id, seed_arr).toAddressArr();
  }




  function balanceOf(address _storage, bytes32 _exec_id, address _owner) external view returns (uint)
    { return uint(GetterInterface(_storage).read(_exec_id, balances(_owner))); }


  function allowance(address _storage, bytes32 _exec_id, address _owner, address _spender) external view returns (uint)
    { return uint(GetterInterface(_storage).read(_exec_id, allowed(_owner, _spender))); }


  function decimals(address _storage, bytes32 _exec_id) external view returns (uint)
    { return uint(GetterInterface(_storage).read(_exec_id, tokenDecimals())); }


  function totalSupply(address _storage, bytes32 _exec_id) external view returns (uint)
    { return uint(GetterInterface(_storage).read(_exec_id, tokenTotalSupply())); }


  function name(address _storage, bytes32 _exec_id) external view returns (bytes32)
    { return GetterInterface(_storage).read(_exec_id, tokenName()); }


  function symbol(address _storage, bytes32 _exec_id) external view returns (bytes32)
    { return GetterInterface(_storage).read(_exec_id, tokenSymbol()); }


  function getTokenInfo(address _storage, bytes32 _exec_id) external view
  returns (bytes32 token_name, bytes32 token_symbol, uint token_decimals, uint total_supply) {

    bytes32[] memory seed_arr = new bytes32[](4);


    seed_arr[0] = tokenName();
    seed_arr[1] = tokenSymbol();
    seed_arr[2] = tokenDecimals();
    seed_arr[3] = tokenTotalSupply();


    bytes32[] memory values_arr = GetterInterface(_storage).readMulti(_exec_id, seed_arr);


    token_name = values_arr[0];
    token_symbol = values_arr[1];
    token_decimals = uint(values_arr[2]);
    total_supply = uint(values_arr[3]);
  }


  function getTransferAgentStatus(address _storage, bytes32 _exec_id, address _agent) external view returns (bool)
    { return GetterInterface(_storage).read(_exec_id, transferAgents(_agent)) != 0 ? true : false; }
}

pragma solidity ^0.8.0;

library UserAccounting {
    struct Info {
        uint40 checkpoint;
        uint216 farmedPerTokenStored;
        mapping(address => int256) corrections;
    }

    function farmedPerToken(
        Info storage info,
        address context,
        function(address) internal view returns(uint256) lazyGetSupply,
        function(address, uint256) internal view returns(uint256) lazyGetFarmed
    ) internal view returns(uint256) {
        (uint256 checkpoint, uint256 fpt) = (info.checkpoint, info.farmedPerTokenStored);
        if (block.timestamp != checkpoint) {
            uint256 supply = lazyGetSupply(context);
            if (supply > 0) {
                fpt += lazyGetFarmed(context, checkpoint) / supply;
            }
        }
        return fpt;
    }

    function farmed(Info storage info, address account, uint256 balance, uint256 fpt) internal view returns(uint256) {

        return uint256(int256(balance * fpt) - info.corrections[account]) / 1e18;
    }

    function eraseFarmed(Info storage info, address account, uint256 balance, uint256 fpt) internal {
        info.corrections[account] = int256(balance * fpt);
    }

    function updateCheckpoint(Info storage info, uint256 fpt) internal {
        (info.checkpoint, info.farmedPerTokenStored) = (uint40(block.timestamp), uint216(fpt));
    }

    function updateBalances(Info storage info, uint256 fpt, address from, address to, uint256 amount, bool inFrom, bool inTo) internal {
        if (amount > 0 && (inFrom || inTo)) {
            if (inFrom != inTo) {
                updateCheckpoint(info, fpt);
            }
            if (inFrom) {
                info.corrections[from] -= int256(amount * fpt);
            }
            if (inTo) {
                info.corrections[to] += int256(amount * fpt);
            }
        }
    }
}

pragma solidity 0.6.12;
pragma experimental ABIEncoderV2;

import {BaseParaSwapAdapter} from './BaseParaSwapAdapter.sol';
import {PercentageMath} from '../protocol/libraries/math/PercentageMath.sol';
import {IParaSwapAugustus} from '../interfaces/IParaSwapAugustus.sol';
import {ILendingPoolAddressesProvider} from '../interfaces/ILendingPoolAddressesProvider.sol';
import {IERC20} from '../dependencies/openzeppelin/contracts/IERC20.sol';


abstract contract BaseParaSwapSellAdapter is BaseParaSwapAdapter {
  using PercentageMath for uint256;

  constructor(
    ILendingPoolAddressesProvider addressesProvider
  ) public BaseParaSwapAdapter(addressesProvider) {
  }



  function _sellOnParaSwap(
    uint256 fromAmountOffset,
    bytes memory swapCalldata,
    address augustus,
    address assetToSwapFrom,
    address assetToSwapTo,
    uint256 amountToSwap,
    uint256 minAmountToReceive
  ) internal returns (uint256 amountReceived) {
    {
      uint256 fromAssetDecimals = _getDecimals(assetToSwapFrom);
      uint256 toAssetDecimals = _getDecimals(assetToSwapTo);

      uint256 fromAssetPrice = _getPrice(assetToSwapFrom);
      uint256 toAssetPrice = _getPrice(assetToSwapTo);


      uint256 expectedMinAmountOut =
        amountToSwap
          .mul(fromAssetPrice.mul(10**toAssetDecimals))
          .div(toAssetPrice.mul(10**fromAssetDecimals))
          .percentMul(PercentageMath.PERCENTAGE_FACTOR - MAX_SLIPPAGE_PERCENT);

      require(expectedMinAmountOut <= minAmountToReceive, 'MIN_AMOUNT_EXCEEDS_MAX_SLIPPAGE');
    }

    uint256 balanceBeforeAssetFrom = IERC20(assetToSwapFrom).balanceOf(address(this));
    require(balanceBeforeAssetFrom >= amountToSwap, 'INSUFFICIENT_BALANCE_BEFORE_SWAP');
    uint256 balanceBeforeAssetTo = IERC20(assetToSwapTo).balanceOf(address(this));

    address tokenTransferProxy = IParaSwapAugustus(augustus).getTokenTransferProxy();
    IERC20(assetToSwapFrom).safeApprove(tokenTransferProxy, 0);
    IERC20(assetToSwapFrom).safeApprove(tokenTransferProxy, amountToSwap);

    if (fromAmountOffset != 0) {
      require(fromAmountOffset >= 4 &&
        fromAmountOffset <= swapCalldata.length.sub(32),
        'FROM_AMOUNT_OFFSET_OUT_OF_RANGE');
      assembly {
        mstore(add(swapCalldata, add(fromAmountOffset, 32)), amountToSwap)
      }
    }
    (bool success,) = augustus.call(swapCalldata);
    if (!success) {

      assembly {
        returndatacopy(0, 0, returndatasize())
        revert(0, returndatasize())
      }
    }
    require(IERC20(assetToSwapFrom).balanceOf(address(this)) == balanceBeforeAssetFrom - amountToSwap, 'WRONG_BALANCE_AFTER_SWAP');
    amountReceived = IERC20(assetToSwapTo).balanceOf(address(this)).sub(balanceBeforeAssetTo);
    require(amountReceived >= minAmountToReceive, 'INSUFFICIENT_AMOUNT_RECEIVED');

    emit Swapped(assetToSwapFrom, assetToSwapTo, amountToSwap, amountReceived);
  }
}

pragma solidity 0.5.17;

import "@openzeppelin/contracts/math/SafeMath.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/SafeERC20.sol";
import "./BCubePrivateSale.sol";



contract Treasury is BCubePrivateSale {
    using SafeMath for uint256;
    using SafeERC20 for IERC20;





    struct Advisor {
        uint256 increaseInAllowance;
        uint256 currentAllowance;
        uint256 shareWithdrawn;
    }

    mapping(address => Advisor) public advisors;



    uint256 public teamShareWithdrawn;
    uint256 public teamAllowance;
    uint256 public devFundShareWithdrawn;
    uint256 public devFundAllowance;



    uint256 public reservesWithdrawn;
    uint256 public communityShareWithdrawn;
    uint256 public bountyWithdrawn;
    uint256 public publicSaleShareWithdrawn;


    uint256 public listingTime;

    event LogEtherReceived(address indexed sender, uint256 value);
    event LogListingTimeChange(uint256 prevListingTime, uint256 newListingTime);
    event LogAdvisorAddition(
        address indexed newAdvisor,
        uint256 newNetAllowance
    );
    event LogAdvisorAllowanceChange(
        address indexed advisor,
        uint256 prevNetAllowance,
        uint256 newNetAllowance
    );
    event LogAdvisorRemoval(address indexed removedAdvisor);
    event LogAdvisorShareWithdrawn(
        address indexed advisor,
        uint256 bcubeAmountWithdrawn
    );
    event LogTeamShareWithdrawn(uint256 bcubeAmountWithdrawn);
    event LogDevFundShareWithdrawn(uint256 bcubeAmountWithdrawn);
    event LogReservesShareWithdrawn(uint256 bcubeAmountWithdrawn);
    event LogCommunityShareWithdrawn(uint256 bcubeAmountWithdrawn);
    event LogBountyShareWithdrawn(uint256 bcubeAmountWithdrawn);
    event LogPublicSaleShareWithdrawn(uint256 bcubeAmountWithdrawn);
    event LogPrivateSaleShareWithdrawn(
        address indexed participant,
        uint256 bcubeAmountWithdrawn
    );


    modifier onlyTeam() {
        require(_msgSender() == wallet(), "Only team can call");
        _;
    }

    modifier onlyAfterListing() {
        require(now >= listingTime, "Only callable after listing");
        _;
    }

    function() external payable {
        emit LogEtherReceived(_msgSender(), msg.value);
    }


    constructor(
        address payable wallet_,
        IERC20 token_,
        uint256 openingTime_,
        uint256 closingTime_,
        address _chainlinkETHPriceFeed,
        address _chainlinkUSDTPriceFeed,
        address _usdtContract,
        uint256 _listingTime
    )
        public
        BCubePrivateSale(
            wallet_,
            token_,
            openingTime_,
            closingTime_,
            _chainlinkETHPriceFeed,
            _chainlinkUSDTPriceFeed,
            _usdtContract
        )
    {
        listingTime = _listingTime;
    }



    function setListingTime(uint256 _startTime) external onlyWhitelistAdmin {
        require(now < listingTime, "listingTime unchangable after listing");
        uint256 prevListingTime = listingTime;
        listingTime = _startTime;
        emit LogListingTimeChange(prevListingTime, listingTime);
    }

    function addAdvisor(address _newAdvisor, uint256 _netAllowance)
        external
        onlyWhitelistAdmin
    {
        require(_newAdvisor != address(0), "Invalid advisor address");
        advisors[_newAdvisor].increaseInAllowance = _netAllowance.div(4);
        emit LogAdvisorAddition(_newAdvisor, _netAllowance);
    }


    function setAdvisorAllowance(address _advisor, uint256 _newNetAllowance)
        external
        onlyWhitelistAdmin
    {
        uint256 prevNetAllowance;
        require(advisors[_advisor].increaseInAllowance > 0, "Invalid advisor");
        prevNetAllowance = advisors[_advisor].increaseInAllowance.mul(4);
        advisors[_advisor].increaseInAllowance = _newNetAllowance.div(4);
        emit LogAdvisorAllowanceChange(
            _advisor,
            prevNetAllowance,
            _newNetAllowance
        );
    }

    function removeAdvisor(address _advisor) external onlyWhitelistAdmin {
        require(advisors[_advisor].increaseInAllowance > 0, "Invalid advisor");
        delete advisors[_advisor];
        emit LogAdvisorRemoval(_advisor);
    }




    function advisorShareWithdraw(uint256 bcubeAmount)
        external
        onlyAfterListing
    {
        uint256 allowance;
        require(advisors[_msgSender()].increaseInAllowance > 0, "!advisor");
        uint256 increase = advisors[_msgSender()].increaseInAllowance;
        if (now >= listingTime + 104 weeks) allowance = increase * 4;
        else if (now >= listingTime + 78 weeks) allowance = increase * 3;
        else if (now >= listingTime + 52 weeks) allowance = increase * 2;
        else if (now >= listingTime + 26 weeks) allowance = increase;
        if (allowance != advisors[_msgSender()].currentAllowance)
            advisors[_msgSender()].currentAllowance = allowance;
        uint256 finalAdvisorShareWithdrawn;
        finalAdvisorShareWithdrawn = advisors[_msgSender()].shareWithdrawn.add(
            bcubeAmount
        );
        require(
            finalAdvisorShareWithdrawn <=
                advisors[_msgSender()].currentAllowance,
            "Out of advisor share"
        );
        advisors[_msgSender()].shareWithdrawn = finalAdvisorShareWithdrawn;
        token().safeTransfer(_msgSender(), bcubeAmount);
        emit LogAdvisorShareWithdrawn(_msgSender(), bcubeAmount);
    }



    function devFundShareWithdraw(uint256 bcubeAmount)
        external
        onlyTeam
        onlyAfterListing
    {
        uint256 allowance;
        if (now >= listingTime + 104 weeks) allowance = 1_875_000e18 * 4;
        else if (now >= listingTime + 78 weeks) allowance = 1_875_000e18 * 3;
        else if (now >= listingTime + 52 weeks) allowance = 1_875_000e18 * 2;
        else if (now >= listingTime + 26 weeks) allowance = 1_875_000e18;
        if (allowance != devFundAllowance) devFundAllowance = allowance;
        uint256 finalDevFundShareWithdrawn;
        finalDevFundShareWithdrawn = devFundShareWithdrawn.add(bcubeAmount);
        require(
            finalDevFundShareWithdrawn <= devFundAllowance,
            "Out of dev fund share"
        );
        devFundShareWithdrawn = finalDevFundShareWithdrawn;
        token().safeTransfer(wallet(), bcubeAmount);
        emit LogDevFundShareWithdrawn(bcubeAmount);
    }



    function teamShareWithdraw(uint256 bcubeAmount)
        external
        onlyTeam
        onlyAfterListing
    {
        uint256 allowance;
        if (now >= listingTime + 208 weeks) allowance = 625_000e18 * 8;
        else if (now >= listingTime + 182 weeks) allowance = 625_000e18 * 7;
        else if (now >= listingTime + 156 weeks) allowance = 625_000e18 * 6;
        else if (now >= listingTime + 130 weeks) allowance = 625_000e18 * 5;
        else if (now >= listingTime + 104 weeks) allowance = 625_000e18 * 4;
        else if (now >= listingTime + 78 weeks) allowance = 625_000e18 * 3;
        else if (now >= listingTime + 52 weeks) allowance = 625_000e18 * 2;
        else if (now >= listingTime + 26 weeks) allowance = 625_000e18;
        if (allowance != teamAllowance) teamAllowance = allowance;
        uint256 finalTeamShareWithdrawn;
        finalTeamShareWithdrawn = teamShareWithdrawn.add(bcubeAmount);
        require(finalTeamShareWithdrawn <= teamAllowance, "Out of team share");
        teamShareWithdrawn = finalTeamShareWithdrawn;
        token().safeTransfer(wallet(), bcubeAmount);
        emit LogTeamShareWithdrawn(bcubeAmount);
    }


    function reservesShareWithdraw(uint256 bcubeAmount)
        external
        onlyTeam
        onlyAfterListing
    {
        shareWithdraw(
            bcubeAmount,
            reservesWithdrawn,
            7_000_000e18,
            "Out of reserves share",
            0
        );
        emit LogReservesShareWithdrawn(bcubeAmount);
    }


    function communityShareWithdraw(uint256 bcubeAmount) external onlyTeam {
        shareWithdraw(
            bcubeAmount,
            communityShareWithdrawn,
            2_500_000e18,
            "Out of community share",
            1
        );
        emit LogCommunityShareWithdrawn(bcubeAmount);
    }


    function bountyShareWithdraw(uint256 bcubeAmount) external onlyTeam {
        shareWithdraw(
            bcubeAmount,
            bountyWithdrawn,
            500_000e18,
            "Out of bounty share",
            2
        );
        emit LogBountyShareWithdrawn(bcubeAmount);
    }


    function publicSaleShareWithdraw(uint256 bcubeAmount) external onlyTeam {
        shareWithdraw(
            bcubeAmount,
            publicSaleShareWithdrawn,
            25_000_000e18 - netAllocatedBcube,
            "Out of publicSale share",
            3
        );
        emit LogPublicSaleShareWithdrawn(bcubeAmount);
    }




    function shareWithdraw(
        uint256 bcubeAmount,
        uint256 specificShareWithdrawn,
        uint256 cap,
        string memory errMsg,
        uint256 flag
    ) private {
        uint256 finalShareWithdrawn;
        finalShareWithdrawn = specificShareWithdrawn.add(bcubeAmount);
        require(finalShareWithdrawn <= cap, errMsg);
        if (flag == 0) reservesWithdrawn = finalShareWithdrawn;
        else if (flag == 1) communityShareWithdrawn = finalShareWithdrawn;
        else if (flag == 2) bountyWithdrawn = finalShareWithdrawn;
        else if (flag == 3) publicSaleShareWithdrawn = finalShareWithdrawn;
        token().safeTransfer(wallet(), bcubeAmount);
    }



    function privateSaleShareWithdraw(uint256 bcubeAmount)
        external
        onlyAfterListing
    {
        require(
            bcubeAllocationRegistry[_msgSender()].allocatedBcube > 0,
            "!privateSaleParticipant || 0 BCUBE allocated"
        );
        uint256 allowance;
        uint256 increase =
            bcubeAllocationRegistry[_msgSender()].allocatedBcube.div(4);
        if (now >= listingTime + 120 days) allowance = increase * 4;
        else if (now >= listingTime + 90 days) allowance = increase * 3;
        else if (now >= listingTime + 60 days) allowance = increase * 2;
        else if (now >= listingTime + 30 days) allowance = increase;
        if (allowance != bcubeAllocationRegistry[_msgSender()].currentAllowance)
            bcubeAllocationRegistry[_msgSender()].currentAllowance = allowance;
        uint256 finalPSSWithdrawn;
        finalPSSWithdrawn = bcubeAllocationRegistry[_msgSender()]
            .shareWithdrawn
            .add(bcubeAmount);
        require(
            finalPSSWithdrawn <=
                bcubeAllocationRegistry[_msgSender()].currentAllowance,
            "Insufficient allowance"
        );
        bcubeAllocationRegistry[_msgSender()]
            .shareWithdrawn = finalPSSWithdrawn;
        token().safeTransfer(_msgSender(), bcubeAmount);
        emit LogPrivateSaleShareWithdrawn(_msgSender(), bcubeAmount);
    }
}

pragma solidity ^0.6.0;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/token/ERC20/SafeERC20.sol";
import "@openzeppelin/contracts/math/SafeMath.sol";
import "./utils/OwnablePausable.sol";
import "./uniswap/IUniswapV2Router02.sol";
import "./GovernanceToken.sol";

contract Investment is OwnablePausable {
    using SafeMath for uint256;
    using SafeERC20 for ERC20;


    ERC20 public cumulative;


    GovernanceToken public governanceToken;


    uint256 public governanceTokenLockDate;

    uint8 internal constant GOVERNANCE_TOKEN_PRICE_DECIMALS = 6;


    uint256 public governanceTokenPrice = 1000000;


    IUniswapV2Router02 internal uniswapRouter;


    mapping(address => bool) public investmentTokens;


    event UniswapRouterChanged(address newUniswapRouter);


    event InvestTokenAllowed(address token);


    event InvestTokenDenied(address token);


    event GovernanceTokenPriceChanged(uint256 newPrice);


    event Invested(address investor, address token, uint256 amount, uint256 reward);


    event Withdrawal(address recipient, address token, uint256 amount);


    constructor(
        address _cumulative,
        address _governanceToken,
        uint256 _governanceTokenLockDate,
        address _uniswapRouter
    ) public {
        cumulative = ERC20(_cumulative);
        governanceToken = GovernanceToken(_governanceToken);
        governanceTokenLockDate = _governanceTokenLockDate;
        uniswapRouter = IUniswapV2Router02(_uniswapRouter);
    }


    function changeUniswapRouter(address _uniswapRouter) external onlyOwner {
        uniswapRouter = IUniswapV2Router02(_uniswapRouter);
        emit UniswapRouterChanged(_uniswapRouter);
    }


    function allowToken(address token) external onlyOwner {
        investmentTokens[token] = true;
        emit InvestTokenAllowed(token);
    }


    function denyToken(address token) external onlyOwner {
        investmentTokens[token] = false;
        emit InvestTokenDenied(token);
    }


    function changeGovernanceTokenPrice(uint256 newPrice) external onlyOwner {
        require(newPrice > 0, "Investment::changeGovernanceTokenPrice: invalid new governance token price");

        governanceTokenPrice = newPrice;
        emit GovernanceTokenPriceChanged(newPrice);
    }


    function _path(address token) internal view returns (address[] memory) {
        address weth = uniswapRouter.WETH();
        if (weth == token) {
            address[] memory path = new address[](2);
            path[0] = token;
            path[1] = address(cumulative);
            return path;
        }

        address[] memory path = new address[](3);
        path[0] = token;
        path[1] = weth;
        path[2] = address(cumulative);
        return path;
    }


    function _amountOut(address token, uint256 amount) internal view returns (uint256) {
        uint256[] memory amountsOut = uniswapRouter.getAmountsOut(amount, _path(token));
        require(amountsOut.length != 0, "Investment::_amountOut: invalid amounts out length");

        return amountsOut[amountsOut.length - 1];
    }



    function _governanceTokenPrice(uint256 amount) internal view returns (uint256) {
        uint256 decimals = cumulative.decimals();

        return amount.mul(10**(18 - decimals + GOVERNANCE_TOKEN_PRICE_DECIMALS)).div(governanceTokenPrice);
    }


    function price(address token, uint256 amount) external view returns (uint256) {
        require(investmentTokens[token], "Investment::price: invalid investable token");

        uint256 amountOut = amount;
        if (token != address(cumulative)) {
            amountOut = _amountOut(token, amount);
        }

        return _governanceTokenPrice(amountOut);
    }


    function invest(address token, uint256 amount) external whenNotPaused returns (bool) {
        require(investmentTokens[token], "Investment::invest: invalid investable token");
        uint256 reward = _governanceTokenPrice(amount);

        ERC20(token).safeTransferFrom(_msgSender(), address(this), amount);

        if (token != address(cumulative)) {
            uint256 amountOut = _amountOut(token, amount);
            require(amountOut != 0, "Investment::invest: liquidity pool is empty");
            reward = _governanceTokenPrice(amountOut);

            ERC20(token).safeApprove(address(uniswapRouter), amount);
            uniswapRouter.swapExactTokensForTokens(amount, amountOut, _path(token), address(this), block.timestamp);
        }

        governanceToken.transferLock(_msgSender(), reward, governanceTokenLockDate);

        emit Invested(_msgSender(), token, amount, reward);
        return true;
    }


    function investETH() external payable whenNotPaused returns (bool) {
        address token = uniswapRouter.WETH();
        require(investmentTokens[token], "Investment::investETH: invalid investable token");
        uint256 reward = _governanceTokenPrice(msg.value);

        if (token != address(cumulative)) {
            uint256 amountOut = _amountOut(token, msg.value);
            require(amountOut != 0, "Investment::invest: liquidity pool is empty");
            reward = _governanceTokenPrice(amountOut);

            uniswapRouter.swapExactETHForTokens{value: msg.value}(amountOut, _path(token), address(this), block.timestamp);
        }

        governanceToken.transferLock(_msgSender(), reward, governanceTokenLockDate);

        emit Invested(_msgSender(), token, msg.value, reward);
        return true;
    }


    function withdraw(address recipient) external onlyOwner {
        require(recipient != address(0), "Investment::withdraw: cannot transfer to the zero address");

        uint256 balance = cumulative.balanceOf(address(this));
        cumulative.safeTransfer(recipient, balance);

        emit Withdrawal(recipient, address(cumulative), balance);
    }
}

