pragma solidity ^0.7.4;
pragma abicoder v2;

import {Address} from "@openzeppelin/contracts/utils/Address.sol";
import {IERC20} from "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import {SafeERC20} from "@openzeppelin/contracts/token/ERC20/SafeERC20.sol";

import {SafeMath} from "@openzeppelin/contracts/math/SafeMath.sol";
import {PercentageMath} from "../libraries/math/PercentageMath.sol";
import {ReentrancyGuard} from "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

import {IAccountFactory} from "../interfaces/IAccountFactory.sol";
import {ICreditAccount} from "../interfaces/ICreditAccount.sol";
import {IPoolService} from "../interfaces/IPoolService.sol";
import {IWETHGateway} from "../interfaces/IWETHGateway.sol";
import {ICreditManager} from "../interfaces/ICreditManager.sol";
import {ICreditFilter} from "../interfaces/ICreditFilter.sol";
import {CreditAccount} from "./CreditAccount.sol";
import {AddressProvider} from "../core/AddressProvider.sol";
import {ACLTrait} from "../core/ACLTrait.sol";

import {Constants} from "../libraries/helpers/Constants.sol";
import {Errors} from "../libraries/helpers/Errors.sol";
import {DataTypes} from "../libraries/data/Types.sol";

import "hardhat/console.sol";





contract CreditManager is ICreditManager, ACLTrait, ReentrancyGuard {
    using SafeMath for uint256;
    using PercentageMath for uint256;
    using SafeERC20 for IERC20;
    using Address for address payable;


    uint256 public override minAmount;


    uint256 public override maxAmount;


    uint256 public override maxLeverageFactor;


    uint256 public override minHealthFactor;


    mapping(address => address) public override creditAccounts;


    AddressProvider public addressProvider;


    IAccountFactory internal _accountFactory;


    ICreditFilter public override creditFilter;


    address public override underlyingToken;


    address public override poolService;


    address public wethAddress;


    address public wethGateway;


    address public defaultSwapContract;

    uint256 public override feeSuccess;

    uint256 public override feeInterest;

    uint256 public override feeLiquidation;

    uint256 public override liquidationDiscount;






    modifier allowedAdaptersOnly(address targetContract) {
        require(
            creditFilter.contractToAdapter(targetContract) == msg.sender,
            Errors.CM_TARGET_CONTRACT_iS_NOT_ALLOWED
        );
        _;
    }









    constructor(
        address _addressProvider,
        uint256 _minAmount,
        uint256 _maxAmount,
        uint256 _maxLeverage,
        address _poolService,
        address _creditFilterAddress,
        address _defaultSwapContract
    ) ACLTrait(_addressProvider) {
        addressProvider = AddressProvider(_addressProvider); 
        poolService = _poolService; 
        underlyingToken = IPoolService(_poolService).underlyingToken(); 

        wethAddress = addressProvider.getWethToken(); 
        wethGateway = addressProvider.getWETHGateway(); 
        defaultSwapContract = _defaultSwapContract; 
        _accountFactory = IAccountFactory(addressProvider.getAccountFactory()); 

        setParams(
            _minAmount,
            _maxAmount,
            _maxLeverage,
            Constants.FEE_SUCCESS,
            Constants.FEE_INTEREST,
            Constants.FEE_LIQUIDATION,
            Constants.LIQUIDATION_DISCOUNTED_SUM
        ); 

        creditFilter = ICreditFilter(_creditFilterAddress); 
    }






    function openCreditAccount(
        uint256 amount,
        address onBehalfOf,
        uint256 leverageFactor,
        uint256 referralCode
    )
        external
        override
        whenNotPaused 
        nonReentrant
    {

        require(
            amount >= minAmount && amount <= maxAmount,
            Errors.CM_INCORRECT_AMOUNT
        ); 


        require(
            !hasOpenedCreditAccount(onBehalfOf),
            Errors.CM_YOU_HAVE_ALREADY_OPEN_CREDIT_ACCOUNT
        ); 


        require(
            leverageFactor > 0 && leverageFactor <= maxLeverageFactor,
            Errors.CM_INCORRECT_LEVERAGE_FACTOR
        ); 


        uint256 borrowedAmount = amount.mul(leverageFactor).div(
            Constants.LEVERAGE_DECIMALS
        ); 


        address creditAccount = _accountFactory.takeCreditAccount(); 



        creditFilter.initEnabledTokens(creditAccount); 


        IPoolService(poolService).lendCreditAccount(
            borrowedAmount,
            creditAccount
        ); 


        IERC20(underlyingToken).safeTransferFrom(
            msg.sender,
            creditAccount,
            amount
        ); 


        ICreditAccount(creditAccount).setGenericParameters(
            borrowedAmount,
            IPoolService(poolService).calcLinearCumulative_RAY()
        ); 


        creditAccounts[onBehalfOf] = creditAccount; 


        emit OpenCreditAccount(
            msg.sender,
            onBehalfOf,
            creditAccount,
            amount,
            borrowedAmount,
            referralCode
        ); 
    }


    function closeCreditAccount(address to, DataTypes.Exchange[] calldata paths)
        external
        override
        whenNotPaused 
        nonReentrant
    {
        address creditAccount = getCreditAccountOrRevert(msg.sender); 


        _convertAllAssetsToUnderlying(creditAccount, paths); 


        uint256 totalValue = IERC20(underlyingToken).balanceOf(creditAccount); 

        (, uint256 remainingFunds) = _closeCreditAccountImpl(
            creditAccount,
            Constants.OPERATION_CLOSURE,
            totalValue,
            msg.sender,
            address(0),
            to
        ); 

        emit CloseCreditAccount(msg.sender, to, remainingFunds); 
    }


    function liquidateCreditAccount(
        address borrower,
        address to,
        bool force
    )
        external
        override
        whenNotPaused 
        nonReentrant
    {
        address creditAccount = getCreditAccountOrRevert(borrower); 


        (uint256 totalValue, uint256 tvw) = _transferAssetsTo(
            creditAccount,
            to,
            force
        ); 


        require(
            tvw <
                creditFilter
                .calcCreditAccountAccruedInterest(creditAccount)
                .mul(PercentageMath.PERCENTAGE_FACTOR),
            Errors.CM_CAN_LIQUIDATE_WITH_SUCH_HEALTH_FACTOR
        ); 


        (, uint256 remainingFunds) = _closeCreditAccountImpl(
            creditAccount,
            Constants.OPERATION_LIQUIDATION,
            totalValue,
            borrower,
            msg.sender,
            to
        ); 

        emit LiquidateCreditAccount(borrower, msg.sender, remainingFunds); 
    }





    function repayCreditAccount(address to)
        external
        override
        whenNotPaused 
        nonReentrant
    {
        _repayCreditAccountImpl(msg.sender, to); 
    }





    function repayCreditAccountETH(address borrower, address to)
        external
        override
        whenNotPaused 
        nonReentrant
        returns (uint256)
    {

        require(msg.sender == wethGateway, Errors.CM_WETH_GATEWAY_ONLY); 


        return _repayCreditAccountImpl(borrower, to); 
    }





    function _repayCreditAccountImpl(address borrower, address to)
        internal
        returns (uint256)
    {
        address creditAccount = getCreditAccountOrRevert(borrower);
        (uint256 totalValue, ) = _transferAssetsTo(creditAccount, to, false); 

        (uint256 amountToPool, ) = _closeCreditAccountImpl(
            creditAccount,
            Constants.OPERATION_REPAY,
            totalValue,
            borrower,
            borrower,
            to
        ); 

        emit RepayCreditAccount(borrower, to); 
        return amountToPool;
    }


    function _closeCreditAccountImpl(
        address creditAccount,
        uint8 operation,
        uint256 totalValue,
        address borrower,
        address liquidator,
        address to
    ) internal returns (uint256, uint256) {
        bool isLiquidated = operation == Constants.OPERATION_LIQUIDATION;

        (
            uint256 borrowedAmount,
            uint256 amountToPool,
            uint256 remainingFunds,
            uint256 profit,
            uint256 loss
        ) = _calcClosePayments(creditAccount, totalValue, isLiquidated); 

        if (operation == Constants.OPERATION_CLOSURE) {
            ICreditAccount(creditAccount).safeTransfer(
                underlyingToken,
                poolService,
                amountToPool
            ); 


            require(loss <= 1, Errors.CM_CANT_CLOSE_WITH_LOSS); 


            _safeTokenTransfer(
                creditAccount,
                underlyingToken,
                to,
                remainingFunds,
                false
            ); 
        }

        else if (operation == Constants.OPERATION_LIQUIDATION) {

            IERC20(underlyingToken).safeTransferFrom(
                liquidator,
                poolService,
                amountToPool
            ); 


            IERC20(underlyingToken).safeTransferFrom(
                liquidator,
                borrower,
                remainingFunds
            ); 
        }

        else {

            IERC20(underlyingToken).safeTransferFrom(
                msg.sender, 
                poolService,
                amountToPool
            ); 
        }


        _accountFactory.returnCreditAccount(creditAccount); 


        delete creditAccounts[borrower]; 


        IPoolService(poolService).repayCreditAccount(
            borrowedAmount,
            profit,
            loss
        ); 

        return (amountToPool, remainingFunds); 
    }





    function _calcClosePayments(
        address creditAccount,
        uint256 totalValue,
        bool isLiquidated
    )
        public
        view
        returns (
            uint256 _borrowedAmount,
            uint256 amountToPool,
            uint256 remainingFunds,
            uint256 profit,
            uint256 loss
        )
    {

        (
            uint256 borrowedAmount,
            uint256 cumulativeIndexAtCreditAccountOpen_RAY
        ) = getCreditAccountParameters(creditAccount); 

        return
            _calcClosePaymentsPure(
                totalValue,
                isLiquidated,
                borrowedAmount,
                cumulativeIndexAtCreditAccountOpen_RAY,
                IPoolService(poolService).calcLinearCumulative_RAY()
            );
    }







    function _calcClosePaymentsPure(
        uint256 totalValue,
        bool isLiquidated,
        uint256 borrowedAmount,
        uint256 cumulativeIndexAtCreditAccountOpen_RAY,
        uint256 cumulativeIndexNow_RAY
    )
        public
        view
        returns (
            uint256 _borrowedAmount,
            uint256 amountToPool,
            uint256 remainingFunds,
            uint256 profit,
            uint256 loss
        )
    {
        uint256 totalFunds = isLiquidated
            ? totalValue.mul(liquidationDiscount).div(
                PercentageMath.PERCENTAGE_FACTOR
            )
            : totalValue; 

        _borrowedAmount = borrowedAmount; 

        uint256 borrowedAmountWithInterest = borrowedAmount
        .mul(cumulativeIndexNow_RAY)
        .div(cumulativeIndexAtCreditAccountOpen_RAY); 

        if (totalFunds < borrowedAmountWithInterest) {
            amountToPool = totalFunds.sub(1); 
            loss = borrowedAmountWithInterest.sub(amountToPool); 
        } else {
            amountToPool = isLiquidated
                ? totalFunds.percentMul(feeLiquidation).add(
                    borrowedAmountWithInterest
                )
                : totalFunds
                .sub(borrowedAmountWithInterest)
                .percentMul(feeSuccess)
                .add(borrowedAmountWithInterest)
                .add(
                    borrowedAmountWithInterest.sub(borrowedAmount).percentMul(
                        feeInterest
                    )
                ); 

            amountToPool = totalFunds >= amountToPool
                ? amountToPool
                : totalFunds; 
            profit = amountToPool.sub(borrowedAmountWithInterest); 
            remainingFunds = totalFunds > amountToPool
                ? totalFunds.sub(amountToPool).sub(1)
                : 0; 
        }
    }




    function _transferAssetsTo(
        address creditAccount,
        address to,
        bool force
    ) internal returns (uint256 totalValue, uint256 totalWeightedValue) {
        totalValue = 0;
        totalWeightedValue = 0;

        uint256 tokenMask;
        uint256 enabledTokens = creditFilter.enabledTokens(creditAccount);

        for (uint256 i = 0; i < creditFilter.allowedTokensCount(); i++) {
            tokenMask = 1 << i;
            if (enabledTokens & tokenMask > 0) {
                (
                    address token,
                    uint256 amount,
                    uint256 tv,
                    uint256 tvw
                ) = creditFilter.getCreditAccountTokenById(creditAccount, i); 
                if (amount > 1) {
                    _safeTokenTransfer(
                        creditAccount,
                        token,
                        to,
                        amount.sub(1),
                        force
                    ); 


                    totalValue += tv;
                    totalWeightedValue += tvw;
                } 
            }
        }
    }








    function _safeTokenTransfer(
        address creditAccount,
        address token,
        address to,
        uint256 amount,
        bool force
    ) internal {
        if (token != wethAddress) {
            try
                ICreditAccount(creditAccount).safeTransfer(token, to, amount) 
            {} catch {
                require(force, Errors.CM_TRANSFER_FAILED); 
            }
        } else {
            ICreditAccount(creditAccount).safeTransfer(
                token,
                wethGateway,
                amount
            ); 
            IWETHGateway(wethGateway).unwrapWETH(to, amount); 
        }
    }






    function increaseBorrowedAmount(uint256 amount)
        external
        override
        whenNotPaused 
        nonReentrant
    {
        address creditAccount = getCreditAccountOrRevert(msg.sender); 

        (
            uint256 borrowedAmount,
            uint256 cumulativeIndexAtOpen
        ) = getCreditAccountParameters(creditAccount); 

        require(
            borrowedAmount.add(amount) <
                maxAmount.mul(maxLeverageFactor).div(
                    Constants.LEVERAGE_DECIMALS
                ),
            Errors.CM_INCORRECT_AMOUNT
        ); 

        uint256 timeDiscountedAmount = amount.mul(cumulativeIndexAtOpen).div(
            IPoolService(poolService).calcLinearCumulative_RAY()
        ); 


        IPoolService(poolService).lendCreditAccount(amount, creditAccount); 


        ICreditAccount(creditAccount).updateBorrowedAmount(
            borrowedAmount.add(timeDiscountedAmount)
        ); 

        require(
            creditFilter.calcCreditAccountHealthFactor(creditAccount) >=
                minHealthFactor,
            Errors.CM_CAN_UPDATE_WITH_SUCH_HEALTH_FACTOR
        ); 

        emit IncreaseBorrowedAmount(msg.sender, amount); 
    }





    function addCollateral(
        address onBehalfOf,
        address token,
        uint256 amount
    )
        external
        override
        whenNotPaused 
        nonReentrant
    {
        address creditAccount = getCreditAccountOrRevert(onBehalfOf); 
        creditFilter.checkAndEnableToken(creditAccount, token); 
        IERC20(token).safeTransferFrom(msg.sender, creditAccount, amount); 
        emit AddCollateral(onBehalfOf, token, amount); 
    }









    function setParams(
        uint256 _minAmount,
        uint256 _maxAmount,
        uint256 _maxLeverageFactor,
        uint256 _feeSuccess,
        uint256 _feeInterest,
        uint256 _feeLiquidation,
        uint256 _liquidationDiscount
    )
        public
        configuratorOnly 
    {
        require(_minAmount <= _maxAmount, Errors.CM_INCORRECT_LIMITS); 

        minAmount = _minAmount; 
        maxAmount = _maxAmount; 

        maxLeverageFactor = _maxLeverageFactor;

        feeSuccess = _feeSuccess; 
        feeInterest = _feeInterest; 
        feeLiquidation = _feeLiquidation; 
        liquidationDiscount = _liquidationDiscount; 


        minHealthFactor = liquidationDiscount
        .sub(feeLiquidation)
        .mul(maxLeverageFactor.add(Constants.LEVERAGE_DECIMALS))
        .div(maxLeverageFactor); 

        if (address(creditFilter) != address(0)) {
            creditFilter.updateUnderlyingTokenLiquidationThreshold(); 
        }

        emit NewParameters(
            minAmount,
            maxAmount,
            maxLeverageFactor,
            feeSuccess,
            feeInterest,
            feeLiquidation,
            liquidationDiscount
        ); 
    }




    function approve(address targetContract, address token)
        external
        override
        whenNotPaused 
        nonReentrant
    {
        address creditAccount = getCreditAccountOrRevert(msg.sender);


        require(
            creditFilter.contractToAdapter(targetContract) != address(0),
            Errors.CM_TARGET_CONTRACT_iS_NOT_ALLOWED
        );
        _provideCreditAccountAllowance(creditAccount, targetContract, token);
    }





    function provideCreditAccountAllowance(
        address creditAccount,
        address targetContract,
        address token
    )
        external
        override
        allowedAdaptersOnly(targetContract) 
        whenNotPaused 
        nonReentrant
    {
        _provideCreditAccountAllowance(creditAccount, targetContract, token); 
    }





    function _provideCreditAccountAllowance(
        address creditAccount,
        address toContract,
        address token
    ) internal {

        if (
            IERC20(token).allowance(creditAccount, toContract) <
            Constants.MAX_INT_4
        ) {
            ICreditAccount(creditAccount).approveToken(token, toContract); 
        }
    }




    function _convertAllAssetsToUnderlying(
        address creditAccount,
        DataTypes.Exchange[] calldata paths
    ) internal {
        uint256 tokenMask;
        uint256 enabledTokens = creditFilter.enabledTokens(creditAccount); 

        for (uint256 i = 1; i < creditFilter.allowedTokensCount(); i++) {
            tokenMask = 1 << i;
            if (enabledTokens & tokenMask > 0) {
                (address tokenAddr, uint256 amount, , ) = creditFilter
                .getCreditAccountTokenById(creditAccount, i); 

                if (amount > 0) {
                    _provideCreditAccountAllowance(
                        creditAccount,
                        defaultSwapContract,
                        tokenAddr
                    ); 


                    address[] memory currentPath = paths[i].path;
                    currentPath[0] = tokenAddr;
                    currentPath[paths[i].path.length - 1] = underlyingToken;

                    bytes memory data = abi.encodeWithSelector(
                        bytes4(0x38ed1739), 
                        amount,
                        paths[i].amountOutMin, 
                        currentPath,
                        creditAccount,
                        block.timestamp
                    ); 

                    CreditAccount(creditAccount).execute(
                        defaultSwapContract,
                        data
                    ); 
                }
            }
        }
    }





    function executeOrder(
        address borrower,
        address target,
        bytes memory data
    )
        external
        override
        allowedAdaptersOnly(target) 
        whenNotPaused 
        nonReentrant
        returns (bytes memory)
    {
        address creditAccount = getCreditAccountOrRevert(borrower); 
        emit ExecuteOrder(borrower, target);
        return CreditAccount(creditAccount).execute(target, data); 
    }







    function hasOpenedCreditAccount(address borrower)
        public
        view
        override
        returns (bool)
    {
        return creditAccounts[borrower] != address(0); 
    }



    function getCreditAccountOrRevert(address borrower)
        public
        view
        override
        returns (address)
    {
        address result = creditAccounts[borrower]; 
        require(result != address(0), Errors.CM_NO_OPEN_ACCOUNT); 
        return result;
    }








    function calcRepayAmount(address borrower, bool isLiquidated)
        external
        view
        override
        returns (uint256)
    {
        address creditAccount = getCreditAccountOrRevert(borrower);
        uint256 totalValue = creditFilter.calcTotalValue(creditAccount);

        (
            ,
            uint256 amountToPool,
            uint256 remainingFunds,
            ,

        ) = _calcClosePayments(creditAccount, totalValue, isLiquidated); 

        return isLiquidated ? amountToPool.add(remainingFunds) : amountToPool; 
    }





    function getCreditAccountParameters(address creditAccount)
        internal
        view
        returns (uint256 borrowedAmount, uint256 cumulativeIndexAtOpen)
    {
        borrowedAmount = ICreditAccount(creditAccount).borrowedAmount();
        cumulativeIndexAtOpen = ICreditAccount(creditAccount)
        .cumulativeIndexAtOpen();
    }



    function transferAccountOwnership(address newOwner)
        external
        override
        whenNotPaused 
        nonReentrant
    {
        address creditAccount = getCreditAccountOrRevert(msg.sender); 
        require(
            newOwner != address(0) && !hasOpenedCreditAccount(newOwner),
            Errors.CM_INCORRECT_NEW_OWNER
        ); 
        delete creditAccounts[msg.sender]; 
        creditAccounts[newOwner] = creditAccount; 
        emit TransferAccount(msg.sender, newOwner); 
    }
}

pragma solidity ^0.7.4;

import {ReentrancyGuard} from "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import {ACLTrait} from "../core/ACLTrait.sol";

import {IERC20} from "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import {SafeERC20} from "@openzeppelin/contracts/token/ERC20/SafeERC20.sol";
import {Math} from "@openzeppelin/contracts/math/Math.sol";
import {SafeMath} from "@openzeppelin/contracts/math/SafeMath.sol";
import {WadRayMath} from "../libraries/math/WadRayMath.sol";
import {PercentageMath} from "../libraries/math/PercentageMath.sol";

import {IInterestRateModel} from "../interfaces/IInterestRateModel.sol";
import {IPoolService} from "../interfaces/IPoolService.sol";
import {ICreditFilter} from "../interfaces/ICreditFilter.sol";
import {ICreditManager} from "../interfaces/ICreditManager.sol";

import {AddressProvider} from "../core/AddressProvider.sol";
import {DieselToken} from "../tokens/DieselToken.sol";
import {Constants} from "../libraries/helpers/Constants.sol";
import {Errors} from "../libraries/helpers/Errors.sol";

import "hardhat/console.sol";








contract PoolService is IPoolService, ACLTrait, ReentrancyGuard {
    using SafeMath for uint256;
    using WadRayMath for uint256;
    using SafeERC20 for IERC20;
    using PercentageMath for uint256;


    uint256 public _expectedLiquidityLU;


    uint256 public override expectedLiquidityLimit;


    uint256 public override totalBorrowed;


    AddressProvider public addressProvider;


    IInterestRateModel public interestRateModel;


    address public override underlyingToken;


    address public override dieselToken;


    mapping(address => bool) public override creditManagersCanBorrow;
    mapping(address => bool) public creditManagersCanRepay;


    address[] public override creditManagers;


    address public treasuryAddress;


    uint256 public override _cumulativeIndex_RAY;


    uint256 public override borrowAPY_RAY;


    uint256 public override _timestampLU;


    uint256 public override withdrawFee;


    uint256 public withdrawMultiplier;










    constructor(
        address _addressProvider,
        address _underlyingToken,
        address _dieselAddress,
        address _interestRateModelAddress
    ) ACLTrait(_addressProvider) {
        addressProvider = AddressProvider(_addressProvider);
        interestRateModel = IInterestRateModel(_interestRateModelAddress);
        underlyingToken = _underlyingToken;
        dieselToken = _dieselAddress;
        treasuryAddress = addressProvider.getTreasuryContract();

        _cumulativeIndex_RAY = WadRayMath.RAY; 
        _updateBorrowRate(); 

        setWithdrawFee(0);
    }






    function addLiquidity(
        uint256 amount,
        address onBehalfOf,
        uint256 referralCode
    )
        external
        override
        whenNotPaused 
        nonReentrant
    {

        require(
            expectedLiquidity() + amount <= expectedLiquidityLimit,
            Errors.POOL_MORE_THAN_EXPECTED_LIQUIDITY_LIMIT
        ); 

        IERC20(underlyingToken).safeTransferFrom(
            msg.sender,
            address(this),
            amount
        ); 

        DieselToken(dieselToken).mint(onBehalfOf, toDiesel(amount)); 

        _expectedLiquidityLU = _expectedLiquidityLU.add(amount); 
        _updateBorrowRate(); 

        emit AddLiquidity(msg.sender, onBehalfOf, amount, referralCode); 
    }


    function removeLiquidity(uint256 amount, address to)
        external
        override
        whenNotPaused 
        nonReentrant
        returns (uint256)
    {
        uint256 underlyingTokensAmount = fromDiesel(amount); 

        uint256 amountSent = underlyingTokensAmount.percentMul(
            withdrawMultiplier
        );

        IERC20(underlyingToken).safeTransfer(to, amountSent); 
        IERC20(underlyingToken).safeTransfer(
            treasuryAddress,
            underlyingTokensAmount.percentMul(withdrawFee)
        ); 
        DieselToken(dieselToken).burn(msg.sender, amount); 

        _expectedLiquidityLU = _expectedLiquidityLU.sub(underlyingTokensAmount); 
        _updateBorrowRate(); 

        emit RemoveLiquidity(msg.sender, to, amount); 

        return amountSent;
    }





    function expectedLiquidity() public view override returns (uint256) {

        uint256 timeDifference = block.timestamp.sub(uint256(_timestampLU));





        uint256 interestAccrued = totalBorrowed.rayMul(
            borrowAPY_RAY.mul(timeDifference).div(Constants.SECONDS_PER_YEAR)
        ); 

        return _expectedLiquidityLU.add(interestAccrued); 
    }



    function availableLiquidity() public view override returns (uint256) {
        return IERC20(underlyingToken).balanceOf(address(this));
    }











    function lendCreditAccount(uint256 borrowedAmount, address creditAccount)
        external
        override
        whenNotPaused 
    {
        require(
            creditManagersCanBorrow[msg.sender],
            Errors.POOL_CREDIT_MANAGERS_ONLY
        ); 


        IERC20(underlyingToken).safeTransfer(creditAccount, borrowedAmount); 


        _updateBorrowRate(); 


        totalBorrowed = totalBorrowed.add(borrowedAmount); 

        emit Borrow(msg.sender, creditAccount, borrowedAmount); 
    }







    function repayCreditAccount(
        uint256 borrowedAmount,
        uint256 profit,
        uint256 loss
    )
        external
        override
        whenNotPaused 
    {
        require(
            creditManagersCanRepay[msg.sender],
            Errors.POOL_CREDIT_MANAGERS_ONLY
        ); 


        if (profit > 0) {

            DieselToken(dieselToken).mint(treasuryAddress, toDiesel(profit)); 
            _expectedLiquidityLU = _expectedLiquidityLU.add(profit); 
        }



        else {
            uint256 amountToBurn = toDiesel(loss); 

            uint256 treasuryBalance = DieselToken(dieselToken).balanceOf(
                treasuryAddress
            ); 

            if (treasuryBalance < amountToBurn) {
                amountToBurn = treasuryBalance;
                emit UncoveredLoss(
                    msg.sender,
                    loss.sub(fromDiesel(treasuryBalance))
                ); 
            }



            DieselToken(dieselToken).burn(treasuryAddress, amountToBurn); 

            _expectedLiquidityLU = _expectedLiquidityLU.sub(loss); 
        }


        _updateBorrowRate(); 


        totalBorrowed = totalBorrowed.sub(borrowedAmount); 

        emit Repay(msg.sender, borrowedAmount, profit, loss); 
    }






    function calcLinearCumulative_RAY() public view override returns (uint256) {

        uint256 timeDifference = block.timestamp.sub(uint256(_timestampLU)); 

        return
            calcLinearIndex_RAY(
                _cumulativeIndex_RAY,
                borrowAPY_RAY,
                timeDifference
            ); 
    }






    function calcLinearIndex_RAY(
        uint256 cumulativeIndex_RAY,
        uint256 currentBorrowRate_RAY,
        uint256 timeDifference
    ) public pure returns (uint256) {




        uint256 linearAccumulated_RAY = WadRayMath.RAY.add(
            currentBorrowRate_RAY.mul(timeDifference).div(
                Constants.SECONDS_PER_YEAR
            )
        ); 

        return cumulativeIndex_RAY.rayMul(linearAccumulated_RAY); 
    }





    function _updateBorrowRate() internal {


        _expectedLiquidityLU = expectedLiquidity(); 


        _cumulativeIndex_RAY = calcLinearCumulative_RAY(); 


        borrowAPY_RAY = interestRateModel.calcBorrowRate(
            _expectedLiquidityLU,
            availableLiquidity()
        ); 
        _timestampLU = block.timestamp; 
    }







    function getDieselRate_RAY() public view override returns (uint256) {
        uint256 dieselSupply = IERC20(dieselToken).totalSupply();
        if (dieselSupply == 0) return WadRayMath.RAY; 
        return expectedLiquidity().rayDiv(dieselSupply); 
    }



    function toDiesel(uint256 amount) public view override returns (uint256) {
        return amount.rayDiv(getDieselRate_RAY()); 
    }



    function fromDiesel(uint256 amount) public view override returns (uint256) {
        return amount.rayMul(getDieselRate_RAY()); 
    }







    function connectCreditManager(address _creditManager)
        external
        configuratorOnly 
    {
        require(
            address(this) == ICreditManager(_creditManager).poolService(),
            Errors.POOL_INCOMPATIBLE_CREDIT_ACCOUNT_MANAGER
        ); 

        require(
            !creditManagersCanRepay[_creditManager],
            Errors.POOL_CANT_ADD_CREDIT_MANAGER_TWICE
        ); 

        creditManagersCanBorrow[_creditManager] = true; 
        creditManagersCanRepay[_creditManager] = true; 
        creditManagers.push(_creditManager); 
        emit NewCreditManagerConnected(_creditManager); 
    }



    function forbidCreditManagerToBorrow(address _creditManager)
        external
        configuratorOnly 
    {
        creditManagersCanBorrow[_creditManager] = false; 
        emit BorrowForbidden(_creditManager); 
    }



    function newInterestRateModel(address _interestRateModel)
        external
        configuratorOnly 
    {
        interestRateModel = IInterestRateModel(_interestRateModel); 
        _updateBorrowRate(); 
        emit NewInterestRateModel(_interestRateModel); 
    }



    function setExpectedLiquidityLimit(uint256 newLimit)
        external
        configuratorOnly 
    {
        expectedLiquidityLimit = newLimit; 
        emit NewExpectedLiquidityLimit(newLimit); 
    }


    function setWithdrawFee(uint256 fee)
        public
        configuratorOnly 
    {
        require(
            fee < Constants.MAX_WITHDRAW_FEE,
            Errors.POOL_INCORRECT_WITHDRAW_FEE
        ); 
        withdrawFee = fee; 
        withdrawMultiplier = PercentageMath.PERCENTAGE_FACTOR.sub(fee); 
    }


    function creditManagersCount() external view override returns (uint256) {
        return creditManagers.length; 
    }
}

pragma solidity 0.6.12;
pragma experimental ABIEncoderV2;

import {IERC20} from '../../../dependencies/openzeppelin/contracts/IERC20.sol';
import {SafeERC20} from '../../../dependencies/openzeppelin/contracts/SafeERC20.sol';
import {ILendingPool} from '../../../interfaces/ILendingPool.sol';
import {IAToken} from '../../../interfaces/IAToken.sol';
import {WadRayMath} from '../../libraries/math/WadRayMath.sol';
import {Errors} from '../../libraries/helpers/Errors.sol';
import {
  VersionedInitializable
} from '../../libraries/aave-upgradeability/VersionedInitializable.sol';
import {IncentivizedERC20} from '../IncentivizedERC20.sol';
import {IAaveIncentivesController} from '../../../interfaces/IAaveIncentivesController.sol';
import {DataTypes} from '../../libraries/types/DataTypes.sol';
import {ISTETH} from '../../../interfaces/ISTETH.sol';
import {SignedSafeMath} from '../../../dependencies/openzeppelin/contracts/SignedSafeMath.sol';
import {UInt256Lib} from '../../../dependencies/uFragments/UInt256Lib.sol';

interface IBookKeptBorrowing {

  function getBorrowData() external view returns (uint256, int256);
}


contract AStETH is VersionedInitializable, IncentivizedERC20, IAToken {
  using WadRayMath for uint256;
  using SafeERC20 for IERC20;
  using UInt256Lib for uint256;
  using SignedSafeMath for int256;

  bytes public constant EIP712_REVISION = bytes('1');
  bytes32 internal constant EIP712_DOMAIN =
    keccak256('EIP712Domain(string name,string version,uint256 chainId,address verifyingContract)');
  bytes32 public constant PERMIT_TYPEHASH =
    keccak256('Permit(address owner,address spender,uint256 value,uint256 nonce,uint256 deadline)');

  uint256 public constant UINT_MAX_VALUE = uint256(-1);
  uint256 public constant ATOKEN_REVISION = 0x1;
  address public immutable UNDERLYING_ASSET_ADDRESS;
  address public immutable RESERVE_TREASURY_ADDRESS;
  ILendingPool public immutable POOL;


  mapping(address => uint256) public _nonces;

  bytes32 public DOMAIN_SEPARATOR;



  IBookKeptBorrowing internal _variableDebtStETH;
  int256 internal _totalShares;

  struct ExtData {
    uint256 totalStETHSupply;
    uint256 totalPrincipalBorrowed;
    int256 totalSharesBorrowed;
  }


  modifier onlyLendingPool() {
    require(_msgSender() == address(POOL), Errors.CT_CALLER_MUST_BE_LENDING_POOL);
    _;
  }

  constructor(
    ILendingPool pool,
    address underlyingAssetAddress,
    address reserveTreasuryAddress,
    string memory tokenName,
    string memory tokenSymbol,
    address incentivesController
  ) public IncentivizedERC20(tokenName, tokenSymbol, 18, incentivesController) {
    POOL = pool;
    UNDERLYING_ASSET_ADDRESS = underlyingAssetAddress;
    RESERVE_TREASURY_ADDRESS = reserveTreasuryAddress;
  }

  function getRevision() internal pure virtual override returns (uint256) {
    return ATOKEN_REVISION;
  }

  function initialize(
    uint8 underlyingAssetDecimals,
    string calldata tokenName,
    string calldata tokenSymbol
  ) external virtual initializer {
    uint256 chainId;


    assembly {
      chainId := chainid()
    }

    DOMAIN_SEPARATOR = keccak256(
      abi.encode(
        EIP712_DOMAIN,
        keccak256(bytes(tokenName)),
        keccak256(EIP712_REVISION),
        chainId,
        address(this)
      )
    );

    _setName(tokenName);
    _setSymbol(tokenSymbol);
    _setDecimals(underlyingAssetDecimals);
  }

  function initializeDebtToken() external {
    DataTypes.ReserveData memory reserveData = POOL.getReserveData(UNDERLYING_ASSET_ADDRESS);
    _variableDebtStETH = IBookKeptBorrowing(reserveData.variableDebtTokenAddress);
  }


  function burn(
    address user,
    address receiverOfUnderlying,
    uint256 amount,
    uint256 index
  ) external override onlyLendingPool {
    uint256 amountScaled = amount.rayDiv(index);
    require(amountScaled != 0, Errors.CT_INVALID_BURN_AMOUNT);

    _burnScaled(user, amountScaled, _fetchExtData());
    _totalShares = _totalShares.sub(
      ISTETH(UNDERLYING_ASSET_ADDRESS).getSharesByPooledEth(amountScaled).toInt256Safe()
    );

    IERC20(UNDERLYING_ASSET_ADDRESS).safeTransfer(receiverOfUnderlying, amount);

    emit Transfer(user, address(0), amount);
    emit Burn(user, receiverOfUnderlying, amount, index);
  }


  function mint(
    address user,
    uint256 amount,
    uint256 index
  ) external override onlyLendingPool returns (bool) {
    uint256 previousBalance = super.balanceOf(user);

    uint256 amountScaled = amount.rayDiv(index);
    require(amountScaled != 0, Errors.CT_INVALID_MINT_AMOUNT);

    _mintScaled(user, amountScaled, _fetchExtData());
    _totalShares = _totalShares.add(
      ISTETH(UNDERLYING_ASSET_ADDRESS).getSharesByPooledEth(amountScaled).toInt256Safe()
    );

    emit Transfer(address(0), user, amount);
    emit Mint(user, amount, index);

    return previousBalance == 0;
  }


  function mintToTreasury(uint256 amount, uint256 index) external override onlyLendingPool {
    if (amount == 0) {
      return;
    }

    address treasury = RESERVE_TREASURY_ADDRESS;





    uint256 amountScaled = amount.rayDiv(index);
    _mintScaled(treasury, amountScaled, _fetchExtData());
    _totalShares = _totalShares.add(
      ISTETH(UNDERLYING_ASSET_ADDRESS).getSharesByPooledEth(amountScaled).toInt256Safe()
    );

    emit Transfer(address(0), treasury, amount);
    emit Mint(treasury, amount, index);
  }


  function transferOnLiquidation(
    address from,
    address to,
    uint256 value
  ) external override onlyLendingPool {


    _transfer(from, to, value, false);

    emit Transfer(from, to, value);
  }


  function balanceOf(address user)
    public
    view
    override(IncentivizedERC20, IERC20)
    returns (uint256)
  {
    uint256 userBalanceScaled =
      _scaledBalanceOf(
        super.balanceOf(user),
        super.totalSupply(),
        _scaledTotalSupply(_fetchExtData())
      );

    if (userBalanceScaled == 0) {
      return 0;
    }

    return userBalanceScaled.rayMul(POOL.getReserveNormalizedIncome(UNDERLYING_ASSET_ADDRESS));
  }


  function scaledBalanceOf(address user) external view override returns (uint256) {
    return
      _scaledBalanceOf(
        super.balanceOf(user),
        super.totalSupply(),
        _scaledTotalSupply(_fetchExtData())
      );
  }


  function getScaledUserBalanceAndSupply(address user)
    external
    view
    override
    returns (uint256, uint256)
  {
    uint256 scaledTotalSupply = _scaledTotalSupply(_fetchExtData());
    return (
      _scaledBalanceOf(super.balanceOf(user), super.totalSupply(), scaledTotalSupply),
      scaledTotalSupply
    );
  }


  function getInternalUserBalanceAndSupply(address user) external view returns (uint256, uint256) {
    return (super.balanceOf(user), super.totalSupply());
  }


  function totalSupply() public view override(IncentivizedERC20, IERC20) returns (uint256) {
    uint256 currentSupplyScaled = _scaledTotalSupply(_fetchExtData());

    if (currentSupplyScaled == 0) {
      return 0;
    }

    return currentSupplyScaled.rayMul(POOL.getReserveNormalizedIncome(UNDERLYING_ASSET_ADDRESS));
  }


  function scaledTotalSupply() public view virtual override returns (uint256) {
    return _scaledTotalSupply(_fetchExtData());
  }


  function internalTotalSupply() public view returns (uint256) {
    return super.totalSupply();
  }


  function transferUnderlyingTo(address target, uint256 amount)
    external
    override
    onlyLendingPool
    returns (uint256)
  {
    IERC20(UNDERLYING_ASSET_ADDRESS).safeTransfer(target, amount);
    return amount;
  }


  function permit(
    address owner,
    address spender,
    uint256 value,
    uint256 deadline,
    uint8 v,
    bytes32 r,
    bytes32 s
  ) external {
    require(owner != address(0), 'INVALID_OWNER');

    require(block.timestamp <= deadline, 'INVALID_EXPIRATION');
    uint256 currentValidNonce = _nonces[owner];
    bytes32 digest =
      keccak256(
        abi.encodePacked(
          '\x19\x01',
          DOMAIN_SEPARATOR,
          keccak256(abi.encode(PERMIT_TYPEHASH, owner, spender, value, currentValidNonce, deadline))
        )
      );
    require(owner == ecrecover(digest, v, r, s), 'INVALID_SIGNATURE');
    _nonces[owner] = currentValidNonce.add(1);
    _approve(owner, spender, value);
  }


  function _transfer(
    address from,
    address to,
    uint256 amount,
    bool validate
  ) internal {
    uint256 index = POOL.getReserveNormalizedIncome(UNDERLYING_ASSET_ADDRESS);
    uint256 amountScaled = amount.rayDiv(index);

    ExtData memory e = _fetchExtData();
    uint256 totalSupplyInternal = super.totalSupply();

    uint256 scaledTotalSupply = _scaledTotalSupply(e);
    uint256 fromBalanceScaled =
      _scaledBalanceOf(super.balanceOf(from), totalSupplyInternal, scaledTotalSupply);
    uint256 toBalanceScaled =
      _scaledBalanceOf(super.balanceOf(to), totalSupplyInternal, scaledTotalSupply);

    _transferScaled(from, to, amountScaled, e);

    if (validate) {
      POOL.finalizeTransfer(
        UNDERLYING_ASSET_ADDRESS,
        from,
        to,
        amount,
        fromBalanceScaled.rayMul(index),
        toBalanceScaled.rayMul(index)
      );
    }

    emit BalanceTransfer(from, to, amount, index);
  }


  function _transfer(
    address from,
    address to,
    uint256 amount
  ) internal override {
    _transfer(from, to, amount, true);
  }





  function _mintScaled(
    address user,
    uint256 mintAmountScaled,
    ExtData memory e
  ) internal {
    uint256 totalSupplyInternalBefore = super.totalSupply();
    uint256 userBalanceInternalBefore = super.balanceOf(user);


    if (totalSupplyInternalBefore == 0) {
      _mint(user, ISTETH(UNDERLYING_ASSET_ADDRESS).getSharesByPooledEth(mintAmountScaled));
      return;
    }

    uint256 scaledTotalSupplyBefore = _scaledTotalSupply(e);

    uint256 userBalanceScaledBefore =
      _scaledBalanceOf(
        userBalanceInternalBefore,
        totalSupplyInternalBefore,
        scaledTotalSupplyBefore
      );
    uint256 otherBalanceScaledBefore = scaledTotalSupplyBefore.sub(userBalanceScaledBefore);

    uint256 scaledTotalSupplyAfter = scaledTotalSupplyBefore.add(mintAmountScaled);
    uint256 userBalanceScaledAfter = userBalanceScaledBefore.add(mintAmountScaled);
    uint256 mintAmountInternal = 0;


    if (otherBalanceScaledBefore == 0) {
      uint256 mintAmountInternal =
        mintAmountScaled.mul(totalSupplyInternalBefore).div(scaledTotalSupplyBefore);
      _mint(user, mintAmountInternal);
      return;
    }

    mintAmountInternal = totalSupplyInternalBefore
      .mul(userBalanceScaledAfter)
      .sub(scaledTotalSupplyAfter.mul(userBalanceInternalBefore))
      .div(otherBalanceScaledBefore);

    _mint(user, mintAmountInternal);
  }


  function _burnScaled(
    address user,
    uint256 burnAmountScaled,
    ExtData memory e
  ) internal {
    uint256 totalSupplyInternalBefore = super.totalSupply();
    uint256 userBalanceInternalBefore = super.balanceOf(user);

    uint256 scaledTotalSupplyBefore = _scaledTotalSupply(e);
    uint256 userBalanceScaledBefore =
      _scaledBalanceOf(
        userBalanceInternalBefore,
        totalSupplyInternalBefore,
        scaledTotalSupplyBefore
      );

    uint256 otherBalanceScaledBefore = 0;
    if (userBalanceScaledBefore <= scaledTotalSupplyBefore) {
      otherBalanceScaledBefore = scaledTotalSupplyBefore.sub(userBalanceScaledBefore);
    }

    uint256 scaledTotalSupplyAfter = 0;
    if (burnAmountScaled <= scaledTotalSupplyBefore) {
      scaledTotalSupplyAfter = scaledTotalSupplyBefore.sub(burnAmountScaled);
    }

    uint256 userBalanceScaledAfter = 0;
    if (burnAmountScaled <= userBalanceScaledBefore) {
      userBalanceScaledAfter = userBalanceScaledBefore.sub(burnAmountScaled);
    }

    uint256 burnAmountInternal = 0;


    if (otherBalanceScaledBefore == 0) {
      _burn(user, burnAmountScaled.mul(totalSupplyInternalBefore).div(scaledTotalSupplyBefore));
      return;
    }

    burnAmountInternal = scaledTotalSupplyAfter
      .mul(userBalanceInternalBefore)
      .sub(totalSupplyInternalBefore.mul(userBalanceScaledAfter))
      .div(otherBalanceScaledBefore);

    _burn(user, burnAmountInternal);
  }


  function _fetchExtData() internal view returns (ExtData memory) {
    ExtData memory extData;

    extData.totalStETHSupply = ISTETH(UNDERLYING_ASSET_ADDRESS).totalSupply();
    (extData.totalPrincipalBorrowed, extData.totalSharesBorrowed) = _variableDebtStETH
      .getBorrowData();

    return extData;
  }


  function _scaledBalanceOf(
    uint256 _intBalanceOf,
    uint256 _intTotalSupply,
    uint256 _scaledTotalSupply
  ) private pure returns (uint256) {
    if (_intBalanceOf == 0 || _intTotalSupply == 0) {
      return 0;
    }
    return _intBalanceOf.wadMul(_scaledTotalSupply).wadDiv(_intTotalSupply);
  }


  function _scaledTotalSupply(ExtData memory e) private view returns (uint256) {
    return

      ISTETH(UNDERLYING_ASSET_ADDRESS).getPooledEthByShares(
        uint256(_totalShares - e.totalSharesBorrowed)
      ) + e.totalPrincipalBorrowed;
  }


  function _transferScaled(
    address from,
    address to,
    uint256 transferAmountScaled,
    ExtData memory e
  ) private {
    uint256 totalSupplyInternal = super.totalSupply();
    uint256 scaledTotalSupply = _scaledTotalSupply(e);
    uint256 transferAmountInternal =
      transferAmountScaled.mul(totalSupplyInternal).div(scaledTotalSupply);
    super._transfer(from, to, transferAmountInternal);
  }

  function VARIABLE_DEBT_TOKEN_ADDRESS() external view returns (address) {
    return address(_variableDebtStETH);
  }
}

pragma solidity 0.4.24;

import "@aragon/os/contracts/apps/AragonApp.sol";
import "@aragon/os/contracts/common/IsContract.sol";
import "@aragon/os/contracts/lib/math/SafeMath.sol";
import "@aragon/os/contracts/lib/math/SafeMath64.sol";
import "solidity-bytes-utils/contracts/BytesLib.sol";

import "../interfaces/INodeOperatorsRegistry.sol";
import "../lib/MemUtils.sol";



contract NodeOperatorsRegistry is INodeOperatorsRegistry, IsContract, AragonApp {
    using SafeMath for uint256;
    using SafeMath64 for uint64;
    using UnstructuredStorage for bytes32;


    bytes32 constant public MANAGE_SIGNING_KEYS = keccak256("MANAGE_SIGNING_KEYS");
    bytes32 constant public ADD_NODE_OPERATOR_ROLE = keccak256("ADD_NODE_OPERATOR_ROLE");
    bytes32 constant public SET_NODE_OPERATOR_ACTIVE_ROLE = keccak256("SET_NODE_OPERATOR_ACTIVE_ROLE");
    bytes32 constant public SET_NODE_OPERATOR_NAME_ROLE = keccak256("SET_NODE_OPERATOR_NAME_ROLE");
    bytes32 constant public SET_NODE_OPERATOR_ADDRESS_ROLE = keccak256("SET_NODE_OPERATOR_ADDRESS_ROLE");
    bytes32 constant public SET_NODE_OPERATOR_LIMIT_ROLE = keccak256("SET_NODE_OPERATOR_LIMIT_ROLE");
    bytes32 constant public REPORT_STOPPED_VALIDATORS_ROLE = keccak256("REPORT_STOPPED_VALIDATORS_ROLE");

    uint256 constant public PUBKEY_LENGTH = 48;
    uint256 constant public SIGNATURE_LENGTH = 96;

    uint256 internal constant UINT64_MAX = uint256(uint64(-1));

    bytes32 internal constant SIGNING_KEYS_MAPPING_NAME = keccak256("lido.NodeOperatorsRegistry.signingKeysMappingName");



    struct NodeOperator {
        bool active;    
        address rewardAddress;  
        string name;    
        uint64 stakingLimit;    
        uint64 stoppedValidators;   

        uint64 totalSigningKeys;    
        uint64 usedSigningKeys;     
    }


    struct DepositLookupCacheEntry {

        uint256 id;
        uint256 stakingLimit;
        uint256 stoppedValidators;
        uint256 totalSigningKeys;
        uint256 usedSigningKeys;
        uint256 initialUsedSigningKeys;
    }


    mapping(uint256 => NodeOperator) internal operators;


    bytes32 internal constant TOTAL_OPERATORS_COUNT_POSITION = keccak256("lido.NodeOperatorsRegistry.totalOperatorsCount");


    bytes32 internal constant ACTIVE_OPERATORS_COUNT_POSITION = keccak256("lido.NodeOperatorsRegistry.activeOperatorsCount");


    bytes32 internal constant LIDO_POSITION = keccak256("lido.NodeOperatorsRegistry.lido");


    bytes32 internal constant KEYS_OP_INDEX_POSITION = keccak256("lido.NodeOperatorsRegistry.keysOpIndex");


    modifier onlyLido() {
        require(msg.sender == LIDO_POSITION.getStorageAddress(), "APP_AUTH_FAILED");
        _;
    }

    modifier validAddress(address _a) {
        require(_a != address(0), "EMPTY_ADDRESS");
        _;
    }

    modifier operatorExists(uint256 _id) {
        require(_id < getNodeOperatorsCount(), "NODE_OPERATOR_NOT_FOUND");
        _;
    }

    function initialize(address _lido) public onlyInit {
        TOTAL_OPERATORS_COUNT_POSITION.setStorageUint256(0);
        ACTIVE_OPERATORS_COUNT_POSITION.setStorageUint256(0);
        KEYS_OP_INDEX_POSITION.setStorageUint256(0);
        LIDO_POSITION.setStorageAddress(_lido);
        initialized();
    }


    function addNodeOperator(string _name, address _rewardAddress) external
        auth(ADD_NODE_OPERATOR_ROLE)
        validAddress(_rewardAddress)
        returns (uint256 id)
    {
        id = getNodeOperatorsCount();
        TOTAL_OPERATORS_COUNT_POSITION.setStorageUint256(id.add(1));

        NodeOperator storage operator = operators[id];

        uint256 activeOperatorsCount = getActiveNodeOperatorsCount();
        ACTIVE_OPERATORS_COUNT_POSITION.setStorageUint256(activeOperatorsCount.add(1));

        operator.active = true;
        operator.name = _name;
        operator.rewardAddress = _rewardAddress;
        operator.stakingLimit = 0;

        emit NodeOperatorAdded(id, _name, _rewardAddress, 0);

        return id;
    }


    function setNodeOperatorActive(uint256 _id, bool _active) external
        authP(SET_NODE_OPERATOR_ACTIVE_ROLE, arr(_id, _active ? uint256(1) : uint256(0)))
        operatorExists(_id)
    {
        _increaseKeysOpIndex();
        if (operators[_id].active != _active) {
            uint256 activeOperatorsCount = getActiveNodeOperatorsCount();
            if (_active)
                ACTIVE_OPERATORS_COUNT_POSITION.setStorageUint256(activeOperatorsCount.add(1));
            else
                ACTIVE_OPERATORS_COUNT_POSITION.setStorageUint256(activeOperatorsCount.sub(1));
        }

        operators[_id].active = _active;

        emit NodeOperatorActiveSet(_id, _active);
    }


    function setNodeOperatorName(uint256 _id, string _name) external
        authP(SET_NODE_OPERATOR_NAME_ROLE, arr(_id))
        operatorExists(_id)
    {
        operators[_id].name = _name;
        emit NodeOperatorNameSet(_id, _name);
    }


    function setNodeOperatorRewardAddress(uint256 _id, address _rewardAddress) external
        authP(SET_NODE_OPERATOR_ADDRESS_ROLE, arr(_id, uint256(_rewardAddress)))
        operatorExists(_id)
        validAddress(_rewardAddress)
    {
        operators[_id].rewardAddress = _rewardAddress;
        emit NodeOperatorRewardAddressSet(_id, _rewardAddress);
    }


    function setNodeOperatorStakingLimit(uint256 _id, uint64 _stakingLimit) external
        authP(SET_NODE_OPERATOR_LIMIT_ROLE, arr(_id, uint256(_stakingLimit)))
        operatorExists(_id)
    {
        _increaseKeysOpIndex();
        operators[_id].stakingLimit = _stakingLimit;
        emit NodeOperatorStakingLimitSet(_id, _stakingLimit);
    }


    function reportStoppedValidators(uint256 _id, uint64 _stoppedIncrement) external
        authP(REPORT_STOPPED_VALIDATORS_ROLE, arr(_id, uint256(_stoppedIncrement)))
        operatorExists(_id)
    {
        require(0 != _stoppedIncrement, "EMPTY_VALUE");
        operators[_id].stoppedValidators = operators[_id].stoppedValidators.add(_stoppedIncrement);
        require(operators[_id].stoppedValidators <= operators[_id].usedSigningKeys, "STOPPED_MORE_THAN_LAUNCHED");

        emit NodeOperatorTotalStoppedValidatorsReported(_id, operators[_id].stoppedValidators);
    }


    function trimUnusedKeys() external onlyLido {
        uint256 length = getNodeOperatorsCount();

        for (uint256 operatorId = 0; operatorId < length; ++operatorId) {
            uint64 totalSigningKeys = operators[operatorId].totalSigningKeys;
            uint64 usedSigningKeys = operators[operatorId].usedSigningKeys;
            if (totalSigningKeys != usedSigningKeys) { 
                operators[operatorId].totalSigningKeys = usedSigningKeys;  
                emit NodeOperatorTotalKeysTrimmed(operatorId, totalSigningKeys - usedSigningKeys);
            }
        }
    }


    function addSigningKeys(uint256 _operator_id, uint256 _quantity, bytes _pubkeys, bytes _signatures) external
        authP(MANAGE_SIGNING_KEYS, arr(_operator_id))
    {
        _addSigningKeys(_operator_id, _quantity, _pubkeys, _signatures);
    }


    function addSigningKeysOperatorBH(
        uint256 _operator_id,
        uint256 _quantity,
        bytes _pubkeys,
        bytes _signatures
    )
        external
    {
        require(msg.sender == operators[_operator_id].rewardAddress, "APP_AUTH_FAILED");
        _addSigningKeys(_operator_id, _quantity, _pubkeys, _signatures);
    }


    function removeSigningKey(uint256 _operator_id, uint256 _index)
        external
        authP(MANAGE_SIGNING_KEYS, arr(_operator_id))
    {
        _removeSigningKey(_operator_id, _index);
    }


    function removeSigningKeys(uint256 _operator_id, uint256 _index, uint256 _amount)
        external
        authP(MANAGE_SIGNING_KEYS, arr(_operator_id))
    {


        for (uint256 i = _index + _amount; i > _index ; --i) {
            _removeSigningKey(_operator_id, i - 1);
        }
    }


    function removeSigningKeyOperatorBH(uint256 _operator_id, uint256 _index) external {
        require(msg.sender == operators[_operator_id].rewardAddress, "APP_AUTH_FAILED");
        _removeSigningKey(_operator_id, _index);
    }


    function removeSigningKeysOperatorBH(uint256 _operator_id, uint256 _index, uint256 _amount) external {
        require(msg.sender == operators[_operator_id].rewardAddress, "APP_AUTH_FAILED");


        for (uint256 i = _index + _amount; i > _index ; --i) {
            _removeSigningKey(_operator_id, i - 1);
        }
    }


    function assignNextSigningKeys(uint256 _numKeys) external onlyLido returns (bytes memory pubkeys, bytes memory signatures) {

        DepositLookupCacheEntry[] memory cache = _loadOperatorCache();
        if (0 == cache.length)
            return (new bytes(0), new bytes(0));

        uint256 numAssignedKeys = 0;
        DepositLookupCacheEntry memory entry;

        while (numAssignedKeys < _numKeys) {

            uint256 bestOperatorIdx = cache.length;   
            uint256 smallestStake;

            for (uint256 idx = 0; idx < cache.length; ++idx) {
                entry = cache[idx];

                assert(entry.usedSigningKeys <= entry.totalSigningKeys);
                if (entry.usedSigningKeys == entry.totalSigningKeys)
                    continue;

                uint256 stake = entry.usedSigningKeys.sub(entry.stoppedValidators);
                if (stake + 1 > entry.stakingLimit)
                    continue;

                if (bestOperatorIdx == cache.length || stake < smallestStake) {
                    bestOperatorIdx = idx;
                    smallestStake = stake;
                }
            }

            if (bestOperatorIdx == cache.length)  
                break;

            entry = cache[bestOperatorIdx];
            assert(entry.usedSigningKeys < UINT64_MAX);

            ++entry.usedSigningKeys;
            ++numAssignedKeys;
        }

        if (numAssignedKeys == 0) {
            return (new bytes(0), new bytes(0));
        }

        if (numAssignedKeys > 1) {

            pubkeys = MemUtils.unsafeAllocateBytes(numAssignedKeys * PUBKEY_LENGTH);
            signatures = MemUtils.unsafeAllocateBytes(numAssignedKeys * SIGNATURE_LENGTH);
        }

        uint256 numLoadedKeys = 0;

        for (uint256 i = 0; i < cache.length; ++i) {
            entry = cache[i];

            if (entry.usedSigningKeys == entry.initialUsedSigningKeys) {
                continue;
            }

            operators[entry.id].usedSigningKeys = uint64(entry.usedSigningKeys);

            for (uint256 keyIndex = entry.initialUsedSigningKeys; keyIndex < entry.usedSigningKeys; ++keyIndex) {
                (bytes memory pubkey, bytes memory signature) = _loadSigningKey(entry.id, keyIndex);
                if (numAssignedKeys == 1) {
                    return (pubkey, signature);
                } else {
                    MemUtils.copyBytes(pubkey, pubkeys, numLoadedKeys * PUBKEY_LENGTH);
                    MemUtils.copyBytes(signature, signatures, numLoadedKeys * SIGNATURE_LENGTH);
                    ++numLoadedKeys;
                }
            }

            if (numLoadedKeys == numAssignedKeys) {
                break;
            }
        }

        assert(numLoadedKeys == numAssignedKeys);
        return (pubkeys, signatures);
    }


    function getRewardsDistribution(uint256 _totalRewardShares) external view
        returns (
            address[] memory recipients,
            uint256[] memory shares
        )
    {
        uint256 nodeOperatorCount = getNodeOperatorsCount();

        uint256 activeCount = getActiveNodeOperatorsCount();
        recipients = new address[](activeCount);
        shares = new uint256[](activeCount);
        uint256 idx = 0;

        uint256 effectiveStakeTotal = 0;
        for (uint256 operatorId = 0; operatorId < nodeOperatorCount; ++operatorId) {
            NodeOperator storage operator = operators[operatorId];
            if (!operator.active)
                continue;

            uint256 effectiveStake = operator.usedSigningKeys.sub(operator.stoppedValidators);
            effectiveStakeTotal = effectiveStakeTotal.add(effectiveStake);

            recipients[idx] = operator.rewardAddress;
            shares[idx] = effectiveStake;

            ++idx;
        }

        if (effectiveStakeTotal == 0)
            return (recipients, shares);

        uint256 perValidatorReward = _totalRewardShares.div(effectiveStakeTotal);

        for (idx = 0; idx < activeCount; ++idx) {
            shares[idx] = shares[idx].mul(perValidatorReward);
        }

        return (recipients, shares);
    }


    function getActiveNodeOperatorsCount() public view returns (uint256) {
        return ACTIVE_OPERATORS_COUNT_POSITION.getStorageUint256();
    }


    function getNodeOperator(uint256 _id, bool _fullInfo) external view
        operatorExists(_id)
        returns
        (
            bool active,
            string name,
            address rewardAddress,
            uint64 stakingLimit,
            uint64 stoppedValidators,
            uint64 totalSigningKeys,
            uint64 usedSigningKeys
        )
    {
        NodeOperator storage operator = operators[_id];

        active = operator.active;
        name = _fullInfo ? operator.name : "";    
        rewardAddress = operator.rewardAddress;
        stakingLimit = operator.stakingLimit;
        stoppedValidators = operator.stoppedValidators;
        totalSigningKeys = operator.totalSigningKeys;
        usedSigningKeys = operator.usedSigningKeys;
    }


    function getTotalSigningKeyCount(uint256 _operator_id) external view operatorExists(_operator_id) returns (uint256) {
        return operators[_operator_id].totalSigningKeys;
    }


    function getUnusedSigningKeyCount(uint256 _operator_id) external view operatorExists(_operator_id) returns (uint256) {
        return operators[_operator_id].totalSigningKeys.sub(operators[_operator_id].usedSigningKeys);
    }


    function getSigningKey(uint256 _operator_id, uint256 _index) external view
        operatorExists(_operator_id)
        returns (bytes key, bytes depositSignature, bool used)
    {
        require(_index < operators[_operator_id].totalSigningKeys, "KEY_NOT_FOUND");

        (bytes memory key_, bytes memory signature) = _loadSigningKey(_operator_id, _index);

        return (key_, signature, _index < operators[_operator_id].usedSigningKeys);
    }


    function getNodeOperatorsCount() public view returns (uint256) {
        return TOTAL_OPERATORS_COUNT_POSITION.getStorageUint256();
    }


    function getKeysOpIndex() public view returns (uint256) {
        return KEYS_OP_INDEX_POSITION.getStorageUint256();
    }


    function _isEmptySigningKey(bytes memory _key) internal pure returns (bool) {
        assert(_key.length == PUBKEY_LENGTH);

        assert(PUBKEY_LENGTH >= 32 && PUBKEY_LENGTH <= 64);

        uint256 k1;
        uint256 k2;
        assembly {
            k1 := mload(add(_key, 0x20))
            k2 := mload(add(_key, 0x40))
        }

        return 0 == k1 && 0 == (k2 >> ((2 * 32 - PUBKEY_LENGTH) * 8));
    }

    function to64(uint256 v) internal pure returns (uint64) {
        assert(v <= uint256(uint64(-1)));
        return uint64(v);
    }

    function _signingKeyOffset(uint256 _operator_id, uint256 _keyIndex) internal pure returns (uint256) {
        return uint256(keccak256(abi.encodePacked(SIGNING_KEYS_MAPPING_NAME, _operator_id, _keyIndex)));
    }


    function _storeSigningKey(uint256 _operator_id, uint256 _keyIndex, bytes memory _key, bytes memory _signature) internal {
        assert(_key.length == PUBKEY_LENGTH);
        assert(_signature.length == SIGNATURE_LENGTH);

        assert(PUBKEY_LENGTH >= 32 && PUBKEY_LENGTH <= 64);

        assert(0 == SIGNATURE_LENGTH % 32);


        uint256 offset = _signingKeyOffset(_operator_id, _keyIndex);
        uint256 keyExcessBits = (2 * 32 - PUBKEY_LENGTH) * 8;
        assembly {
            sstore(offset, mload(add(_key, 0x20)))
            sstore(add(offset, 1), shl(keyExcessBits, shr(keyExcessBits, mload(add(_key, 0x40)))))
        }
        offset += 2;


        for (uint256 i = 0; i < SIGNATURE_LENGTH; i += 32) {
            assembly {
                sstore(offset, mload(add(_signature, add(0x20, i))))
            }
            offset++;
        }
    }

    function _addSigningKeys(uint256 _operator_id, uint256 _quantity, bytes _pubkeys, bytes _signatures) internal
        operatorExists(_operator_id)
    {
        require(_quantity != 0, "NO_KEYS");
        require(_pubkeys.length == _quantity.mul(PUBKEY_LENGTH), "INVALID_LENGTH");
        require(_signatures.length == _quantity.mul(SIGNATURE_LENGTH), "INVALID_LENGTH");

        _increaseKeysOpIndex();

        for (uint256 i = 0; i < _quantity; ++i) {
            bytes memory key = BytesLib.slice(_pubkeys, i * PUBKEY_LENGTH, PUBKEY_LENGTH);
            require(!_isEmptySigningKey(key), "EMPTY_KEY");
            bytes memory sig = BytesLib.slice(_signatures, i * SIGNATURE_LENGTH, SIGNATURE_LENGTH);

            _storeSigningKey(_operator_id, operators[_operator_id].totalSigningKeys + i, key, sig);
            emit SigningKeyAdded(_operator_id, key);
        }

        operators[_operator_id].totalSigningKeys = operators[_operator_id].totalSigningKeys.add(to64(_quantity));
    }

    function _removeSigningKey(uint256 _operator_id, uint256 _index) internal
        operatorExists(_operator_id)
    {
        require(_index < operators[_operator_id].totalSigningKeys, "KEY_NOT_FOUND");
        require(_index >= operators[_operator_id].usedSigningKeys, "KEY_WAS_USED");

        _increaseKeysOpIndex();

        (bytes memory removedKey, ) = _loadSigningKey(_operator_id, _index);

        uint256 lastIndex = operators[_operator_id].totalSigningKeys.sub(1);
        if (_index < lastIndex) {
            (bytes memory key, bytes memory signature) = _loadSigningKey(_operator_id, lastIndex);
            _storeSigningKey(_operator_id, _index, key, signature);
        }

        _deleteSigningKey(_operator_id, lastIndex);
        operators[_operator_id].totalSigningKeys = operators[_operator_id].totalSigningKeys.sub(1);

        if (_index < operators[_operator_id].stakingLimit) {

            operators[_operator_id].stakingLimit = uint64(_index);
        }

        emit SigningKeyRemoved(_operator_id, removedKey);
    }

    function _deleteSigningKey(uint256 _operator_id, uint256 _keyIndex) internal {
        uint256 offset = _signingKeyOffset(_operator_id, _keyIndex);

        for (uint256 i = 0; i < (PUBKEY_LENGTH + SIGNATURE_LENGTH) / 32 + 1; ++i) {
            assembly {
                sstore(add(offset, i), 0)
            }
        }
    }


    function _loadSigningKey(uint256 _operator_id, uint256 _keyIndex) internal view returns (bytes memory key, bytes memory signature) {


        assert(PUBKEY_LENGTH >= 32 && PUBKEY_LENGTH <= 64);
        assert(0 == SIGNATURE_LENGTH % 32);

        uint256 offset = _signingKeyOffset(_operator_id, _keyIndex);


        bytes memory tmpKey = new bytes(64);
        assembly {
            mstore(add(tmpKey, 0x20), sload(offset))
            mstore(add(tmpKey, 0x40), sload(add(offset, 1)))
        }
        offset += 2;
        key = BytesLib.slice(tmpKey, 0, PUBKEY_LENGTH);


        signature = new bytes(SIGNATURE_LENGTH);
        for (uint256 i = 0; i < SIGNATURE_LENGTH; i += 32) {
            assembly {
                mstore(add(signature, add(0x20, i)), sload(offset))
            }
            offset++;
        }

        return (key, signature);
    }

    function _loadOperatorCache() internal view returns (DepositLookupCacheEntry[] memory cache) {
        cache = new DepositLookupCacheEntry[](getActiveNodeOperatorsCount());
        if (0 == cache.length)
            return cache;

        uint256 totalOperators = getNodeOperatorsCount();
        uint256 idx = 0;
        for (uint256 operatorId = 0; operatorId < totalOperators; ++operatorId) {
            NodeOperator storage operator = operators[operatorId];

            if (!operator.active)
                continue;

            DepositLookupCacheEntry memory entry = cache[idx++];
            entry.id = operatorId;
            entry.stakingLimit = operator.stakingLimit;
            entry.stoppedValidators = operator.stoppedValidators;
            entry.totalSigningKeys = operator.totalSigningKeys;
            entry.usedSigningKeys = operator.usedSigningKeys;
            entry.initialUsedSigningKeys = entry.usedSigningKeys;
        }
        require(idx == cache.length, "INCOSISTENT_ACTIVE_COUNT");

        return cache;
    }

    function _increaseKeysOpIndex() internal {
        uint256 keysOpIndex = getKeysOpIndex();
        KEYS_OP_INDEX_POSITION.setStorageUint256(keysOpIndex + 1);
        emit KeysOpIndexSet(keysOpIndex + 1);
    }
}

pragma solidity 0.4.24;

import "@aragon/os/contracts/apps/AragonApp.sol";
import "@aragon/os/contracts/common/IsContract.sol";
import "@aragon/os/contracts/lib/math/SafeMath.sol";
import "@aragon/os/contracts/lib/math/SafeMath64.sol";
import "solidity-bytes-utils/contracts/BytesLib.sol";

import "../interfaces/INodeOperatorsRegistry.sol";
import "../lib/MemUtils.sol";



contract NodeOperatorsRegistry is INodeOperatorsRegistry, IsContract, AragonApp {
    using SafeMath for uint256;
    using SafeMath64 for uint64;
    using UnstructuredStorage for bytes32;


    bytes32 constant public MANAGE_SIGNING_KEYS = keccak256("MANAGE_SIGNING_KEYS");
    bytes32 constant public ADD_NODE_OPERATOR_ROLE = keccak256("ADD_NODE_OPERATOR_ROLE");
    bytes32 constant public SET_NODE_OPERATOR_ACTIVE_ROLE = keccak256("SET_NODE_OPERATOR_ACTIVE_ROLE");
    bytes32 constant public SET_NODE_OPERATOR_NAME_ROLE = keccak256("SET_NODE_OPERATOR_NAME_ROLE");
    bytes32 constant public SET_NODE_OPERATOR_ADDRESS_ROLE = keccak256("SET_NODE_OPERATOR_ADDRESS_ROLE");
    bytes32 constant public SET_NODE_OPERATOR_LIMIT_ROLE = keccak256("SET_NODE_OPERATOR_LIMIT_ROLE");
    bytes32 constant public REPORT_STOPPED_VALIDATORS_ROLE = keccak256("REPORT_STOPPED_VALIDATORS_ROLE");

    uint256 constant public PUBKEY_LENGTH = 48;
    uint256 constant public SIGNATURE_LENGTH = 96;

    uint256 internal constant UINT64_MAX = uint256(uint64(-1));

    bytes32 internal constant SIGNING_KEYS_MAPPING_NAME = keccak256("lido.NodeOperatorsRegistry.signingKeysMappingName");



    struct NodeOperator {
        bool active;    
        address rewardAddress;  
        string name;    
        uint64 stakingLimit;    
        uint64 stoppedValidators;   

        uint64 totalSigningKeys;    
        uint64 usedSigningKeys;     
    }


    struct DepositLookupCacheEntry {

        uint256 id;
        uint256 stakingLimit;
        uint256 stoppedValidators;
        uint256 totalSigningKeys;
        uint256 usedSigningKeys;
        uint256 initialUsedSigningKeys;
    }


    mapping(uint256 => NodeOperator) internal operators;


    bytes32 internal constant TOTAL_OPERATORS_COUNT_POSITION = keccak256("lido.NodeOperatorsRegistry.totalOperatorsCount");


    bytes32 internal constant ACTIVE_OPERATORS_COUNT_POSITION = keccak256("lido.NodeOperatorsRegistry.activeOperatorsCount");


    bytes32 internal constant LIDO_POSITION = keccak256("lido.NodeOperatorsRegistry.lido");


    bytes32 internal constant KEYS_OP_INDEX_POSITION = keccak256("lido.NodeOperatorsRegistry.keysOpIndex");


    modifier onlyLido() {
        require(msg.sender == LIDO_POSITION.getStorageAddress(), "APP_AUTH_FAILED");
        _;
    }

    modifier validAddress(address _a) {
        require(_a != address(0), "EMPTY_ADDRESS");
        _;
    }

    modifier operatorExists(uint256 _id) {
        require(_id < getNodeOperatorsCount(), "NODE_OPERATOR_NOT_FOUND");
        _;
    }

    function initialize(address _lido) public onlyInit {
        TOTAL_OPERATORS_COUNT_POSITION.setStorageUint256(0);
        ACTIVE_OPERATORS_COUNT_POSITION.setStorageUint256(0);
        KEYS_OP_INDEX_POSITION.setStorageUint256(0);
        LIDO_POSITION.setStorageAddress(_lido);
        initialized();
    }


    function addNodeOperator(string _name, address _rewardAddress) external
        auth(ADD_NODE_OPERATOR_ROLE)
        validAddress(_rewardAddress)
        returns (uint256 id)
    {
        id = getNodeOperatorsCount();
        TOTAL_OPERATORS_COUNT_POSITION.setStorageUint256(id.add(1));

        NodeOperator storage operator = operators[id];

        uint256 activeOperatorsCount = getActiveNodeOperatorsCount();
        ACTIVE_OPERATORS_COUNT_POSITION.setStorageUint256(activeOperatorsCount.add(1));

        operator.active = true;
        operator.name = _name;
        operator.rewardAddress = _rewardAddress;
        operator.stakingLimit = 0;

        emit NodeOperatorAdded(id, _name, _rewardAddress, 0);

        return id;
    }


    function setNodeOperatorActive(uint256 _id, bool _active) external
        authP(SET_NODE_OPERATOR_ACTIVE_ROLE, arr(_id, _active ? uint256(1) : uint256(0)))
        operatorExists(_id)
    {
        _increaseKeysOpIndex();
        if (operators[_id].active != _active) {
            uint256 activeOperatorsCount = getActiveNodeOperatorsCount();
            if (_active)
                ACTIVE_OPERATORS_COUNT_POSITION.setStorageUint256(activeOperatorsCount.add(1));
            else
                ACTIVE_OPERATORS_COUNT_POSITION.setStorageUint256(activeOperatorsCount.sub(1));
        }

        operators[_id].active = _active;

        emit NodeOperatorActiveSet(_id, _active);
    }


    function setNodeOperatorName(uint256 _id, string _name) external
        authP(SET_NODE_OPERATOR_NAME_ROLE, arr(_id))
        operatorExists(_id)
    {
        operators[_id].name = _name;
        emit NodeOperatorNameSet(_id, _name);
    }


    function setNodeOperatorRewardAddress(uint256 _id, address _rewardAddress) external
        authP(SET_NODE_OPERATOR_ADDRESS_ROLE, arr(_id, uint256(_rewardAddress)))
        operatorExists(_id)
        validAddress(_rewardAddress)
    {
        operators[_id].rewardAddress = _rewardAddress;
        emit NodeOperatorRewardAddressSet(_id, _rewardAddress);
    }


    function setNodeOperatorStakingLimit(uint256 _id, uint64 _stakingLimit) external
        authP(SET_NODE_OPERATOR_LIMIT_ROLE, arr(_id, uint256(_stakingLimit)))
        operatorExists(_id)
    {
        _increaseKeysOpIndex();
        operators[_id].stakingLimit = _stakingLimit;
        emit NodeOperatorStakingLimitSet(_id, _stakingLimit);
    }


    function reportStoppedValidators(uint256 _id, uint64 _stoppedIncrement) external
        authP(REPORT_STOPPED_VALIDATORS_ROLE, arr(_id, uint256(_stoppedIncrement)))
        operatorExists(_id)
    {
        require(0 != _stoppedIncrement, "EMPTY_VALUE");
        operators[_id].stoppedValidators = operators[_id].stoppedValidators.add(_stoppedIncrement);
        require(operators[_id].stoppedValidators <= operators[_id].usedSigningKeys, "STOPPED_MORE_THAN_LAUNCHED");

        emit NodeOperatorTotalStoppedValidatorsReported(_id, operators[_id].stoppedValidators);
    }


    function trimUnusedKeys() external onlyLido {
        uint256 length = getNodeOperatorsCount();

        for (uint256 operatorId = 0; operatorId < length; ++operatorId) {
            uint64 totalSigningKeys = operators[operatorId].totalSigningKeys;
            uint64 usedSigningKeys = operators[operatorId].usedSigningKeys;
            if (totalSigningKeys != usedSigningKeys) { 
                operators[operatorId].totalSigningKeys = usedSigningKeys;  
                emit NodeOperatorTotalKeysTrimmed(operatorId, totalSigningKeys - usedSigningKeys);
            }
        }
    }


    function addSigningKeys(uint256 _operator_id, uint256 _quantity, bytes _pubkeys, bytes _signatures) external
        authP(MANAGE_SIGNING_KEYS, arr(_operator_id))
    {
        _addSigningKeys(_operator_id, _quantity, _pubkeys, _signatures);
    }


    function addSigningKeysOperatorBH(
        uint256 _operator_id,
        uint256 _quantity,
        bytes _pubkeys,
        bytes _signatures
    )
        external
    {
        require(msg.sender == operators[_operator_id].rewardAddress, "APP_AUTH_FAILED");
        _addSigningKeys(_operator_id, _quantity, _pubkeys, _signatures);
    }


    function removeSigningKey(uint256 _operator_id, uint256 _index)
        external
        authP(MANAGE_SIGNING_KEYS, arr(_operator_id))
    {
        _removeSigningKey(_operator_id, _index);
    }


    function removeSigningKeys(uint256 _operator_id, uint256 _index, uint256 _amount)
        external
        authP(MANAGE_SIGNING_KEYS, arr(_operator_id))
    {


        for (uint256 i = _index + _amount; i > _index ; --i) {
            _removeSigningKey(_operator_id, i - 1);
        }
    }


    function removeSigningKeyOperatorBH(uint256 _operator_id, uint256 _index) external {
        require(msg.sender == operators[_operator_id].rewardAddress, "APP_AUTH_FAILED");
        _removeSigningKey(_operator_id, _index);
    }


    function removeSigningKeysOperatorBH(uint256 _operator_id, uint256 _index, uint256 _amount) external {
        require(msg.sender == operators[_operator_id].rewardAddress, "APP_AUTH_FAILED");


        for (uint256 i = _index + _amount; i > _index ; --i) {
            _removeSigningKey(_operator_id, i - 1);
        }
    }


    function assignNextSigningKeys(uint256 _numKeys) external onlyLido returns (bytes memory pubkeys, bytes memory signatures) {

        DepositLookupCacheEntry[] memory cache = _loadOperatorCache();
        if (0 == cache.length)
            return (new bytes(0), new bytes(0));

        uint256 numAssignedKeys = 0;
        DepositLookupCacheEntry memory entry;

        while (numAssignedKeys < _numKeys) {

            uint256 bestOperatorIdx = cache.length;   
            uint256 smallestStake;

            for (uint256 idx = 0; idx < cache.length; ++idx) {
                entry = cache[idx];

                assert(entry.usedSigningKeys <= entry.totalSigningKeys);
                if (entry.usedSigningKeys == entry.totalSigningKeys)
                    continue;

                uint256 stake = entry.usedSigningKeys.sub(entry.stoppedValidators);
                if (stake + 1 > entry.stakingLimit)
                    continue;

                if (bestOperatorIdx == cache.length || stake < smallestStake) {
                    bestOperatorIdx = idx;
                    smallestStake = stake;
                }
            }

            if (bestOperatorIdx == cache.length)  
                break;

            entry = cache[bestOperatorIdx];
            assert(entry.usedSigningKeys < UINT64_MAX);

            ++entry.usedSigningKeys;
            ++numAssignedKeys;
        }

        if (numAssignedKeys == 0) {
            return (new bytes(0), new bytes(0));
        }

        if (numAssignedKeys > 1) {

            pubkeys = MemUtils.unsafeAllocateBytes(numAssignedKeys * PUBKEY_LENGTH);
            signatures = MemUtils.unsafeAllocateBytes(numAssignedKeys * SIGNATURE_LENGTH);
        }

        uint256 numLoadedKeys = 0;

        for (uint256 i = 0; i < cache.length; ++i) {
            entry = cache[i];

            if (entry.usedSigningKeys == entry.initialUsedSigningKeys) {
                continue;
            }

            operators[entry.id].usedSigningKeys = uint64(entry.usedSigningKeys);

            for (uint256 keyIndex = entry.initialUsedSigningKeys; keyIndex < entry.usedSigningKeys; ++keyIndex) {
                (bytes memory pubkey, bytes memory signature) = _loadSigningKey(entry.id, keyIndex);
                if (numAssignedKeys == 1) {
                    return (pubkey, signature);
                } else {
                    MemUtils.copyBytes(pubkey, pubkeys, numLoadedKeys * PUBKEY_LENGTH);
                    MemUtils.copyBytes(signature, signatures, numLoadedKeys * SIGNATURE_LENGTH);
                    ++numLoadedKeys;
                }
            }

            if (numLoadedKeys == numAssignedKeys) {
                break;
            }
        }

        assert(numLoadedKeys == numAssignedKeys);
        return (pubkeys, signatures);
    }


    function getRewardsDistribution(uint256 _totalRewardShares) external view
        returns (
            address[] memory recipients,
            uint256[] memory shares
        )
    {
        uint256 nodeOperatorCount = getNodeOperatorsCount();

        uint256 activeCount = getActiveNodeOperatorsCount();
        recipients = new address[](activeCount);
        shares = new uint256[](activeCount);
        uint256 idx = 0;

        uint256 effectiveStakeTotal = 0;
        for (uint256 operatorId = 0; operatorId < nodeOperatorCount; ++operatorId) {
            NodeOperator storage operator = operators[operatorId];
            if (!operator.active)
                continue;

            uint256 effectiveStake = operator.usedSigningKeys.sub(operator.stoppedValidators);
            effectiveStakeTotal = effectiveStakeTotal.add(effectiveStake);

            recipients[idx] = operator.rewardAddress;
            shares[idx] = effectiveStake;

            ++idx;
        }

        if (effectiveStakeTotal == 0)
            return (recipients, shares);

        uint256 perValidatorReward = _totalRewardShares.div(effectiveStakeTotal);

        for (idx = 0; idx < activeCount; ++idx) {
            shares[idx] = shares[idx].mul(perValidatorReward);
        }

        return (recipients, shares);
    }


    function getActiveNodeOperatorsCount() public view returns (uint256) {
        return ACTIVE_OPERATORS_COUNT_POSITION.getStorageUint256();
    }


    function getNodeOperator(uint256 _id, bool _fullInfo) external view
        operatorExists(_id)
        returns
        (
            bool active,
            string name,
            address rewardAddress,
            uint64 stakingLimit,
            uint64 stoppedValidators,
            uint64 totalSigningKeys,
            uint64 usedSigningKeys
        )
    {
        NodeOperator storage operator = operators[_id];

        active = operator.active;
        name = _fullInfo ? operator.name : "";    
        rewardAddress = operator.rewardAddress;
        stakingLimit = operator.stakingLimit;
        stoppedValidators = operator.stoppedValidators;
        totalSigningKeys = operator.totalSigningKeys;
        usedSigningKeys = operator.usedSigningKeys;
    }


    function getTotalSigningKeyCount(uint256 _operator_id) external view operatorExists(_operator_id) returns (uint256) {
        return operators[_operator_id].totalSigningKeys;
    }


    function getUnusedSigningKeyCount(uint256 _operator_id) external view operatorExists(_operator_id) returns (uint256) {
        return operators[_operator_id].totalSigningKeys.sub(operators[_operator_id].usedSigningKeys);
    }


    function getSigningKey(uint256 _operator_id, uint256 _index) external view
        operatorExists(_operator_id)
        returns (bytes key, bytes depositSignature, bool used)
    {
        require(_index < operators[_operator_id].totalSigningKeys, "KEY_NOT_FOUND");

        (bytes memory key_, bytes memory signature) = _loadSigningKey(_operator_id, _index);

        return (key_, signature, _index < operators[_operator_id].usedSigningKeys);
    }


    function getNodeOperatorsCount() public view returns (uint256) {
        return TOTAL_OPERATORS_COUNT_POSITION.getStorageUint256();
    }


    function getKeysOpIndex() public view returns (uint256) {
        return KEYS_OP_INDEX_POSITION.getStorageUint256();
    }


    function _isEmptySigningKey(bytes memory _key) internal pure returns (bool) {
        assert(_key.length == PUBKEY_LENGTH);

        assert(PUBKEY_LENGTH >= 32 && PUBKEY_LENGTH <= 64);

        uint256 k1;
        uint256 k2;
        assembly {
            k1 := mload(add(_key, 0x20))
            k2 := mload(add(_key, 0x40))
        }

        return 0 == k1 && 0 == (k2 >> ((2 * 32 - PUBKEY_LENGTH) * 8));
    }

    function to64(uint256 v) internal pure returns (uint64) {
        assert(v <= uint256(uint64(-1)));
        return uint64(v);
    }

    function _signingKeyOffset(uint256 _operator_id, uint256 _keyIndex) internal pure returns (uint256) {
        return uint256(keccak256(abi.encodePacked(SIGNING_KEYS_MAPPING_NAME, _operator_id, _keyIndex)));
    }


    function _storeSigningKey(uint256 _operator_id, uint256 _keyIndex, bytes memory _key, bytes memory _signature) internal {
        assert(_key.length == PUBKEY_LENGTH);
        assert(_signature.length == SIGNATURE_LENGTH);

        assert(PUBKEY_LENGTH >= 32 && PUBKEY_LENGTH <= 64);

        assert(0 == SIGNATURE_LENGTH % 32);


        uint256 offset = _signingKeyOffset(_operator_id, _keyIndex);
        uint256 keyExcessBits = (2 * 32 - PUBKEY_LENGTH) * 8;
        assembly {
            sstore(offset, mload(add(_key, 0x20)))
            sstore(add(offset, 1), shl(keyExcessBits, shr(keyExcessBits, mload(add(_key, 0x40)))))
        }
        offset += 2;


        for (uint256 i = 0; i < SIGNATURE_LENGTH; i += 32) {
            assembly {
                sstore(offset, mload(add(_signature, add(0x20, i))))
            }
            offset++;
        }
    }

    function _addSigningKeys(uint256 _operator_id, uint256 _quantity, bytes _pubkeys, bytes _signatures) internal
        operatorExists(_operator_id)
    {
        require(_quantity != 0, "NO_KEYS");
        require(_pubkeys.length == _quantity.mul(PUBKEY_LENGTH), "INVALID_LENGTH");
        require(_signatures.length == _quantity.mul(SIGNATURE_LENGTH), "INVALID_LENGTH");

        _increaseKeysOpIndex();

        for (uint256 i = 0; i < _quantity; ++i) {
            bytes memory key = BytesLib.slice(_pubkeys, i * PUBKEY_LENGTH, PUBKEY_LENGTH);
            require(!_isEmptySigningKey(key), "EMPTY_KEY");
            bytes memory sig = BytesLib.slice(_signatures, i * SIGNATURE_LENGTH, SIGNATURE_LENGTH);

            _storeSigningKey(_operator_id, operators[_operator_id].totalSigningKeys + i, key, sig);
            emit SigningKeyAdded(_operator_id, key);
        }

        operators[_operator_id].totalSigningKeys = operators[_operator_id].totalSigningKeys.add(to64(_quantity));
    }

    function _removeSigningKey(uint256 _operator_id, uint256 _index) internal
        operatorExists(_operator_id)
    {
        require(_index < operators[_operator_id].totalSigningKeys, "KEY_NOT_FOUND");
        require(_index >= operators[_operator_id].usedSigningKeys, "KEY_WAS_USED");

        _increaseKeysOpIndex();

        (bytes memory removedKey, ) = _loadSigningKey(_operator_id, _index);

        uint256 lastIndex = operators[_operator_id].totalSigningKeys.sub(1);
        if (_index < lastIndex) {
            (bytes memory key, bytes memory signature) = _loadSigningKey(_operator_id, lastIndex);
            _storeSigningKey(_operator_id, _index, key, signature);
        }

        _deleteSigningKey(_operator_id, lastIndex);
        operators[_operator_id].totalSigningKeys = operators[_operator_id].totalSigningKeys.sub(1);

        if (_index < operators[_operator_id].stakingLimit) {

            operators[_operator_id].stakingLimit = uint64(_index);
        }

        emit SigningKeyRemoved(_operator_id, removedKey);
    }

    function _deleteSigningKey(uint256 _operator_id, uint256 _keyIndex) internal {
        uint256 offset = _signingKeyOffset(_operator_id, _keyIndex);

        for (uint256 i = 0; i < (PUBKEY_LENGTH + SIGNATURE_LENGTH) / 32 + 1; ++i) {
            assembly {
                sstore(add(offset, i), 0)
            }
        }
    }


    function _loadSigningKey(uint256 _operator_id, uint256 _keyIndex) internal view returns (bytes memory key, bytes memory signature) {


        assert(PUBKEY_LENGTH >= 32 && PUBKEY_LENGTH <= 64);
        assert(0 == SIGNATURE_LENGTH % 32);

        uint256 offset = _signingKeyOffset(_operator_id, _keyIndex);


        bytes memory tmpKey = new bytes(64);
        assembly {
            mstore(add(tmpKey, 0x20), sload(offset))
            mstore(add(tmpKey, 0x40), sload(add(offset, 1)))
        }
        offset += 2;
        key = BytesLib.slice(tmpKey, 0, PUBKEY_LENGTH);


        signature = new bytes(SIGNATURE_LENGTH);
        for (uint256 i = 0; i < SIGNATURE_LENGTH; i += 32) {
            assembly {
                mstore(add(signature, add(0x20, i)), sload(offset))
            }
            offset++;
        }

        return (key, signature);
    }

    function _loadOperatorCache() internal view returns (DepositLookupCacheEntry[] memory cache) {
        cache = new DepositLookupCacheEntry[](getActiveNodeOperatorsCount());
        if (0 == cache.length)
            return cache;

        uint256 totalOperators = getNodeOperatorsCount();
        uint256 idx = 0;
        for (uint256 operatorId = 0; operatorId < totalOperators; ++operatorId) {
            NodeOperator storage operator = operators[operatorId];

            if (!operator.active)
                continue;

            DepositLookupCacheEntry memory entry = cache[idx++];
            entry.id = operatorId;
            entry.stakingLimit = operator.stakingLimit;
            entry.stoppedValidators = operator.stoppedValidators;
            entry.totalSigningKeys = operator.totalSigningKeys;
            entry.usedSigningKeys = operator.usedSigningKeys;
            entry.initialUsedSigningKeys = entry.usedSigningKeys;
        }
        require(idx == cache.length, "INCOSISTENT_ACTIVE_COUNT");

        return cache;
    }

    function _increaseKeysOpIndex() internal {
        uint256 keysOpIndex = getKeysOpIndex();
        KEYS_OP_INDEX_POSITION.setStorageUint256(keysOpIndex + 1);
        emit KeysOpIndexSet(keysOpIndex + 1);
    }
}

pragma solidity ^0.8.0;
pragma abicoder v2;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/utils/math/SafeCast.sol";

import "../interfaces/IOracleMaster.sol";
import "../interfaces/ILido.sol";
import "../interfaces/IRelayEncoder.sol";
import "../interfaces/IXcmTransactor.sol";
import "../interfaces/IController.sol";
import "../interfaces/Types.sol";

import "./utils/LedgerUtils.sol";
import "./utils/ReportUtils.sol";



contract Ledger {
    using LedgerUtils for Types.OracleData;
    using SafeCast for uint256;

    event DownwardComplete(uint128 amount);
    event UpwardComplete(uint128 amount);
    event Rewards(uint128 amount, uint128 balance);
    event Slash(uint128 amount, uint128 balance);


    bytes32 public stashAccount;


    bytes32 public controllerAccount;


    uint128 public totalBalance;


    uint128 public lockedBalance;


    uint128 public activeBalance;


    Types.LedgerStatus public status;


    uint128 public cachedTotalBalance;


    uint128 public transferUpwardBalance;
    uint128 public transferDownwardBalance;



    IERC20 internal vKSM;

    IController internal controller;


    ILido public LIDO;


    uint128 public MIN_NOMINATOR_BALANCE;



    bytes32 internal constant GARANTOR = 0x00;


    modifier onlyLido() {
        require(msg.sender == address(LIDO), "LEDGED: NOT_LIDO");
        _;
    }

    modifier onlyOracle() {
        address oracle = IOracleMaster(ILido(LIDO).ORACLE_MASTER()).getOracle(address(this));
        require(msg.sender == oracle, "LEDGED: NOT_ORACLE");
        _;
    }


    function initialize(
        bytes32 _stashAccount,
        bytes32 _controllerAccount,
        address _vKSM,
        address _controller,
        uint128 _minNominatorBalance
    ) external {
        require(address(vKSM) == address(0), "LEDGED: ALREADY_INITIALIZED");


        stashAccount = _stashAccount;

        controllerAccount = _controllerAccount;

        status = Types.LedgerStatus.None;

        LIDO = ILido(msg.sender);

        vKSM = IERC20(_vKSM);

        controller = IController(_controller);

        MIN_NOMINATOR_BALANCE = _minNominatorBalance;


    }


    function setMinNominatorBalance(uint128 _minNominatorBalance) external onlyLido {
        MIN_NOMINATOR_BALANCE = _minNominatorBalance;
    }

    function refreshAllowances() external {
        vKSM.approve(address(controller), type(uint256).max);
    }


    function ledgerStake() public view returns (uint256) {
        return LIDO.ledgerStake(address(this));
    }


    function isEmpty() external view returns (bool) {
        return totalBalance == 0 && transferUpwardBalance == 0 && transferDownwardBalance == 0;
    }


    function nominate(bytes32[] calldata _validators) external onlyLido {
        require(activeBalance >= MIN_NOMINATOR_BALANCE, "LEDGED: NOT_ENOUGH_STAKE");
        controller.nominate(_validators);
    }


    function pushData(uint64 _eraId, Types.OracleData memory _report) external onlyOracle {
        require(stashAccount == _report.stashAccount, "LEDGED: STASH_ACCOUNT_MISMATCH");

        status = _report.stakeStatus;
        activeBalance = _report.activeBalance;

        (uint128 unlockingBalance, uint128 withdrawableBalance) = _report.getTotalUnlocking(_eraId);
        uint128 nonWithdrawableBalance = unlockingBalance - withdrawableBalance;

        if (!_processRelayTransfers(_report)) {
            return;
        }
        uint128 _cachedTotalBalance = cachedTotalBalance;
        if (_cachedTotalBalance < _report.stashBalance) { 
            uint128 reward = _report.stashBalance - _cachedTotalBalance;
            LIDO.distributeRewards(reward, _report.stashBalance);

            emit Rewards(reward, _report.stashBalance);
        }
        else if (_cachedTotalBalance > _report.stashBalance) {
            uint128 slash = _cachedTotalBalance - _report.stashBalance;
            LIDO.distributeLosses(slash, _report.stashBalance);

            emit Slash(slash, _report.stashBalance);
        }

        uint128 _ledgerStake = ledgerStake().toUint128();


        if (_report.stashBalance <= _ledgerStake) {





            uint128 deficit = _ledgerStake - _report.stashBalance;


            if (deficit > 0) {
                uint128 lidoBalance = uint128(LIDO.avaliableForStake());
                uint128 forTransfer = lidoBalance > deficit ? deficit : lidoBalance;

                if (forTransfer > 0) {
                    vKSM.transferFrom(address(LIDO), address(this), forTransfer);
                    controller.transferToRelaychain(forTransfer);
                    transferUpwardBalance += forTransfer;
                }
            }


            if (unlockingBalance > 0) {
                controller.rebond(unlockingBalance);
            }

            uint128 relayFreeBalance = _report.getFreeBalance();

            if (relayFreeBalance > 0 &&
                (_report.stakeStatus == Types.LedgerStatus.Nominator || _report.stakeStatus == Types.LedgerStatus.Idle)) {
                controller.bondExtra(relayFreeBalance);
            } else if (_report.stakeStatus == Types.LedgerStatus.None && relayFreeBalance >= MIN_NOMINATOR_BALANCE) {
                controller.bond(controllerAccount, relayFreeBalance);
            }

        }
        else if (_report.stashBalance > _ledgerStake) { 






            if (_ledgerStake < MIN_NOMINATOR_BALANCE && status != Types.LedgerStatus.Idle) {
                controller.chill();
            }

            uint128 deficit = _report.stashBalance - _ledgerStake;
            uint128 relayFreeBalance = _report.getFreeBalance();


            if (relayFreeBalance > 0) {
                uint128 forTransfer = relayFreeBalance > deficit ? deficit : relayFreeBalance;
                controller.transferToParachain(forTransfer);
                transferDownwardBalance += forTransfer;
                deficit -= forTransfer;
                relayFreeBalance -= forTransfer;
            }


            if (deficit > 0 && withdrawableBalance > 0) {
                controller.withdrawUnbonded();
                deficit -= withdrawableBalance > deficit ? deficit : withdrawableBalance;
            }


            if (nonWithdrawableBalance < deficit) {

                uint128 forUnbond = deficit - nonWithdrawableBalance;
                controller.unbond(forUnbond);


            }


            if (relayFreeBalance > 0) {
                controller.bondExtra(relayFreeBalance);
            }
        }

        cachedTotalBalance = _report.stashBalance;
    }

    function _processRelayTransfers(Types.OracleData memory _report) internal returns(bool) {

        uint128 _transferDownwardBalance = transferDownwardBalance;
        if (_transferDownwardBalance > 0) {
            uint128 totalDownwardTransferred = uint128(vKSM.balanceOf(address(this)));

            if (totalDownwardTransferred >= _transferDownwardBalance ) {

                vKSM.transfer(address(LIDO), _transferDownwardBalance);


                cachedTotalBalance -= _transferDownwardBalance;
                transferDownwardBalance = 0;

                emit DownwardComplete(_transferDownwardBalance);
                _transferDownwardBalance = 0;
            }
        }


        uint128 _transferUpwardBalance = transferUpwardBalance;
        if (_transferUpwardBalance > 0) {
            uint128 ledgerFreeBalance = (totalBalance - lockedBalance);

            uint128 freeBalanceIncrement = _report.getFreeBalance() - ledgerFreeBalance;

            if (freeBalanceIncrement >= _transferUpwardBalance) {
                cachedTotalBalance += _transferUpwardBalance;

                transferUpwardBalance = 0;
                emit UpwardComplete(_transferUpwardBalance);
                _transferUpwardBalance = 0;
            }
        }

        if (_transferDownwardBalance == 0 && _transferUpwardBalance == 0) {

            totalBalance = _report.stashBalance;
            lockedBalance = _report.totalBalance;
            return true;
        }

        return false;
    }
}

pragma solidity ^0.8.0;
pragma abicoder v2;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/utils/math/SafeCast.sol";
import "@openzeppelin/contracts/proxy/Clones.sol";
import "@openzeppelin/contracts/proxy/utils/Initializable.sol";

import "../interfaces/IOracleMaster.sol";
import "../interfaces/ILedger.sol";
import "../interfaces/IController.sol";
import "../interfaces/IAuthManager.sol";

import "./stKSM.sol";


contract Lido is stKSM, Initializable {
    using Clones for address;
    using SafeCast for uint256;


    event Deposited(address indexed sender, uint256 amount);


    event Redeemed(address indexed receiver, uint256 amount);


    event Claimed(address indexed receiver, uint256 amount);


    event FeeSet(uint16 fee, uint16 feeOperatorsBP, uint16 feeTreasuryBP,  uint16 feeDevelopersBP);


    event Rewards(address ledger, uint256 rewards, uint256 balance);


    event Losses(address ledger, uint256 losses, uint256 balance);


    event LedgerAdd(
        address addr,
        bytes32 stashAccount,
        bytes32 controllerAccount,
        uint256 share
    );


    event LedgerRemove(
        address addr
    );


    event LedgerSetShare(
        address addr,
        uint256 share
    );


    uint256 private fundRaisedBalance;

    struct Claim {
        uint256 balance;
        uint64 timeout;
    }

    mapping(address => Claim[]) public claimOrders;


    uint256 public pendingClaimsTotal;


    address[] private ledgers;


    mapping(bytes32 => address) private ledgerByStash;


    mapping(address => uint256) private ledgerByAddress;


    mapping(address => uint256) public ledgerShares;


    uint256 public ledgerSharesTotal;


    uint256 public bufferedDeposits;


    uint256 public bufferedRedeems;


    mapping(address => uint256) public ledgerStake;



    IERC20 public vKSM;

    address public controller;



    address public AUTH_MANAGER;


    uint256 public MAX_LEDGERS_AMOUNT;


    bytes32 public GARANTOR;


    Types.Fee private FEE;


    address public LEDGER_CLONE;


    address public ORACLE_MASTER;


    Types.RelaySpec public RELAY_SPEC;


    address public developers;


    address public treasury;


    uint16 internal constant DEFAULT_DEVELOPERS_FEE = 140;
    uint16 internal constant DEFAULT_OPERATORS_FEE = 300;
    uint16 internal constant DEFAULT_TREASURY_FEE = 560;


    uint256 internal constant MEMBER_NOT_FOUND = type(uint256).max;


    bytes32 internal constant ROLE_SPEC_MANAGER = keccak256("ROLE_SPEC_MANAGER");


    bytes32 internal constant ROLE_PAUSE_MANAGER = keccak256("ROLE_PAUSE_MANAGER");


    bytes32 internal constant ROLE_FEE_MANAGER = keccak256("ROLE_FEE_MANAGER");


    bytes32 internal constant ROLE_ORACLE_MANAGER = keccak256("ROLE_ORACLE_MANAGER");


    bytes32 internal constant ROLE_LEDGER_MANAGER = keccak256("ROLE_LEDGER_MANAGER");


    bytes32 internal constant ROLE_STAKE_MANAGER = keccak256("ROLE_STAKE_MANAGER");


    bytes32 internal constant ROLE_TREASURY = keccak256("ROLE_SET_TREASURY");


    bytes32 internal constant ROLE_DEVELOPERS = keccak256("ROLE_SET_DEVELOPERS");


    uint16 internal constant MAX_CLAIMS = 10;


    modifier auth(bytes32 role) {
        require(IAuthManager(AUTH_MANAGER).has(role, msg.sender), "LIDO: UNAUTHORIZED");
        _;
    }


    function initialize(
        address _authManager,
        address _vKSM,
        address _controller,
        address _developers,
        address _treasury
    ) external initializer {
        vKSM = IERC20(_vKSM);
        controller = _controller;
        AUTH_MANAGER = _authManager;

        MAX_LEDGERS_AMOUNT = 200;
        Types.Fee memory _fee;
        _fee.total = DEFAULT_OPERATORS_FEE + DEFAULT_DEVELOPERS_FEE + DEFAULT_TREASURY_FEE;
        _fee.operators = DEFAULT_OPERATORS_FEE;
        _fee.developers = DEFAULT_DEVELOPERS_FEE;
        _fee.treasury = DEFAULT_TREASURY_FEE;
        FEE = _fee;

        GARANTOR = 0x00;

        treasury = _treasury;
        developers =_developers;
    }


    fallback() external {
        revert("FORBIDDEN");
    }


    function setTreasury(address _treasury) external auth(ROLE_TREASURY) {
        treasury = _treasury;
    }


    function setDevelopers(address _developers) external auth(ROLE_DEVELOPERS) {
        developers = _developers;
    }


    function getUnbonded(address _holder) external view returns (uint256 waiting, uint256 unbonded) {
        uint256 waitingToUnbonding = 0;
        uint256 readyToClaim = 0;
        Claim[] storage orders = claimOrders[_holder];

        for (uint256 i = 0; i < orders.length; ++i) {
            if (orders[i].timeout < block.timestamp) {
                readyToClaim += orders[i].balance;
            }
            else {
                waitingToUnbonding += orders[i].balance;
            }
        }
        return (waitingToUnbonding, readyToClaim);
    }


    function getStashAccounts() public view returns (bytes32[] memory) {
        bytes32[] memory _stashes = new bytes32[](ledgers.length);

        for (uint i = 0; i < ledgers.length; i++) {
            _stashes[i] = bytes32(ILedger(ledgers[i]).stashAccount());
        }
        return _stashes;
    }


    function getLedgerAddresses() public view returns (address[] memory) {
        return ledgers;
    }


    function findLedger(bytes32 _stashAccount) external view returns (address) {
        return ledgerByStash[_stashAccount];
    }


    function avaliableForStake() external view returns(uint256) {
        uint256 freeBalance = vKSM.balanceOf(address(this));
        return freeBalance < pendingClaimsTotal ? 0 : freeBalance - pendingClaimsTotal;
    }


    function setRelaySpec(Types.RelaySpec calldata _relaySpec) external auth(ROLE_SPEC_MANAGER) {
        require(ORACLE_MASTER != address(0), "LIDO: ORACLE_MASTER_UNDEFINED");
        require(_relaySpec.genesisTimestamp > 0, "LIDO: BAD_GENESIS_TIMESTAMP");
        require(_relaySpec.secondsPerEra > 0, "LIDO: BAD_SECONDS_PER_ERA");
        require(_relaySpec.unbondingPeriod > 0, "LIDO: BAD_UNBONDING_PERIOD");
        require(_relaySpec.maxValidatorsPerLedger > 0, "LIDO: BAD_MAX_VALIDATORS_PER_LEDGER");



        RELAY_SPEC = _relaySpec;

        IOracleMaster(ORACLE_MASTER).setRelayParams(_relaySpec.genesisTimestamp, _relaySpec.secondsPerEra);
    }


    function setOracleMaster(address _oracleMaster) external auth(ROLE_ORACLE_MANAGER) {
        require(ORACLE_MASTER == address(0), "LIDO: ORACLE_MASTER_ALREADY_DEFINED");
        ORACLE_MASTER = _oracleMaster;
        IOracleMaster(ORACLE_MASTER).setLido(address(this));
    }


    function setLedgerClone(address _ledgerClone) external auth(ROLE_LEDGER_MANAGER) {
        LEDGER_CLONE = _ledgerClone;
    }


    function setFee(uint16 _feeOperators, uint16 _feeTreasury,  uint16 _feeDevelopers) external auth(ROLE_FEE_MANAGER) {
        Types.Fee memory _fee;
        _fee.total = _feeTreasury + _feeOperators + _feeDevelopers;
        require(_fee.total <= 10000 && (_feeTreasury > 0 || _feeDevelopers > 0) , "LIDO: FEE_DONT_ADD_UP");

        emit FeeSet(_fee.total, _feeOperators, _feeTreasury, _feeDevelopers);

        _fee.developers = _feeDevelopers;
        _fee.operators = _feeOperators;
        _fee.treasury = _feeTreasury;
        FEE = _fee;
    }


    function getFee() external view returns (uint16){
        return FEE.total;
    }


    function getOperatorsFee() external view returns (uint16){
        return FEE.operators;
    }


    function getTreasuryFee() external view returns (uint16){
       return FEE.treasury;
    }


    function getDevelopersFee() external view returns (uint16){
        return FEE.developers;
    }


    function pause() external auth(ROLE_PAUSE_MANAGER) {
        _pause();
    }


    function resume() external auth(ROLE_PAUSE_MANAGER) {
        _unpause();
    }


    function addLedger(
        bytes32 _stashAccount,
        bytes32 _controllerAccount,
        uint16 _index,
        uint256 _share
    )
        external
        auth(ROLE_LEDGER_MANAGER)
        returns(address)
    {
        require(LEDGER_CLONE != address(0), "LIDO: UNSPECIFIED_LEDGER_CLONE");
        require(ORACLE_MASTER != address(0), "LIDO: NO_ORACLE_MASTER");
        require(ledgers.length < MAX_LEDGERS_AMOUNT, "LIDO: LEDGERS_POOL_LIMIT");
        require(ledgerByStash[_stashAccount] == address(0), "LIDO: STASH_ALREADY_EXISTS");

        address ledger = LEDGER_CLONE.cloneDeterministic(_stashAccount);

        ILedger(ledger).initialize(
            _stashAccount,
            _controllerAccount,
            address(vKSM),
            controller,
            RELAY_SPEC.minNominatorBalance
        );
        ledgers.push(ledger);
        ledgerByStash[_stashAccount] = ledger;
        ledgerByAddress[ledger] = ledgers.length;
        ledgerShares[ledger] = _share;
        ledgerSharesTotal += _share;

        IOracleMaster(ORACLE_MASTER).addLedger(ledger);



        IController(controller).newSubAccount(_index, _stashAccount, ledger);

        emit LedgerAdd(ledger, _stashAccount, _controllerAccount, _share);
        return ledger;
    }


    function setLedgerShare(address _ledger, uint256 _newShare) external auth(ROLE_LEDGER_MANAGER) {
        require(ledgerByAddress[_ledger] != 0, "LIDO: LEDGER_NOT_FOUND");

        ledgerSharesTotal -= ledgerShares[_ledger];
        ledgerShares[_ledger] = _newShare;
        ledgerSharesTotal += _newShare;

        emit LedgerSetShare(_ledger, _newShare);
    }


    function removeLedger(address _ledgerAddress) external auth(ROLE_LEDGER_MANAGER) {
        require(ledgerByAddress[_ledgerAddress] != 0, "LIDO: LEDGER_NOT_FOUND");
        require(ledgerShares[_ledgerAddress] == 0, "LIDO: LEDGER_HAS_NON_ZERO_SHARE");

        ILedger ledger = ILedger(_ledgerAddress);
        require(ledger.isEmpty(), "LIDO: LEDGER_IS_NOT_EMPTY");

        address lastLedger = ledgers[ledgers.length - 1];
        uint256 idxToRemove = ledgerByAddress[_ledgerAddress] - 1;
        ledgers[idxToRemove] = lastLedger; 
        ledgerByAddress[lastLedger] = idxToRemove + 1; 
        ledgers.pop();
        delete ledgerByAddress[_ledgerAddress];
        delete ledgerByStash[ledger.stashAccount()];
        delete ledgerShares[_ledgerAddress];

        IOracleMaster(ORACLE_MASTER).removeLedger(_ledgerAddress);

        vKSM.approve(address(ledger), 0);

        emit LedgerRemove(_ledgerAddress);
    }


    function nominate(bytes32 _stashAccount, bytes32[] calldata _validators) external auth(ROLE_STAKE_MANAGER) {
        require(ledgerByStash[_stashAccount] != address(0),  "UNKNOWN_STASH_ACCOUNT");

        ILedger(ledgerByStash[_stashAccount]).nominate(_validators);
    }


    function deposit(uint256 _amount) external whenNotPaused {
        vKSM.transferFrom(msg.sender, address(this), _amount);

        _submit(_amount);

        emit Deposited(msg.sender, _amount);
    }


    function redeem(uint256 _amount) external whenNotPaused {
        uint256 _shares = getSharesByPooledKSM(_amount);
        require(_shares <= _sharesOf(msg.sender), "LIDO: REDEEM_AMOUNT_EXCEEDS_BALANCE");
        require(claimOrders[msg.sender].length < MAX_CLAIMS, "LIDO: MAX_CLAIMS_EXCEEDS");

        _burnShares(msg.sender, _shares);
        fundRaisedBalance -= _amount;
        bufferedRedeems += _amount;

        Claim memory newClaim = Claim(_amount, uint64(block.timestamp) + RELAY_SPEC.unbondingPeriod);
        claimOrders[msg.sender].push(newClaim);
        pendingClaimsTotal += _amount;


        emit Transfer(msg.sender, address(0), _amount);


        emit Redeemed(msg.sender, _amount);
    }


    function claimUnbonded() external whenNotPaused {
        uint256 readyToClaim = 0;
        uint256 readyToClaimCount = 0;
        Claim[] storage orders = claimOrders[msg.sender];

        for (uint256 i = 0; i < orders.length; ++i) {
            if (orders[i].timeout < block.timestamp) {
                readyToClaim += orders[i].balance;
                readyToClaimCount += 1;
            }
            else {
                orders[i - readyToClaimCount] = orders[i];
            }
        }


        for (uint256 i = 0; i < readyToClaimCount; ++i) { orders.pop(); }

        if (readyToClaim > 0) {
            vKSM.transfer(msg.sender, readyToClaim);
            pendingClaimsTotal -= readyToClaim;
            emit Claimed(msg.sender, readyToClaim);
        }
    }


    function distributeRewards(uint256 _totalRewards, uint256 ledgerBalance) external {
        require(ledgerByAddress[msg.sender] != 0, "LIDO: NOT_FROM_LEDGER");

        Types.Fee memory _fee = FEE;


        uint256 _feeDevTreasure = uint256(_fee.developers + _fee.treasury);
        assert(_feeDevTreasure>0);

        fundRaisedBalance += _totalRewards;

        if (ledgerShares[msg.sender] > 0) {
            ledgerStake[msg.sender] += _totalRewards;
        }

        uint256 _rewards = _totalRewards * _feeDevTreasure / uint256(10000 - _fee.operators);
        uint256 shares2mint = _rewards * _getTotalShares() / (_getTotalPooledKSM()  - _rewards);

        _mintShares(treasury, shares2mint);

        uint256 _devShares = shares2mint *  uint256(_fee.developers) / _feeDevTreasure;
        _transferShares(treasury, developers, _devShares);
        _emitTransferAfterMintingShares(developers, _devShares);
        _emitTransferAfterMintingShares(treasury, shares2mint - _devShares);

        emit Rewards(msg.sender, _totalRewards, ledgerBalance);
    }


    function distributeLosses(uint256 _totalLosses, uint256 ledgerBalance) external {
        require(ledgerByAddress[msg.sender] != 0, "LIDO: NOT_FROM_LEDGER");

        fundRaisedBalance -= _totalLosses;
        if (ledgerShares[msg.sender] > 0) {

            ledgerStake[msg.sender] -= _totalLosses;
        }

        emit Losses(msg.sender, _totalLosses, ledgerBalance);
    }


    function flushStakes() external {
        require(msg.sender == ORACLE_MASTER, "LIDO: NOT_FROM_ORACLE_MASTER");

        _softRebalanceStakes();
    }


    function forceRebalanceStake() external auth(ROLE_STAKE_MANAGER) {
        _forceRebalanceStakes();

        bufferedDeposits = 0;
        bufferedRedeems = 0;
    }


    function refreshAllowances() external auth(ROLE_LEDGER_MANAGER) {
        uint _length = ledgers.length;
        for (uint i = 0; i < _length; i++) {
            vKSM.approve(ledgers[i], type(uint256).max);
        }
    }


    function _forceRebalanceStakes() internal {
        uint256 totalStake = getTotalPooledKSM();

        uint256 stakesSum = 0;
        address nonZeroLedged = address(0);
        uint _length = ledgers.length;
        uint256 _ledgerSharesTotal = ledgerSharesTotal;
        for (uint i = 0; i < _length; i++) {
            uint256 share = ledgerShares[ledgers[i]];
            uint256 stake = totalStake * share / _ledgerSharesTotal;

            stakesSum += stake;
            ledgerStake[ledgers[i]] = stake;

            if (share > 0 && nonZeroLedged == address(0)) {
                nonZeroLedged = ledgers[i];
            }
        }



        uint256 remainingDust = totalStake - stakesSum;
        if (remainingDust > 0 && nonZeroLedged != address(0)) {
            ledgerStake[nonZeroLedged] += remainingDust;
        }
    }


    function _softRebalanceStakes() internal {
        if (bufferedDeposits > 0 || bufferedRedeems > 0) {
            _distribute(bufferedDeposits.toInt256() - bufferedRedeems.toInt256());

            bufferedDeposits = 0;
            bufferedRedeems = 0;
        }
    }

    function _distribute(int256 _stake) internal {
        uint256 ledgersLength = ledgers.length;

        int256[] memory diffs = new int256[](ledgersLength);
        address[] memory ledgersCache = new address[](ledgersLength);
        int256[] memory ledgerStakesCache = new int256[](ledgersLength);
        uint256[] memory ledgerSharesCache = new uint256[](ledgersLength);

        int256 activeDiffsSum = 0;
        int256 totalChange = 0;

        {
            uint256 totalStake = getTotalPooledKSM();
            uint256 _ledgerSharesTotal = ledgerSharesTotal;
            int256 diff = 0;
            for (uint256 i = 0; i < ledgersLength; ++i) {
                ledgersCache[i] = ledgers[i];
                ledgerStakesCache[i] = int256(ledgerStake[ledgersCache[i]]);
                ledgerSharesCache[i] = ledgerShares[ledgersCache[i]];

                uint256 targetStake = totalStake * ledgerSharesCache[i] / _ledgerSharesTotal;
                diff = int256(targetStake) - int256(ledgerStakesCache[i]);
                if (_stake * diff > 0) {
                    activeDiffsSum += diff;
                }
                diffs[i] = diff;
            }
        }


        if (activeDiffsSum != 0) {
            int8 direction = 1;
            if (activeDiffsSum < 0) {
                direction = -1;
                activeDiffsSum = -activeDiffsSum;
            }

            for (uint256 i = 0; i < ledgersLength; ++i) {
                diffs[i] *= direction;
                if (diffs[i] > 0 && (direction < 0 || ledgerSharesCache[i] > 0)) {
                    int256 change = diffs[i] * _stake / activeDiffsSum;
                    int256 newStake = ledgerStakesCache[i] + change;

                    ledgerStake[ledgersCache[i]] = uint256(newStake);
                    ledgerStakesCache[i] = newStake;
                    totalChange += change;
                }
            }
        }

        {
            int256 remaining = _stake - totalChange;
            if (remaining > 0) {
                for (uint256 i = 0; i < ledgersLength; ++i) {
                    if (ledgerSharesCache[i] > 0) {
                        ledgerStake[ledgersCache[i]] += uint256(remaining);
                        break;
                    }
                }
            }
            else if (remaining < 0) {
                for (uint256 i = 0; i < ledgersLength || remaining < 0; ++i) {
                    uint256 stake = uint256(ledgerStakesCache[i]);
                    if (stake > 0) {
                        uint256 decrement = stake > uint256(-remaining) ? uint256(-remaining) : stake;
                        ledgerStake[ledgersCache[i]] -= decrement;
                        remaining += int256(decrement);
                    }
                }
            }
        }
    }


    function _submit(uint256 _deposit) internal returns (uint256) {
        address sender = msg.sender;

        require(_deposit != 0, "LIDO: ZERO_DEPOSIT");

        uint256 sharesAmount = getSharesByPooledKSM(_deposit);
        if (sharesAmount == 0) {


            sharesAmount = _deposit;
        }

        fundRaisedBalance += _deposit;
        bufferedDeposits += _deposit;
        _mintShares(sender, sharesAmount);

        _emitTransferAfterMintingShares(sender, sharesAmount);
        return sharesAmount;
    }



    function _emitTransferAfterMintingShares(address _to, uint256 _sharesAmount) internal {
        emit Transfer(address(0), _to, getPooledKSMByShares(_sharesAmount));
    }


    function _getTotalPooledKSM() internal view override returns (uint256) {
        return fundRaisedBalance;
    }
}

pragma solidity ^0.8.0;
pragma abicoder v2;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/utils/math/SafeCast.sol";
import "@openzeppelin/contracts/proxy/Clones.sol";
import "@openzeppelin/contracts/proxy/utils/Initializable.sol";

import "../interfaces/IOracleMaster.sol";
import "../interfaces/ILedger.sol";
import "../interfaces/IController.sol";
import "../interfaces/IAuthManager.sol";

import "./stKSM.sol";


contract Lido is stKSM, Initializable {
    using Clones for address;
    using SafeCast for uint256;


    event Deposited(address indexed sender, uint256 amount);


    event Redeemed(address indexed receiver, uint256 amount);


    event Claimed(address indexed receiver, uint256 amount);


    event FeeSet(uint16 fee, uint16 feeOperatorsBP, uint16 feeTreasuryBP,  uint16 feeDevelopersBP);


    event Rewards(address ledger, uint256 rewards, uint256 balance);


    event Losses(address ledger, uint256 losses, uint256 balance);


    event LedgerAdd(
        address addr,
        bytes32 stashAccount,
        bytes32 controllerAccount,
        uint256 share
    );


    event LedgerRemove(
        address addr
    );


    event LedgerSetShare(
        address addr,
        uint256 share
    );


    uint256 private fundRaisedBalance;

    struct Claim {
        uint256 balance;
        uint64 timeout;
    }

    mapping(address => Claim[]) public claimOrders;


    uint256 public pendingClaimsTotal;


    address[] private ledgers;


    mapping(bytes32 => address) private ledgerByStash;


    mapping(address => uint256) private ledgerByAddress;


    mapping(address => uint256) public ledgerShares;


    uint256 public ledgerSharesTotal;


    uint256 public bufferedDeposits;


    uint256 public bufferedRedeems;


    mapping(address => uint256) public ledgerStake;



    IERC20 public vKSM;

    address public controller;



    address public AUTH_MANAGER;


    uint256 public MAX_LEDGERS_AMOUNT;


    bytes32 public GARANTOR;


    Types.Fee private FEE;


    address public LEDGER_CLONE;


    address public ORACLE_MASTER;


    Types.RelaySpec public RELAY_SPEC;


    address public developers;


    address public treasury;


    uint16 internal constant DEFAULT_DEVELOPERS_FEE = 140;
    uint16 internal constant DEFAULT_OPERATORS_FEE = 300;
    uint16 internal constant DEFAULT_TREASURY_FEE = 560;


    uint256 internal constant MEMBER_NOT_FOUND = type(uint256).max;


    bytes32 internal constant ROLE_SPEC_MANAGER = keccak256("ROLE_SPEC_MANAGER");


    bytes32 internal constant ROLE_PAUSE_MANAGER = keccak256("ROLE_PAUSE_MANAGER");


    bytes32 internal constant ROLE_FEE_MANAGER = keccak256("ROLE_FEE_MANAGER");


    bytes32 internal constant ROLE_ORACLE_MANAGER = keccak256("ROLE_ORACLE_MANAGER");


    bytes32 internal constant ROLE_LEDGER_MANAGER = keccak256("ROLE_LEDGER_MANAGER");


    bytes32 internal constant ROLE_STAKE_MANAGER = keccak256("ROLE_STAKE_MANAGER");


    bytes32 internal constant ROLE_TREASURY = keccak256("ROLE_SET_TREASURY");


    bytes32 internal constant ROLE_DEVELOPERS = keccak256("ROLE_SET_DEVELOPERS");


    uint16 internal constant MAX_CLAIMS = 10;


    modifier auth(bytes32 role) {
        require(IAuthManager(AUTH_MANAGER).has(role, msg.sender), "LIDO: UNAUTHORIZED");
        _;
    }


    function initialize(
        address _authManager,
        address _vKSM,
        address _controller,
        address _developers,
        address _treasury
    ) external initializer {
        vKSM = IERC20(_vKSM);
        controller = _controller;
        AUTH_MANAGER = _authManager;

        MAX_LEDGERS_AMOUNT = 200;
        Types.Fee memory _fee;
        _fee.total = DEFAULT_OPERATORS_FEE + DEFAULT_DEVELOPERS_FEE + DEFAULT_TREASURY_FEE;
        _fee.operators = DEFAULT_OPERATORS_FEE;
        _fee.developers = DEFAULT_DEVELOPERS_FEE;
        _fee.treasury = DEFAULT_TREASURY_FEE;
        FEE = _fee;

        GARANTOR = 0x00;

        treasury = _treasury;
        developers =_developers;
    }


    fallback() external {
        revert("FORBIDDEN");
    }


    function setTreasury(address _treasury) external auth(ROLE_TREASURY) {
        treasury = _treasury;
    }


    function setDevelopers(address _developers) external auth(ROLE_DEVELOPERS) {
        developers = _developers;
    }


    function getUnbonded(address _holder) external view returns (uint256 waiting, uint256 unbonded) {
        uint256 waitingToUnbonding = 0;
        uint256 readyToClaim = 0;
        Claim[] storage orders = claimOrders[_holder];

        for (uint256 i = 0; i < orders.length; ++i) {
            if (orders[i].timeout < block.timestamp) {
                readyToClaim += orders[i].balance;
            }
            else {
                waitingToUnbonding += orders[i].balance;
            }
        }
        return (waitingToUnbonding, readyToClaim);
    }


    function getStashAccounts() public view returns (bytes32[] memory) {
        bytes32[] memory _stashes = new bytes32[](ledgers.length);

        for (uint i = 0; i < ledgers.length; i++) {
            _stashes[i] = bytes32(ILedger(ledgers[i]).stashAccount());
        }
        return _stashes;
    }


    function getLedgerAddresses() public view returns (address[] memory) {
        return ledgers;
    }


    function findLedger(bytes32 _stashAccount) external view returns (address) {
        return ledgerByStash[_stashAccount];
    }


    function avaliableForStake() external view returns(uint256) {
        uint256 freeBalance = vKSM.balanceOf(address(this));
        return freeBalance < pendingClaimsTotal ? 0 : freeBalance - pendingClaimsTotal;
    }


    function setRelaySpec(Types.RelaySpec calldata _relaySpec) external auth(ROLE_SPEC_MANAGER) {
        require(ORACLE_MASTER != address(0), "LIDO: ORACLE_MASTER_UNDEFINED");
        require(_relaySpec.genesisTimestamp > 0, "LIDO: BAD_GENESIS_TIMESTAMP");
        require(_relaySpec.secondsPerEra > 0, "LIDO: BAD_SECONDS_PER_ERA");
        require(_relaySpec.unbondingPeriod > 0, "LIDO: BAD_UNBONDING_PERIOD");
        require(_relaySpec.maxValidatorsPerLedger > 0, "LIDO: BAD_MAX_VALIDATORS_PER_LEDGER");



        RELAY_SPEC = _relaySpec;

        IOracleMaster(ORACLE_MASTER).setRelayParams(_relaySpec.genesisTimestamp, _relaySpec.secondsPerEra);
    }


    function setOracleMaster(address _oracleMaster) external auth(ROLE_ORACLE_MANAGER) {
        require(ORACLE_MASTER == address(0), "LIDO: ORACLE_MASTER_ALREADY_DEFINED");
        ORACLE_MASTER = _oracleMaster;
        IOracleMaster(ORACLE_MASTER).setLido(address(this));
    }


    function setLedgerClone(address _ledgerClone) external auth(ROLE_LEDGER_MANAGER) {
        LEDGER_CLONE = _ledgerClone;
    }


    function setFee(uint16 _feeOperators, uint16 _feeTreasury,  uint16 _feeDevelopers) external auth(ROLE_FEE_MANAGER) {
        Types.Fee memory _fee;
        _fee.total = _feeTreasury + _feeOperators + _feeDevelopers;
        require(_fee.total <= 10000 && (_feeTreasury > 0 || _feeDevelopers > 0) , "LIDO: FEE_DONT_ADD_UP");

        emit FeeSet(_fee.total, _feeOperators, _feeTreasury, _feeDevelopers);

        _fee.developers = _feeDevelopers;
        _fee.operators = _feeOperators;
        _fee.treasury = _feeTreasury;
        FEE = _fee;
    }


    function getFee() external view returns (uint16){
        return FEE.total;
    }


    function getOperatorsFee() external view returns (uint16){
        return FEE.operators;
    }


    function getTreasuryFee() external view returns (uint16){
       return FEE.treasury;
    }


    function getDevelopersFee() external view returns (uint16){
        return FEE.developers;
    }


    function pause() external auth(ROLE_PAUSE_MANAGER) {
        _pause();
    }


    function resume() external auth(ROLE_PAUSE_MANAGER) {
        _unpause();
    }


    function addLedger(
        bytes32 _stashAccount,
        bytes32 _controllerAccount,
        uint16 _index,
        uint256 _share
    )
        external
        auth(ROLE_LEDGER_MANAGER)
        returns(address)
    {
        require(LEDGER_CLONE != address(0), "LIDO: UNSPECIFIED_LEDGER_CLONE");
        require(ORACLE_MASTER != address(0), "LIDO: NO_ORACLE_MASTER");
        require(ledgers.length < MAX_LEDGERS_AMOUNT, "LIDO: LEDGERS_POOL_LIMIT");
        require(ledgerByStash[_stashAccount] == address(0), "LIDO: STASH_ALREADY_EXISTS");

        address ledger = LEDGER_CLONE.cloneDeterministic(_stashAccount);

        ILedger(ledger).initialize(
            _stashAccount,
            _controllerAccount,
            address(vKSM),
            controller,
            RELAY_SPEC.minNominatorBalance
        );
        ledgers.push(ledger);
        ledgerByStash[_stashAccount] = ledger;
        ledgerByAddress[ledger] = ledgers.length;
        ledgerShares[ledger] = _share;
        ledgerSharesTotal += _share;

        IOracleMaster(ORACLE_MASTER).addLedger(ledger);



        IController(controller).newSubAccount(_index, _stashAccount, ledger);

        emit LedgerAdd(ledger, _stashAccount, _controllerAccount, _share);
        return ledger;
    }


    function setLedgerShare(address _ledger, uint256 _newShare) external auth(ROLE_LEDGER_MANAGER) {
        require(ledgerByAddress[_ledger] != 0, "LIDO: LEDGER_NOT_FOUND");

        ledgerSharesTotal -= ledgerShares[_ledger];
        ledgerShares[_ledger] = _newShare;
        ledgerSharesTotal += _newShare;

        emit LedgerSetShare(_ledger, _newShare);
    }


    function removeLedger(address _ledgerAddress) external auth(ROLE_LEDGER_MANAGER) {
        require(ledgerByAddress[_ledgerAddress] != 0, "LIDO: LEDGER_NOT_FOUND");
        require(ledgerShares[_ledgerAddress] == 0, "LIDO: LEDGER_HAS_NON_ZERO_SHARE");

        ILedger ledger = ILedger(_ledgerAddress);
        require(ledger.isEmpty(), "LIDO: LEDGER_IS_NOT_EMPTY");

        address lastLedger = ledgers[ledgers.length - 1];
        uint256 idxToRemove = ledgerByAddress[_ledgerAddress] - 1;
        ledgers[idxToRemove] = lastLedger; 
        ledgerByAddress[lastLedger] = idxToRemove + 1; 
        ledgers.pop();
        delete ledgerByAddress[_ledgerAddress];
        delete ledgerByStash[ledger.stashAccount()];
        delete ledgerShares[_ledgerAddress];

        IOracleMaster(ORACLE_MASTER).removeLedger(_ledgerAddress);

        vKSM.approve(address(ledger), 0);

        emit LedgerRemove(_ledgerAddress);
    }


    function nominate(bytes32 _stashAccount, bytes32[] calldata _validators) external auth(ROLE_STAKE_MANAGER) {
        require(ledgerByStash[_stashAccount] != address(0),  "UNKNOWN_STASH_ACCOUNT");

        ILedger(ledgerByStash[_stashAccount]).nominate(_validators);
    }


    function deposit(uint256 _amount) external whenNotPaused {
        vKSM.transferFrom(msg.sender, address(this), _amount);

        _submit(_amount);

        emit Deposited(msg.sender, _amount);
    }


    function redeem(uint256 _amount) external whenNotPaused {
        uint256 _shares = getSharesByPooledKSM(_amount);
        require(_shares <= _sharesOf(msg.sender), "LIDO: REDEEM_AMOUNT_EXCEEDS_BALANCE");
        require(claimOrders[msg.sender].length < MAX_CLAIMS, "LIDO: MAX_CLAIMS_EXCEEDS");

        _burnShares(msg.sender, _shares);
        fundRaisedBalance -= _amount;
        bufferedRedeems += _amount;

        Claim memory newClaim = Claim(_amount, uint64(block.timestamp) + RELAY_SPEC.unbondingPeriod);
        claimOrders[msg.sender].push(newClaim);
        pendingClaimsTotal += _amount;


        emit Transfer(msg.sender, address(0), _amount);


        emit Redeemed(msg.sender, _amount);
    }


    function claimUnbonded() external whenNotPaused {
        uint256 readyToClaim = 0;
        uint256 readyToClaimCount = 0;
        Claim[] storage orders = claimOrders[msg.sender];

        for (uint256 i = 0; i < orders.length; ++i) {
            if (orders[i].timeout < block.timestamp) {
                readyToClaim += orders[i].balance;
                readyToClaimCount += 1;
            }
            else {
                orders[i - readyToClaimCount] = orders[i];
            }
        }


        for (uint256 i = 0; i < readyToClaimCount; ++i) { orders.pop(); }

        if (readyToClaim > 0) {
            vKSM.transfer(msg.sender, readyToClaim);
            pendingClaimsTotal -= readyToClaim;
            emit Claimed(msg.sender, readyToClaim);
        }
    }


    function distributeRewards(uint256 _totalRewards, uint256 ledgerBalance) external {
        require(ledgerByAddress[msg.sender] != 0, "LIDO: NOT_FROM_LEDGER");

        Types.Fee memory _fee = FEE;


        uint256 _feeDevTreasure = uint256(_fee.developers + _fee.treasury);
        assert(_feeDevTreasure>0);

        fundRaisedBalance += _totalRewards;

        if (ledgerShares[msg.sender] > 0) {
            ledgerStake[msg.sender] += _totalRewards;
        }

        uint256 _rewards = _totalRewards * _feeDevTreasure / uint256(10000 - _fee.operators);
        uint256 shares2mint = _rewards * _getTotalShares() / (_getTotalPooledKSM()  - _rewards);

        _mintShares(treasury, shares2mint);

        uint256 _devShares = shares2mint *  uint256(_fee.developers) / _feeDevTreasure;
        _transferShares(treasury, developers, _devShares);
        _emitTransferAfterMintingShares(developers, _devShares);
        _emitTransferAfterMintingShares(treasury, shares2mint - _devShares);

        emit Rewards(msg.sender, _totalRewards, ledgerBalance);
    }


    function distributeLosses(uint256 _totalLosses, uint256 ledgerBalance) external {
        require(ledgerByAddress[msg.sender] != 0, "LIDO: NOT_FROM_LEDGER");

        fundRaisedBalance -= _totalLosses;
        if (ledgerShares[msg.sender] > 0) {

            ledgerStake[msg.sender] -= _totalLosses;
        }

        emit Losses(msg.sender, _totalLosses, ledgerBalance);
    }


    function flushStakes() external {
        require(msg.sender == ORACLE_MASTER, "LIDO: NOT_FROM_ORACLE_MASTER");

        _softRebalanceStakes();
    }


    function forceRebalanceStake() external auth(ROLE_STAKE_MANAGER) {
        _forceRebalanceStakes();

        bufferedDeposits = 0;
        bufferedRedeems = 0;
    }


    function refreshAllowances() external auth(ROLE_LEDGER_MANAGER) {
        uint _length = ledgers.length;
        for (uint i = 0; i < _length; i++) {
            vKSM.approve(ledgers[i], type(uint256).max);
        }
    }


    function _forceRebalanceStakes() internal {
        uint256 totalStake = getTotalPooledKSM();

        uint256 stakesSum = 0;
        address nonZeroLedged = address(0);
        uint _length = ledgers.length;
        uint256 _ledgerSharesTotal = ledgerSharesTotal;
        for (uint i = 0; i < _length; i++) {
            uint256 share = ledgerShares[ledgers[i]];
            uint256 stake = totalStake * share / _ledgerSharesTotal;

            stakesSum += stake;
            ledgerStake[ledgers[i]] = stake;

            if (share > 0 && nonZeroLedged == address(0)) {
                nonZeroLedged = ledgers[i];
            }
        }



        uint256 remainingDust = totalStake - stakesSum;
        if (remainingDust > 0 && nonZeroLedged != address(0)) {
            ledgerStake[nonZeroLedged] += remainingDust;
        }
    }


    function _softRebalanceStakes() internal {
        if (bufferedDeposits > 0 || bufferedRedeems > 0) {
            _distribute(bufferedDeposits.toInt256() - bufferedRedeems.toInt256());

            bufferedDeposits = 0;
            bufferedRedeems = 0;
        }
    }

    function _distribute(int256 _stake) internal {
        uint256 ledgersLength = ledgers.length;

        int256[] memory diffs = new int256[](ledgersLength);
        address[] memory ledgersCache = new address[](ledgersLength);
        int256[] memory ledgerStakesCache = new int256[](ledgersLength);
        uint256[] memory ledgerSharesCache = new uint256[](ledgersLength);

        int256 activeDiffsSum = 0;
        int256 totalChange = 0;

        {
            uint256 totalStake = getTotalPooledKSM();
            uint256 _ledgerSharesTotal = ledgerSharesTotal;
            int256 diff = 0;
            for (uint256 i = 0; i < ledgersLength; ++i) {
                ledgersCache[i] = ledgers[i];
                ledgerStakesCache[i] = int256(ledgerStake[ledgersCache[i]]);
                ledgerSharesCache[i] = ledgerShares[ledgersCache[i]];

                uint256 targetStake = totalStake * ledgerSharesCache[i] / _ledgerSharesTotal;
                diff = int256(targetStake) - int256(ledgerStakesCache[i]);
                if (_stake * diff > 0) {
                    activeDiffsSum += diff;
                }
                diffs[i] = diff;
            }
        }


        if (activeDiffsSum != 0) {
            int8 direction = 1;
            if (activeDiffsSum < 0) {
                direction = -1;
                activeDiffsSum = -activeDiffsSum;
            }

            for (uint256 i = 0; i < ledgersLength; ++i) {
                diffs[i] *= direction;
                if (diffs[i] > 0 && (direction < 0 || ledgerSharesCache[i] > 0)) {
                    int256 change = diffs[i] * _stake / activeDiffsSum;
                    int256 newStake = ledgerStakesCache[i] + change;

                    ledgerStake[ledgersCache[i]] = uint256(newStake);
                    ledgerStakesCache[i] = newStake;
                    totalChange += change;
                }
            }
        }

        {
            int256 remaining = _stake - totalChange;
            if (remaining > 0) {
                for (uint256 i = 0; i < ledgersLength; ++i) {
                    if (ledgerSharesCache[i] > 0) {
                        ledgerStake[ledgersCache[i]] += uint256(remaining);
                        break;
                    }
                }
            }
            else if (remaining < 0) {
                for (uint256 i = 0; i < ledgersLength || remaining < 0; ++i) {
                    uint256 stake = uint256(ledgerStakesCache[i]);
                    if (stake > 0) {
                        uint256 decrement = stake > uint256(-remaining) ? uint256(-remaining) : stake;
                        ledgerStake[ledgersCache[i]] -= decrement;
                        remaining += int256(decrement);
                    }
                }
            }
        }
    }


    function _submit(uint256 _deposit) internal returns (uint256) {
        address sender = msg.sender;

        require(_deposit != 0, "LIDO: ZERO_DEPOSIT");

        uint256 sharesAmount = getSharesByPooledKSM(_deposit);
        if (sharesAmount == 0) {


            sharesAmount = _deposit;
        }

        fundRaisedBalance += _deposit;
        bufferedDeposits += _deposit;
        _mintShares(sender, sharesAmount);

        _emitTransferAfterMintingShares(sender, sharesAmount);
        return sharesAmount;
    }



    function _emitTransferAfterMintingShares(address _to, uint256 _sharesAmount) internal {
        emit Transfer(address(0), _to, getPooledKSMByShares(_sharesAmount));
    }


    function _getTotalPooledKSM() internal view override returns (uint256) {
        return fundRaisedBalance;
    }
}

pragma solidity ^0.4.24;

import 'zeppelin-solidity/contracts/token/ERC20/StandardToken.sol';

contract LTOToken is StandardToken {

  uint256 internal internalTotalSupply;

  string public name = "LTO Network Token";
  string public symbol = "LTO";
  uint8 public decimals = 8;
  address public bridgeAddress;

  mapping (address => address) public intermediateAddresses;

  constructor(
    uint256 _initialSupply,
    address _bridgeAddress,
    uint256 _bridgeSupply
  ) public {
    internalTotalSupply = _initialSupply + _bridgeSupply;
    totalSupply_ = _initialSupply;
    balances[msg.sender] = _initialSupply;
    balances[_bridgeAddress] = _bridgeSupply;

    bridgeAddress = _bridgeAddress;
  }

  modifier onlyBridge() {
    require(msg.sender == bridgeAddress);
    _;
  }


  function transfer(address _to, uint256 _value) public returns (bool) {
    require(_value <= balances[msg.sender]);
    require(_to != address(0));

    address to = _to;


    if (intermediateAddresses[to] == to) {
      to = bridgeAddress;
    }

    balances[msg.sender] = balances[msg.sender].sub(_value);
    balances[to] = balances[to].add(_value);
    emit Transfer(msg.sender, _to, _value);

    recalculateTotalSupply();

    return true;
  }

  function recalculateTotalSupply() internal {

    totalSupply_ = internalTotalSupply - balances[bridgeAddress];
  }


  function addIntermediateAddress(address _intermediate) public onlyBridge {
    require(_intermediate != address(0));

    intermediateAddresses[_intermediate] = _intermediate;
  }
}

pragma solidity ^0.4.23;



contract BEP20Basic {
  function totalSupply() public view returns (uint256);
  function balanceOf(address who) public view returns (uint256);
  function transfer(address to, uint256 value) public returns (bool);
  event Transfer(address indexed from, address indexed to, uint256 value);
}




library SafeMath {


  function mul(uint256 a, uint256 b) internal pure returns (uint256 c) {



    if (a == 0) {
      return 0;
    }

    c = a * b;
    assert(c / a == b);
    return c;
  }


  function div(uint256 a, uint256 b) internal pure returns (uint256) {



    return a / b;
  }


  function sub(uint256 a, uint256 b) internal pure returns (uint256) {
    assert(b <= a);
    return a - b;
  }


  function add(uint256 a, uint256 b) internal pure returns (uint256 c) {
    c = a + b;
    assert(c >= a);
    return c;
  }
}




contract BasicToken is BEP20Basic {
  using SafeMath for uint256;

  mapping(address => uint256) balances;

  uint256 totalSupply_;


  function totalSupply() public view returns (uint256) {
    return totalSupply_;
  }


  function transfer(address _to, uint256 _value) public returns (bool) {
    require(_to != address(0));
    require(_value <= balances[msg.sender]);

    balances[msg.sender] = balances[msg.sender].sub(_value);
    balances[_to] = balances[_to].add(_value);
    emit Transfer(msg.sender, _to, _value);
    return true;
  }


  function balanceOf(address _owner) public view returns (uint256) {
    return balances[_owner];
  }

}



contract BEP20 is BEP20Basic {
  function allowance(address owner, address spender)
    public view returns (uint256);

  function transferFrom(address from, address to, uint256 value)
    public returns (bool);

  function approve(address spender, uint256 value) public returns (bool);
  event Approval(
    address indexed owner,
    address indexed spender,
    uint256 value
  );
}



contract StandardToken is BEP20, BasicToken {

  mapping (address => mapping (address => uint256)) internal allowed;



  function transferFrom(
    address _from,
    address _to,
    uint256 _value
  )
    public
    returns (bool)
  {
    require(_to != address(0));
    require(_value <= balances[_from]);
    require(_value <= allowed[_from][msg.sender]);

    balances[_from] = balances[_from].sub(_value);
    balances[_to] = balances[_to].add(_value);
    allowed[_from][msg.sender] = allowed[_from][msg.sender].sub(_value);
    emit Transfer(_from, _to, _value);
    return true;
  }


  function approve(address _spender, uint256 _value) public returns (bool) {
