interface NXMToken {
    function balanceOf(address owner) external view returns (uint256);
    function approve(address spender, uint256 value) external returns (bool);

}

library NexusMutualCover {
    using SafeMath for uint;

    struct Data {
        INXMMaster nxMaster;
    }

    enum CoverStatus {
        Active,
        ClaimAccepted,
        ClaimDenied,
        CoverExpired,
        ClaimSubmitted,
        Requested
    }

    enum ClaimStatus {
        PendingClaimAssessorVote, 
        PendingClaimAssessorVoteDenied, 
        PendingClaimAssessorVoteThresholdNotReachedAccept, 
        PendingClaimAssessorVoteThresholdNotReachedDeny, 
        PendingClaimAssessorConsensusNotReachedAccept, 
        PendingClaimAssessorConsensusNotReachedDeny, 
        FinalClaimAssessorVoteDenied, 
        FinalClaimAssessorVoteAccepted, 
        FinalClaimAssessorVoteDeniedMVAccepted, 
        FinalClaimAssessorVoteDeniedMVDenied, 
        FinalClaimAssessorVotAcceptedMVNoDecision, 
        FinalClaimAssessorVoteDeniedMVNoDecision, 
        ClaimAcceptedPayoutPending, 
        ClaimAcceptedNoPayout, 
        ClaimAcceptedPayoutDone 
    }

    function setMasterAddress(Data storage data, address masterAddress) internal {
        data.nxMaster = INXMMaster(masterAddress);
    }

    function buyCover(
        Data storage data,
        address coveredContractAddress,
        bytes4 coverCurrency,
        uint[] memory coverDetails,
        uint16 coverPeriod,
        uint8 _v,
        bytes32 _r,
        bytes32 _s
    ) internal returns (uint coverId) {

        uint coverPrice = coverDetails[1];
        Pool1 pool1 = Pool1(data.nxMaster.getLatestAddress("P1"));
        if (coverCurrency == "ETH") {
            pool1.makeCoverBegin.value(coverPrice)(coveredContractAddress, coverCurrency, coverDetails, coverPeriod, _v, _r, _s);
        } else {
            address payable pool1Address = address(uint160(address(pool1)));
            PoolData poolData = PoolData(data.nxMaster.getLatestAddress("PD"));
            IERC20 erc20 = IERC20(poolData.getCurrencyAssetAddress(coverCurrency));
            erc20.approve(pool1Address, coverPrice);
            pool1.makeCoverUsingCA(coveredContractAddress, coverCurrency, coverDetails, coverPeriod, _v, _r, _s);
        }

        QuotationData quotationData = QuotationData(data.nxMaster.getLatestAddress("QD"));

        coverId = quotationData.getCoverLength().sub(1);
    }

    function submitClaim(Data storage data, uint coverId) internal returns (uint) {
        Claims claims = Claims(data.nxMaster.getLatestAddress("CL"));
        claims.submitClaim(coverId);

        ClaimsData claimsData = ClaimsData(data.nxMaster.getLatestAddress("CD"));

        uint claimId = claimsData.actualClaimLength() - 1;
        return claimId;
    }

    function getCover(
        Data storage data,
        uint coverId
    ) internal view returns (
        uint cid,
        uint8 status,
        uint sumAssured,
        uint16 coverPeriod,
        uint validUntil
    ) {
        QuotationData quotationData = QuotationData(data.nxMaster.getLatestAddress("QD"));
        return quotationData.getCoverDetailsByCoverID2(coverId);
    }

    function sellNXMTokens(Data storage data, uint amount) internal returns (uint ethValue) {
        address payable pool1Address = data.nxMaster.getLatestAddress("P1");
        Pool1 p1 = Pool1(pool1Address);

        NXMToken nxmToken = NXMToken(data.nxMaster.tokenAddress());

        ethValue = p1.getWei(amount);
        nxmToken.approve(pool1Address, amount);
        p1.sellNXMTokens(amount);
    }

    function getCurrencyAssetAddress(Data storage data, bytes4 currency) internal view returns (address) {
        PoolData pd = PoolData(data.nxMaster.getLatestAddress("PD"));
        return pd.getCurrencyAssetAddress(currency);
    }

    function getLockTokenTimeAfterCoverExpiry(Data storage data) internal returns (uint) {
        TokenData tokenData = TokenData(data.nxMaster.getLatestAddress("TD"));
        return tokenData.lockTokenTimeAfterCoverExp();
    }

    function getTokenAddress(Data storage data) internal view returns (address) {
        return data.nxMaster.tokenAddress();
    }

    function payoutIsCompleted(Data storage data, uint claimId) internal view returns (bool) {
        uint256 status;
        Claims claims = Claims(data.nxMaster.getLatestAddress("CL"));
        (, status, , , ) = claims.getClaimbyIndex(claimId);
        return status == uint(ClaimStatus.FinalClaimAssessorVoteAccepted)
            || status == uint(ClaimStatus.ClaimAcceptedPayoutDone);
    }
}

contract Distributor is
  ERC721Full("NXMDistributorNFT", "NXMDNFT"),
  Ownable,
  ReentrancyGuard {

  using NexusMutualCover for NexusMutualCover.Data;

  struct Token {
    uint expirationTimestamp;
    bytes4 coverCurrency;
    uint coverAmount;
    uint coverPrice;
    uint coverPriceNXM;
    uint expireTime;
    uint generationTime;
    uint coverId;
    bool claimInProgress;
    uint claimId;
  }

  event ClaimRedeemed (
    address receiver,
    uint value,
    bytes4 currency
  );

  bytes4 internal constant ethCurrency = "ETH";

  NexusMutualCover.Data coverAPI;
  uint public distributorFeePercentage;
  uint256 internal issuedTokensCount;
  mapping(uint256 => Token) public tokens;

  mapping(bytes4 => uint) public withdrawableTokens;

  constructor(address _masterAddress, uint _distributorFeePercentage) public {
    distributorFeePercentage = _distributorFeePercentage;
    coverAPI.setMasterAddress(_masterAddress);
  }







  function buyCover(
        address coveredContractAddress,
        bytes4 coverCurrency,
        uint[] calldata coverDetails,
        uint16 coverPeriod,
        uint8 _v,
        bytes32 _r,
        bytes32 _s
  )
     external
     payable
  {

    uint coverPrice = coverDetails[1];
    uint requiredValue = distributorFeePercentage.mul(coverPrice).div(100).add(coverPrice);
    if (coverCurrency == "ETH") {
      require(msg.value == requiredValue, "Incorrect value sent");
    } else {
      IERC20 erc20 = IERC20(coverAPI.getCurrencyAssetAddress(coverCurrency));
      require(erc20.transferFrom(msg.sender, address(this), requiredValue), "Transfer failed");
    }

    uint coverId = coverAPI.buyCover(coveredContractAddress, coverCurrency, coverDetails, coverPeriod, _v, _r, _s);
    withdrawableTokens[coverCurrency] = withdrawableTokens[coverCurrency].add(requiredValue.sub(coverPrice));



    uint256 nextTokenId = issuedTokensCount++;

    uint expirationTimestamp = block.timestamp + coverAPI.getLockTokenTimeAfterCoverExpiry() + coverPeriod * 1 days;
    tokens[nextTokenId] = Token(expirationTimestamp,
      coverCurrency,
      coverDetails[0],
      coverDetails[1],
      coverDetails[2],
      coverDetails[3],
      coverDetails[4],
      coverId, false, 0);
    _mint(msg.sender, nextTokenId);
  }

  function submitClaim(
    uint256 tokenId
  )
    external
    onlyTokenApprovedOrOwner(tokenId)
  {

    if (tokens[tokenId].claimInProgress) {
      uint8 coverStatus;
      (, coverStatus, , , ) = coverAPI.getCover(tokens[tokenId].coverId);
      require(coverStatus == uint8(NexusMutualCover.CoverStatus.ClaimDenied),
        "Can submit another claim only if the previous one was denied.");
    }
    require(tokens[tokenId].expirationTimestamp > block.timestamp, "Token is expired");

    uint claimId = coverAPI.submitClaim(tokens[tokenId].coverId);

    tokens[tokenId].claimInProgress = true;
    tokens[tokenId].claimId = claimId;
  }

  function redeemClaim(
    uint256 tokenId
  )
    public
    onlyTokenApprovedOrOwner(tokenId)
    nonReentrant
  {
    require(tokens[tokenId].claimInProgress, "No claim is in progress");
    uint8 coverStatus;
    uint sumAssured;
    (, coverStatus, sumAssured, , ) = coverAPI.getCover(tokens[tokenId].coverId);

    require(coverStatus == uint8(NexusMutualCover.CoverStatus.ClaimAccepted), "Claim is not accepted");
    require(coverAPI.payoutIsCompleted(tokens[tokenId].coverId), "Claim accepted but payout not completed");

    _burn(tokenId);
    _sendAssuredSum(tokens[tokenId].coverCurrency, sumAssured);
    emit ClaimRedeemed(msg.sender, sumAssured, tokens[tokenId].coverCurrency);
  }

  function _sendAssuredSum(
    bytes4 coverCurrency,
    uint sumAssured
    )
    internal
  {
    if (coverCurrency == ethCurrency) {
      msg.sender.transfer(sumAssured);
    } else {
      IERC20 erc20 = IERC20(coverAPI.getCurrencyAssetAddress(coverCurrency));
      require(erc20.transfer(msg.sender, sumAssured), "Transfer failed");
    }
  }

  function getCoverStatus(uint256 tokenId) external view returns (uint8 coverStatus, bool payoutCompleted) {
    (, coverStatus, , , ) = coverAPI.getCover(tokens[tokenId].coverId);
    payoutCompleted = coverAPI.payoutIsCompleted(tokenId);
  }

  function nxmTokenApprove(address _spender, uint256 _value)
  public
  onlyOwner
  {
    IERC20 nxmToken = IERC20(coverAPI.getTokenAddress());
    nxmToken.approve(_spender, _value);
  }

  function withdrawEther(address payable _recipient, uint256 _amount)
    external
    onlyOwner
    nonReentrant
  {
    require(withdrawableTokens[ethCurrency] >= _amount, "Not enough ETH");
    withdrawableTokens[ethCurrency] = withdrawableTokens[ethCurrency].sub(_amount);
    _recipient.transfer(_amount);
  }

  function withdrawTokens(address payable _recipient, uint256 _amount, bytes4 _currency)
    external
    onlyOwner
    nonReentrant
  {
    require(withdrawableTokens[_currency] >= _amount, "Not enough tokens");
    withdrawableTokens[_currency] = withdrawableTokens[_currency].sub(_amount);

    IERC20 erc20 = IERC20(coverAPI.getCurrencyAssetAddress(_currency));
    require(erc20.transfer(_recipient, _amount), "Transfer failed");
  }

  function sellNXMTokens(uint amount)
    external
    onlyOwner
  {
    uint ethValue = coverAPI.sellNXMTokens(amount);
    withdrawableTokens[ethCurrency] = withdrawableTokens[ethCurrency].add(ethValue);
  }

  modifier onlyTokenApprovedOrOwner(uint256 tokenId) {
    require(_isApprovedOrOwner(msg.sender, tokenId), "Not approved or owner");
    _;
  }

  function () payable external {
  }
}

