        return uint(1e18) * x / SQRT_1;
    }

    function rVol(address tokenIn, address tokenOut, uint points, uint window) public view returns (uint) {
        return vol(KV1O.sample(tokenIn, uint(10)**IERC20(tokenIn).decimals(), tokenOut, points, window));
    }

    function rVolHourly(address tokenIn, address tokenOut, uint points) external view returns (uint) {
        return rVol(tokenIn, tokenOut, points, 2);
    }

    function rVolDaily(address tokenIn, address tokenOut, uint points) external view returns (uint) {
        return rVol(tokenIn, tokenOut, points, 48);
    }

    function rVolWeekly(address tokenIn, address tokenOut, uint points) external view returns (uint) {
        return rVol(tokenIn, tokenOut, points, 336);
    }

    function rVolHourlyRecent(address tokenIn, address tokenOut) external view returns (uint) {
        return rVol(tokenIn, tokenOut, 2, 2);
    }

    function rVolDailyRecent(address tokenIn, address tokenOut) external view returns (uint) {
        return rVol(tokenIn, tokenOut, 2, 48);
    }

    function rVolWeeklyRecent(address tokenIn, address tokenOut) external view returns (uint) {
        return rVol(tokenIn, tokenOut, 2, 336);
    }
}

pragma solidity ^0.7.0;
pragma experimental ABIEncoderV2;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "./interfaces/IERC20Decimals.sol";
import "./balancer-core-v2/lib/math/LogExpMath.sol";
import "./balancer-core-v2/lib/math/FixedPoint.sol";
import "./balancer-core-v2/vault/interfaces/IMinimalSwapInfoPool.sol";
import "./balancer-core-v2/vault/interfaces/IVault.sol";
import "./balancer-core-v2/pools/BalancerPoolToken.sol";

contract ConvergentCurvePool is IMinimalSwapInfoPool, BalancerPoolToken {
    using LogExpMath for uint256;
    using FixedPoint for uint256;


    IERC20 public immutable underlying;
    uint8 public immutable underlyingDecimals;

    IERC20 public immutable bond;
    uint8 public immutable bondDecimals;

    uint256 public immutable expiration;

    uint256 public immutable unitSeconds;


    IVault private immutable _vault;
    bytes32 private immutable _poolId;


    uint128 public feesUnderlying;
    uint128 public feesBond;

    address public governance;

    uint256 public immutable percentFee;

    uint256 public immutable percentFeeGov;













    constructor(
        IERC20 _underlying,
        IERC20 _bond,
        uint256 _expiration,
        uint256 _unitSeconds,
        IVault vault,
        uint256 _percentFee,
        uint256 _percentFeeGov,
        address _governance,
        string memory name,
        string memory symbol
    ) BalancerPoolToken(name, symbol) {

        bytes32 poolId = vault.registerPool(
            IVault.PoolSpecialization.TWO_TOKEN
        );

        IERC20[] memory tokens = new IERC20[](2);
        if (_underlying < _bond) {
            tokens[0] = _underlying;
            tokens[1] = _bond;
        } else {
            tokens[0] = _bond;
            tokens[1] = _underlying;
        }




        vault.registerTokens(poolId, tokens, new address[](2));


        _vault = vault;
        _poolId = poolId;
        percentFee = _percentFee;
        percentFeeGov = _percentFeeGov;
        underlying = _underlying;
        underlyingDecimals = IERC20Decimals(address(_underlying)).decimals();
        bond = _bond;
        bondDecimals = IERC20Decimals(address(_bond)).decimals();
        expiration = _expiration;
        unitSeconds = _unitSeconds;
        governance = _governance;
    }


    function getRate() external override view returns (uint256) {

        return FixedPoint.ONE;
    }



    function getVault() external view returns (IVault) {
        return _vault;
    }



    function getPoolId() external view returns (bytes32) {
        return _poolId;
    }








    function onSwapGivenIn(
        IPoolSwapStructs.SwapRequestGivenIn calldata request,
        uint256 currentBalanceTokenIn,
        uint256 currentBalanceTokenOut
    ) public override returns (uint256) {


        uint256 amountTokenIn = _tokenToFixed(
            request.amountIn,
            request.tokenIn
        );




        (uint256 tokenInReserve, uint256 tokenOutReserve) = _adjustedReserve(
            currentBalanceTokenIn,
            request.tokenIn,
            currentBalanceTokenOut,
            request.tokenOut
        );

        tokenInReserve = _tokenToFixed(tokenInReserve, request.tokenIn);
        tokenOutReserve = _tokenToFixed(tokenOutReserve, request.tokenOut);


        uint256 quote = solveTradeInvariant(
            amountTokenIn,
            tokenInReserve,
            tokenOutReserve,
            true
        );


        quote = _assignTradeFee(amountTokenIn, quote, request.tokenOut, false);
        return _fixedToToken(quote, request.tokenOut);
    }







    function onSwapGivenOut(
        IPoolSwapStructs.SwapRequestGivenOut calldata request,
        uint256 currentBalanceTokenIn,
        uint256 currentBalanceTokenOut
    ) public override returns (uint256) {


        uint256 amountTokenOut = _tokenToFixed(
            request.amountOut,
            request.tokenOut
        );




        (uint256 tokenInReserve, uint256 tokenOutReserve) = _adjustedReserve(
            currentBalanceTokenIn,
            request.tokenIn,
            currentBalanceTokenOut,
            request.tokenOut
        );


        tokenInReserve = _tokenToFixed(tokenInReserve, request.tokenIn);
        tokenOutReserve = _tokenToFixed(tokenOutReserve, request.tokenOut);


        uint256 quote = solveTradeInvariant(
            amountTokenOut,
            tokenOutReserve,
            tokenInReserve,
            false
        );

        quote = _assignTradeFee(quote, amountTokenOut, request.tokenOut, true);

        return _fixedToToken(quote, request.tokenIn);
    }



    function _getSortedBalances(uint256[] memory currentBalances)
        internal
        view
        returns (uint256 underlyingBalance, uint256 bondBalance)
    {
        if (underlying < bond) {
            underlyingBalance = currentBalances[0];
            bondBalance = currentBalances[1];
        } else {
            underlyingBalance = currentBalances[1];
            bondBalance = currentBalances[0];
        }
    }



    function onJoinPool(
        bytes32, 
        address, 
        address recipient,
        uint256[] calldata currentBalances,
        uint256,
        uint256 protocolSwapFee,
        bytes calldata userData
    )
        external
        override
        returns (
            uint256[] memory amountsIn,
            uint256[] memory dueProtocolFeeAmounts
        )
    {

        require(msg.sender == address(_vault), "Non Vault caller");
        uint256[2] memory maxAmountsIn = abi.decode(userData, (uint256[2]));
        require(
            currentBalances.length == 2 && maxAmountsIn.length == 2,
            "Invalid format"
        );



        {
            (
                uint256 localFeeUnderlying,
                uint256 localFeeBond
            ) = _mintGovernanceLP(currentBalances);
            dueProtocolFeeAmounts = new uint256[](2);


            if (underlying < bond) {
                dueProtocolFeeAmounts[0] = localFeeUnderlying.mul(
                    protocolSwapFee
                );
                dueProtocolFeeAmounts[1] = localFeeBond.mul(protocolSwapFee);
            } else {
                dueProtocolFeeAmounts[1] = localFeeUnderlying.mul(
                    protocolSwapFee
                );
                dueProtocolFeeAmounts[0] = localFeeBond.mul(protocolSwapFee);
            }
        }

        {
            (uint256 callerUsedUnderlying, uint256 callerUsedBond) = _mintLP(
                maxAmountsIn[0],
                maxAmountsIn[1],
                currentBalances,
                recipient
            );

            amountsIn = new uint256[](2);


            if (underlying < bond) {
                amountsIn[0] = callerUsedUnderlying;
                amountsIn[1] = callerUsedBond;
            } else {
                amountsIn[1] = callerUsedUnderlying;
                amountsIn[0] = callerUsedBond;
            }
        }
    }














    function onExitPool(
        bytes32,
        address,
        address recipient,
        uint256[] calldata currentBalances,
        uint256,
        uint256 protocolSwapFee,
        bytes calldata userData
    )
        external
        override
        returns (
            uint256[] memory amountsOut,
            uint256[] memory dueProtocolFeeAmounts
        )
    {

        require(msg.sender == address(_vault), "Non Vault caller");
        uint256[2] memory minAmountsOut = abi.decode(userData, (uint256[2]));
        require(
            currentBalances.length == 2 && minAmountsOut.length == 2,
            "Invalid format"
        );



        {
            (
                uint256 localFeeUnderlying,
                uint256 localFeeBond
            ) = _mintGovernanceLP(currentBalances);

            dueProtocolFeeAmounts = new uint256[](2);


            if (underlying < bond) {
                dueProtocolFeeAmounts[0] = localFeeUnderlying.mul(
                    protocolSwapFee
                );
                dueProtocolFeeAmounts[1] = localFeeBond.mul(protocolSwapFee);
            } else {
                dueProtocolFeeAmounts[1] = localFeeUnderlying.mul(
                    protocolSwapFee
                );
                dueProtocolFeeAmounts[0] = localFeeBond.mul(protocolSwapFee);
            }
        }

        {
            (uint256 releasedUnderlying, uint256 releasedBond) = _burnLP(
                minAmountsOut[0],
                minAmountsOut[1],
                currentBalances,
                recipient
            );

            amountsOut = new uint256[](2);


            if (underlying < bond) {
                amountsOut[0] = releasedUnderlying;
                amountsOut[1] = releasedBond;
            } else {
                amountsOut[1] = releasedUnderlying;
                amountsOut[0] = releasedBond;
            }
        }
    }













    function solveTradeInvariant(
        uint256 amountX,
        uint256 reserveX,
        uint256 reserveY,
        bool out
    ) public view returns (uint256) {

        uint256 a = _getYieldExponent();

        uint256 xBeforePowA = LogExpMath.pow(reserveX, a);

        uint256 yBeforePowA = LogExpMath.pow(reserveY, a);

        uint256 xAfterPowA = out
            ? LogExpMath.pow(reserveX + amountX, a)
            : LogExpMath.pow(reserveX.sub(amountX), a);


        uint256 yAfter = (xBeforePowA + yBeforePowA).sub(xAfterPowA);

        yAfter = LogExpMath.pow(yAfter, uint256(FixedPoint.ONE).div(a));

        return out ? reserveY.sub(yAfter) : yAfter.sub(reserveY);
    }












    function _assignTradeFee(
        uint256 amountIn,
        uint256 amountOut,
        IERC20 outputToken,
        bool isInputTrade
    ) internal returns (uint256) {

        if (isInputTrade) {

            if (outputToken == bond) {

                uint256 impliedYieldFee = percentFee.mul(
                    amountOut.sub(amountIn)
                );

                feesUnderlying += uint128(
                    _fixedToToken(impliedYieldFee, underlying)
                );

                return amountIn.add(impliedYieldFee);
            } else {

                uint256 impliedYieldFee = percentFee.mul(
                    amountIn.sub(amountOut)
                );

                feesBond += uint128(_fixedToToken(impliedYieldFee, bond));

                return amountIn.add(impliedYieldFee);
            }
        } else {
            if (outputToken == bond) {

                uint256 impliedYieldFee = percentFee.mul(
                    amountOut.sub(amountIn)
                );

                feesBond += uint128(_fixedToToken(impliedYieldFee, bond));

                return amountOut.sub(impliedYieldFee);
            } else {

                uint256 impliedYieldFee = percentFee.mul(
                    amountIn.sub(amountOut)
                );

                feesUnderlying += uint128(
                    _fixedToToken(impliedYieldFee, underlying)
                );

                return amountOut.sub(impliedYieldFee);
            }
        }
    }







    function _mintLP(
        uint256 inputUnderlying,
        uint256 inputBond,
        uint256[] memory currentBalances,
        address recipient
    ) internal returns (uint256, uint256) {


        (uint256 reserveUnderlying, uint256 reserveBond) = _getSortedBalances(
            currentBalances
        );

        uint256 localTotalSupply = totalSupply();

        if (localTotalSupply == 0) {


            _mintPoolTokens(recipient, inputUnderlying);
            return (inputUnderlying, 0);
        }



        uint256 underlyingPerBond = reserveUnderlying.div(reserveBond);

        uint256 neededUnderlying = underlyingPerBond.mul(inputBond);


        if (neededUnderlying > inputUnderlying) {


            uint256 mintAmount = (inputUnderlying.mul(localTotalSupply)).div(
                reserveUnderlying
            );


            _mintPoolTokens(recipient, mintAmount);


            return (inputUnderlying, inputUnderlying.div(underlyingPerBond));
        } else {


            uint256 mintAmount = (neededUnderlying.mul(localTotalSupply)).div(
                reserveUnderlying
            );

            _mintPoolTokens(recipient, mintAmount);

            return (neededUnderlying, inputBond);
        }
    }








    function _burnLP(
        uint256 minOutputUnderlying,
        uint256 minOutputBond,
        uint256[] memory currentBalances,
        address source
    ) internal returns (uint256, uint256) {
        (uint256 reserveUnderlying, uint256 reserveBond) = _getSortedBalances(
            currentBalances
        );

        uint256 localTotalSupply = totalSupply();

        uint256 underlyingPerBond = reserveUnderlying.div(reserveBond);

        if (minOutputUnderlying > minOutputBond.mul(underlyingPerBond)) {



            uint256 burned = (minOutputUnderlying.mul(localTotalSupply)).div(
                reserveUnderlying
            );
            _burnPoolTokens(source, burned);


            return (
                minOutputUnderlying,
                minOutputUnderlying.div(underlyingPerBond)
            );
        } else {


            uint256 burned = (minOutputBond.mul(localTotalSupply)).div(
                reserveBond
            );
            _burnPoolTokens(source, burned);


            return (minOutputBond.mul(underlyingPerBond), minOutputBond);
        }
    }




    function _mintGovernanceLP(uint256[] memory currentBalances)
        internal
        returns (uint256, uint256)
    {
        if (percentFeeGov == 0) {
            return (feesUnderlying, feesBond);
        }



        uint256 localFeeUnderlying = uint256(feesUnderlying);
        uint256 localFeeBond = uint256(feesBond);
        (uint256 feesUsedUnderlying, uint256 feesUsedBond) = _mintLP(
            localFeeUnderlying.mul(percentFeeGov),
            localFeeBond.mul(percentFeeGov),
            currentBalances,
            governance
        );


        require(
            localFeeUnderlying >= (feesUsedUnderlying).div(percentFeeGov),
            "Underflow"
        );
        require(localFeeBond >= (feesUsedBond).div(percentFeeGov), "Underflow");

        (feesUnderlying, feesBond) = (
            uint128(
                localFeeUnderlying - (feesUsedUnderlying).div(percentFeeGov)
            ),
            uint128(localFeeBond - (feesUsedBond).div(percentFeeGov))
        );

        return (localFeeUnderlying, localFeeBond);
    }



    function _getYieldExponent() internal virtual view returns (uint256) {

        uint256 timeTillExpiry = block.timestamp < expiration
            ? expiration - block.timestamp
            : 0;
        timeTillExpiry *= 1e18;

        timeTillExpiry = timeTillExpiry.div(unitSeconds * 1e18);
        uint256 result = uint256(FixedPoint.ONE).sub(timeTillExpiry);
        return result;
    }






    function _adjustedReserve(
        uint256 reserveTokenIn,
        IERC20 tokenIn,
        uint256 reserveTokenOut,
        IERC20 tokenOut
    ) internal view returns (uint256, uint256) {


        if (tokenIn == underlying && tokenOut == bond) {

            return (reserveTokenIn, reserveTokenOut + totalSupply());
        } else if (tokenIn == bond && tokenOut == underlying) {

            return (reserveTokenIn + totalSupply(), reserveTokenOut);
        }

        revert("Token request doesn't match stored");
    }





    function _tokenToFixed(uint256 amount, IERC20 token)
        internal
        view
        returns (uint256)
    {

        if (token == underlying) {
            return _normalize(amount, underlyingDecimals, 18);
        } else if (token == bond) {
            return _normalize(amount, bondDecimals, 18);
        }

        revert("Called with non pool token");
    }






    function _fixedToToken(uint256 amount, IERC20 token)
        internal
        view
        returns (uint256)
    {
        if (token == underlying) {

            return _normalize(amount, 18, underlyingDecimals);
        } else if (token == bond) {

            return _normalize(amount, 18, bondDecimals);
        }

        revert("Called with non pool token");
    }






    function _normalize(
        uint256 amount,
        uint8 decimalsBefore,
        uint8 decimalsAfter
    ) internal view returns (uint256) {

        if (decimalsBefore > decimalsAfter) {

            amount = amount / 10**(decimalsBefore - decimalsAfter);

        } else if (decimalsBefore < decimalsAfter) {

            amount = amount * 10**(decimalsAfter - decimalsBefore);
        }

        return amount;
    }
}

pragma solidity ^0.8.3;

import "./Storage.sol";








library History {













    struct HistoricalBalances {
        string name;

        bytes32 cachedPointer;
    }





    function load(string memory name)
        internal
        pure
        returns (HistoricalBalances memory)
    {
        mapping(address => uint256[]) storage storageData =
            Storage.mappingAddressToUnit256ArrayPtr(name);
        bytes32 pointer;
        assembly {
            pointer := storageData.slot
        }
        return HistoricalBalances(name, pointer);
    }






    function _getMapping(bytes32 pointer)
        private
        pure
        returns (mapping(address => uint256[]) storage storageData)
    {
        assembly {
            storageData.slot := pointer
        }
    }







    function push(
        HistoricalBalances memory wrapper,
        address who,
        uint256 data
    ) internal {


        require(data < uint256(1) << 192, "OoB");

        mapping(address => uint256[]) storage storageMapping =
            _getMapping(wrapper.cachedPointer);

        uint256[] storage storageData = storageMapping[who];

        uint256 blockNumber = block.number << 192;


        uint256 packedData = blockNumber | data;

        (uint256 minIndex, uint256 length) = _loadBounds(storageData);

        uint256 loadedBlockNumber = 0;
        if (length != 0) {
            (loadedBlockNumber, ) = _loadAndUnpack(storageData, length - 1);
        }

        uint256 index = length;


        if (loadedBlockNumber == block.number) {
            index = length - 1;
        }

        assembly {

            sstore(
                add(

                    add(storageData.slot, 1),

                    index
                ),
                packedData
            )
        }

        if (loadedBlockNumber != block.number) {
            _setBounds(storageData, minIndex, length + 1);
        }
    }





    function loadTop(HistoricalBalances memory wrapper, address who)
        internal
        view
        returns (uint256)
    {

        uint256[] storage userData = _getMapping(wrapper.cachedPointer)[who];

        (, uint256 length) = _loadBounds(userData);

        if (length == 0) {
            return 0;
        }

        (, uint256 storedData) = _loadAndUnpack(userData, length - 1);

        return (storedData);
    }







    function find(
        HistoricalBalances memory wrapper,
        address who,
        uint256 blocknumber
    ) internal view returns (uint256) {

        mapping(address => uint256[]) storage storageMapping =
            _getMapping(wrapper.cachedPointer);

        uint256[] storage storageData = storageMapping[who];

        (uint256 minIndex, uint256 length) = _loadBounds(storageData);

        (, uint256 loadedData) =
            _find(storageData, blocknumber, 0, minIndex, length);

        return (loadedData);
    }








    function findAndClear(
        HistoricalBalances memory wrapper,
        address who,
        uint256 blocknumber,
        uint256 staleBlock
    ) internal returns (uint256) {

        mapping(address => uint256[]) storage storageMapping =
            _getMapping(wrapper.cachedPointer);

        uint256[] storage storageData = storageMapping[who];

        (uint256 minIndex, uint256 length) = _loadBounds(storageData);

        (uint256 staleIndex, uint256 loadedData) =
            _find(storageData, blocknumber, staleBlock, minIndex, length);




        if (staleIndex > minIndex) {

            _clear(minIndex, staleIndex, storageData);

            _setBounds(storageData, staleIndex, length);
        }
        return (loadedData);
    }










    function _find(
        uint256[] storage data,
        uint256 blocknumber,
        uint256 staleBlock,
        uint256 startingMinIndex,
        uint256 length
    ) private view returns (uint256, uint256) {


        uint256 maxIndex = length - 1;
        uint256 minIndex = startingMinIndex;
        uint256 staleIndex = 0;








        while (minIndex != maxIndex) {


            uint256 mid = maxIndex + minIndex - (minIndex + maxIndex) / 2;

            (uint256 pastBlock, uint256 loadedData) = _loadAndUnpack(data, mid);


            if (pastBlock == blocknumber) {

                return (staleIndex, loadedData);


            } else if (pastBlock < blocknumber) {

                if (pastBlock < staleBlock) {

                    staleIndex = mid;
                }

                minIndex = mid;


            } else {

                maxIndex = mid - 1;
            }
        }


        (uint256 _pastBlock, uint256 _loadedData) =
            _loadAndUnpack(data, minIndex);


        require(_pastBlock <= blocknumber, "Search Failure");
        return (staleIndex, _loadedData);
    }






    function _clear(
        uint256 oldMin,
        uint256 newMin,
        uint256[] storage data
    ) private {


        assembly {


            let dataLocation := add(data.slot, 1)


            for {
                let i := oldMin
            } lt(i, newMin) {
                i := add(i, 1)
            } {

                sstore(add(dataLocation, i), 0)
            }
        }
    }





    function _loadAndUnpack(uint256[] storage data, uint256 i)
        private
        view
        returns (uint256, uint256)
    {


        uint256 loaded;
        assembly {
            loaded := sload(add(add(data.slot, 1), i))
        }

        return (
            loaded >> 192,
            loaded &
                0x0000000000000000ffffffffffffffffffffffffffffffffffffffffffffffff
        );
    }






    function _setBounds(
        uint256[] storage data,
        uint256 minIndex,
        uint256 length
    ) private {
        assembly {

            let clearedLength := and(
                length,
                0x00000000000000000000000000000000ffffffffffffffffffffffffffffffff
            )

            let minInd := shl(128, minIndex)

            let packed := or(minInd, clearedLength)

            sstore(data.slot, packed)
        }
    }





    function _loadBounds(uint256[] storage data)
        private
        view
        returns (uint256 minInd, uint256 length)
    {

        uint256 packedData;
        assembly {
            packedData := sload(data.slot)
        }

        minInd = packedData >> 128;

        length =
            packedData &
            0x00000000000000000000000000000000ffffffffffffffffffffffffffffffff;
    }
}

pragma solidity ^0.5.0;
import "./base/BaseSafe.sol";
import "./common/MasterCopy.sol";
import "./common/SignatureDecoder.sol";
import "./common/SecuredTokenTransfer.sol";
import "./interfaces/ISignatureValidator.sol";
import "./external/SafeMath.sol";





contract GnosisSafe is MasterCopy, BaseSafe, SignatureDecoder, SecuredTokenTransfer, ISignatureValidator {

    using SafeMath for uint256;

    string public constant NAME = "Gnosis Safe";
    string public constant VERSION = "0.1.0";




    bytes32 public constant DOMAIN_SEPARATOR_TYPEHASH = 0x035aff83d86937d35b32e04f0ddc6ff469290eef2f1b692d8a815c89404d4749;




    bytes32 public constant SAFE_TX_TYPEHASH = 0x14d461bc7412367e924637b363c7bf29b8f47e2f84869f4426e5633d8af47b20;




    bytes32 public constant SAFE_MSG_TYPEHASH = 0x60b3cbf8b4a223d68d641b3b6ddf9a298e7f33710cf3d3a9d1146b5a6150fbca;

    event ExecutionFailed(bytes32 txHash);

    uint256 public nonce;
    bytes32 public domainSeparator;

    mapping(bytes32 => uint256) public signedMessages;

    mapping(address => mapping(bytes32 => uint256)) public approvedHashes;






    function setup(address[] calldata _owners, uint256 _threshold, address to, bytes calldata data)
        external
    {
        require(domainSeparator == 0, "Domain Separator already set!");
        domainSeparator = keccak256(abi.encode(DOMAIN_SEPARATOR_TYPEHASH, this));
        setupSafe(_owners, _threshold, to, data);
    }














    function execTransaction(
        address to,
        uint256 value,
        bytes calldata data,
        Enum.Operation operation,
        uint256 safeTxGas,
        uint256 dataGas,
        uint256 gasPrice,
        address gasToken,
        address payable refundReceiver,
        bytes calldata signatures
    )
        external
        returns (bool success)
    {
        uint256 startGas = gasleft();
        bytes memory txHashData = encodeTransactionData(
            to, value, data, operation, 
            safeTxGas, dataGas, gasPrice, gasToken, refundReceiver, 
            nonce
        );
        require(checkSignatures(keccak256(txHashData), txHashData, signatures, true), "Invalid signatures provided");


        nonce++;
        require(gasleft() >= safeTxGas, "Not enough gas to execute safe transaction");

        success = execute(to, value, data, operation, safeTxGas == 0 && gasPrice == 0 ? gasleft() : safeTxGas);
        if (!success) {
            emit ExecutionFailed(keccak256(txHashData));
        }


        if (gasPrice > 0) {
            handlePayment(startGas, dataGas, gasPrice, gasToken, refundReceiver);
        }
    }

    function handlePayment(
        uint256 startGas,
        uint256 dataGas,
        uint256 gasPrice,
        address gasToken,
        address payable refundReceiver
    )
        private
    {
        uint256 amount = startGas.sub(gasleft()).add(dataGas).mul(gasPrice);

        address payable receiver = refundReceiver == address(0) ? tx.origin : refundReceiver;
        if (gasToken == address(0)) {

            require(receiver.send(amount), "Could not pay gas costs with ether");
        } else {
            require(transferToken(gasToken, receiver, amount), "Could not pay gas costs with token");
        }
    }


    function checkSignatures(bytes32 dataHash, bytes memory data, bytes memory signatures, bool consumeHash)
        internal
        returns (bool)
    {


        if (signatures.length < threshold * 65) {
            return false;
        }

        address lastOwner = address(0);
        address currentOwner;
        uint8 v;
        bytes32 r;
        bytes32 s;
        uint256 i;
        for (i = 0; i < threshold; i++) {
            (v, r, s) = signatureSplit(signatures, i);

            if (v == 0) {

                currentOwner = address(uint256(r));
                bytes memory contractSignature;

                assembly {

                    contractSignature := add(add(signatures, s), 0x20)
                }
                if (!ISignatureValidator(currentOwner).isValidSignature(data, contractSignature)) {
                    return false;
                }

            } else if (v == 1) {

                currentOwner = address(uint256(r));

                if (msg.sender != currentOwner && approvedHashes[currentOwner][dataHash] == 0) {
                    return false;
                }

                if (consumeHash && msg.sender != currentOwner) {
                    approvedHashes[currentOwner][dataHash] = 0;
                }
            } else {

                currentOwner = ecrecover(dataHash, v, r, s);
            }
            if (currentOwner <= lastOwner || owners[currentOwner] == address(0)) {
                return false;
            }
            lastOwner = currentOwner;
        }
        return true;
    }












    function requiredTxGas(address to, uint256 value, bytes calldata data, Enum.Operation operation)
        external
        authorized
        returns (uint256)
    {
        uint256 startGas = gasleft();


        require(execute(to, value, data, operation, gasleft()));
        uint256 requiredGas = startGas - gasleft();

        revert(string(abi.encodePacked(requiredGas)));
    }


    function approveHash(bytes32 hashToApprove)
        external
    {
        require(owners[msg.sender] != address(0), "Only owners can approve a hash");
        approvedHashes[msg.sender][hashToApprove] = 1;
    }


    function signMessage(bytes calldata _data) 
        external
        authorized
    {
        signedMessages[getMessageHash(_data)] = 1;
    }


    function isValidSignature(bytes calldata _data, bytes calldata _signature)
        external
        returns (bool isValid)
    {
        bytes32 messageHash = getMessageHash(_data);
        if (_signature.length == 0) {
            isValid = signedMessages[messageHash] != 0;
        } else {

            isValid = checkSignatures(messageHash, _data, _signature, false);
        }
    }




    function getMessageHash(
        bytes memory message
    )
        public
        view
        returns (bytes32)
    {
        bytes32 safeMessageHash = keccak256(
            abi.encode(SAFE_MSG_TYPEHASH, keccak256(message))
        );
        return keccak256(
            abi.encodePacked(byte(0x19), byte(0x01), domainSeparator, safeMessageHash)
        );
    }













    function encodeTransactionData(
        address to, 
        uint256 value, 
        bytes memory data, 
        Enum.Operation operation, 
        uint256 safeTxGas, 
        uint256 dataGas, 
        uint256 gasPrice,
        address gasToken,
        address refundReceiver,
        uint256 _nonce
    )
        public
        view
        returns (bytes memory)
    {
        bytes32 safeTxHash = keccak256(
            abi.encode(SAFE_TX_TYPEHASH, to, value, keccak256(data), operation, safeTxGas, dataGas, gasPrice, gasToken, refundReceiver, _nonce)
        );
        return abi.encodePacked(byte(0x19), byte(0x01), domainSeparator, safeTxHash);
    }













    function getTransactionHash(
        address to, 
        uint256 value, 
        bytes memory data, 
        Enum.Operation operation, 
        uint256 safeTxGas, 
        uint256 dataGas, 
        uint256 gasPrice,
        address gasToken,
        address refundReceiver,
        uint256 _nonce
    )
        public
        view
        returns (bytes32)
    {
        return keccak256(encodeTransactionData(to, value, data, operation, safeTxGas, dataGas, gasPrice, gasToken, refundReceiver, _nonce));
    }
}

