pragma solidity 0.7.5;
pragma abicoder v2;

import "@openzeppelin/contracts/math/SafeMath.sol";
import "@openzeppelin/contracts/utils/Address.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "../presets/OwnablePausable.sol";
import "../interfaces/IDepositContract.sol";
import "../interfaces/IValidators.sol";
import "../interfaces/ISolos.sol";


contract Solos is ISolos, ReentrancyGuard, OwnablePausable {
    using Address for address payable;
    using SafeMath for uint256;


    uint256 public constant VALIDATOR_DEPOSIT = 32 ether;


    mapping(bytes32 => Solo) public override solos;


    IDepositContract public override validatorRegistration;


    uint256 public override validatorPrice;


    uint256 public override cancelLockDuration;


    IValidators private validators;


    constructor(
        address _admin,
        address _validatorRegistration,
        address _validators,
        uint256 _validatorPrice,
        uint256 _cancelLockDuration
    )
        OwnablePausable(_admin)
    {
        validatorRegistration = IDepositContract(_validatorRegistration);
        validators = IValidators(_validators);


        validatorPrice = _validatorPrice;
        emit ValidatorPriceUpdated(_validatorPrice);


        cancelLockDuration = _cancelLockDuration;
        emit CancelLockDurationUpdated(_cancelLockDuration);
    }


    function addDeposit(bytes32 _withdrawalCredentials) external payable override whenNotPaused {
        require(_withdrawalCredentials != "" && _withdrawalCredentials[0] == 0x00, "Solos: invalid withdrawal credentials");
        require(msg.value > 0 && msg.value.mod(VALIDATOR_DEPOSIT) == 0, "Solos: invalid deposit amount");

        bytes32 soloId = keccak256(abi.encodePacked(address(this), msg.sender, _withdrawalCredentials));
        Solo storage solo = solos[soloId];


        solo.amount = solo.amount.add(msg.value);
        if (solo.withdrawalCredentials == "") {
            solo.withdrawalCredentials = _withdrawalCredentials;
        }



        solo.releaseTime = block.timestamp + cancelLockDuration;


        emit DepositAdded(soloId, msg.sender, msg.value, _withdrawalCredentials);
    }


    function cancelDeposit(bytes32 _withdrawalCredentials, uint256 _amount) external override nonReentrant {

        bytes32 soloId = keccak256(abi.encodePacked(address(this), msg.sender, _withdrawalCredentials));
        Solo storage solo = solos[soloId];


        require(block.timestamp >= solo.releaseTime, "Solos: current time is before release time");

        uint256 newAmount = solo.amount.sub(_amount, "Solos: insufficient balance");
        require(newAmount.mod(VALIDATOR_DEPOSIT) == 0, "Solos: invalid cancel amount");


        emit DepositCanceled(soloId, msg.sender, _amount, solo.withdrawalCredentials);

        if (newAmount > 0) {
            solo.amount = newAmount;


            solo.releaseTime = block.timestamp + cancelLockDuration;
        } else {
            delete solos[soloId];
        }


        msg.sender.sendValue(_amount);
    }


    function setValidatorPrice(uint256 _validatorPrice) external override onlyAdmin {
        validatorPrice = _validatorPrice;
        emit ValidatorPriceUpdated(_validatorPrice);
    }


    function setCancelLockDuration(uint256 _cancelLockDuration) external override onlyAdmin {
        cancelLockDuration = _cancelLockDuration;
        emit CancelLockDurationUpdated(_cancelLockDuration);
    }


    function registerValidator(Validator calldata _validator) external override whenNotPaused {
        require(validators.isOperator(msg.sender), "Solos: permission denied");


        Solo storage solo = solos[_validator.soloId];
        solo.amount = solo.amount.sub(VALIDATOR_DEPOSIT, "Solos: insufficient balance");


        validators.register(keccak256(abi.encodePacked(_validator.publicKey)));
        emit ValidatorRegistered(_validator.soloId, _validator.publicKey, validatorPrice, msg.sender);

        validatorRegistration.deposit{value : VALIDATOR_DEPOSIT}(
            _validator.publicKey,
            abi.encodePacked(solo.withdrawalCredentials),
            _validator.signature,
            _validator.depositDataRoot
        );
    }
}

pragma solidity 0.7.5;
pragma abicoder v2;

import "@openzeppelin/contracts/math/SafeMath.sol";
import "@openzeppelin/contracts/utils/Address.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "../presets/OwnablePausable.sol";
import "../interfaces/IDepositContract.sol";
import "../interfaces/IValidators.sol";
import "../interfaces/ISolos.sol";


contract Solos is ISolos, ReentrancyGuard, OwnablePausable {
    using Address for address payable;
    using SafeMath for uint256;


    uint256 public constant VALIDATOR_DEPOSIT = 32 ether;


    mapping(bytes32 => Solo) public override solos;


    IDepositContract public override validatorRegistration;


    uint256 public override validatorPrice;


    uint256 public override cancelLockDuration;


    IValidators private validators;


    constructor(
        address _admin,
        address _validatorRegistration,
        address _validators,
        uint256 _validatorPrice,
        uint256 _cancelLockDuration
    )
        OwnablePausable(_admin)
    {
        validatorRegistration = IDepositContract(_validatorRegistration);
        validators = IValidators(_validators);


        validatorPrice = _validatorPrice;
        emit ValidatorPriceUpdated(_validatorPrice);


        cancelLockDuration = _cancelLockDuration;
        emit CancelLockDurationUpdated(_cancelLockDuration);
    }


    function addDeposit(bytes32 _withdrawalCredentials) external payable override whenNotPaused {
        require(_withdrawalCredentials != "" && _withdrawalCredentials[0] == 0x00, "Solos: invalid withdrawal credentials");
        require(msg.value > 0 && msg.value.mod(VALIDATOR_DEPOSIT) == 0, "Solos: invalid deposit amount");

        bytes32 soloId = keccak256(abi.encodePacked(address(this), msg.sender, _withdrawalCredentials));
        Solo storage solo = solos[soloId];


        solo.amount = solo.amount.add(msg.value);
        if (solo.withdrawalCredentials == "") {
            solo.withdrawalCredentials = _withdrawalCredentials;
        }



        solo.releaseTime = block.timestamp + cancelLockDuration;


        emit DepositAdded(soloId, msg.sender, msg.value, _withdrawalCredentials);
    }


    function cancelDeposit(bytes32 _withdrawalCredentials, uint256 _amount) external override nonReentrant {

        bytes32 soloId = keccak256(abi.encodePacked(address(this), msg.sender, _withdrawalCredentials));
        Solo storage solo = solos[soloId];


        require(block.timestamp >= solo.releaseTime, "Solos: current time is before release time");

        uint256 newAmount = solo.amount.sub(_amount, "Solos: insufficient balance");
        require(newAmount.mod(VALIDATOR_DEPOSIT) == 0, "Solos: invalid cancel amount");


        emit DepositCanceled(soloId, msg.sender, _amount, solo.withdrawalCredentials);

        if (newAmount > 0) {
            solo.amount = newAmount;


            solo.releaseTime = block.timestamp + cancelLockDuration;
        } else {
            delete solos[soloId];
        }


        msg.sender.sendValue(_amount);
    }


    function setValidatorPrice(uint256 _validatorPrice) external override onlyAdmin {
        validatorPrice = _validatorPrice;
        emit ValidatorPriceUpdated(_validatorPrice);
    }


    function setCancelLockDuration(uint256 _cancelLockDuration) external override onlyAdmin {
        cancelLockDuration = _cancelLockDuration;
        emit CancelLockDurationUpdated(_cancelLockDuration);
    }


    function registerValidator(Validator calldata _validator) external override whenNotPaused {
        require(validators.isOperator(msg.sender), "Solos: permission denied");


        Solo storage solo = solos[_validator.soloId];
        solo.amount = solo.amount.sub(VALIDATOR_DEPOSIT, "Solos: insufficient balance");


        validators.register(keccak256(abi.encodePacked(_validator.publicKey)));
        emit ValidatorRegistered(_validator.soloId, _validator.publicKey, validatorPrice, msg.sender);

        validatorRegistration.deposit{value : VALIDATOR_DEPOSIT}(
            _validator.publicKey,
            abi.encodePacked(solo.withdrawalCredentials),
            _validator.signature,
            _validator.depositDataRoot
        );
    }
}

pragma solidity ^0.4.10;

import "../common/Owned.sol";
import "../common/SafeMath.sol";
import "./IFund.sol";


contract EtherFund is Owned, SafeMath, IFund {

    event EtherWithdrawn(address indexed receiver, address indexed to, uint256 amount);
    event EtherReceived(address indexed sender, uint256 amount);
    event ReceiverChanged(address indexed oldOne, address indexed newOne);
    event ShareChanged(address indexed receiver, uint16 share);


    mapping (address => uint16) public sharePermille;


    mapping (address => uint256) public etherBalance;


    uint public lastBalance;


    mapping (address => uint256) public lastSumDeposits;


    uint public sumDeposits;    


    function EtherFund(address receiver1, uint16 share1, address receiver2, uint16 share2) {

        require(share1 + share2 == 1000);

        sharePermille[receiver1] = share1;
        sharePermille[receiver2] = share2;

        ShareChanged(receiver1, share1);
        ShareChanged(receiver2, share2);
    }


    function () payable {
        EtherReceived(msg.sender, msg.value);
    }


    function migrate(address newFund) public ownerOnly {
        newFund.transfer(this.balance);
    }


    function copyStateFor(EtherFund otherFund, address receiver) public ownerOnly {
        sharePermille[receiver] = otherFund.sharePermille(receiver);
        etherBalance[receiver] = otherFund.etherBalance(receiver);
        lastSumDeposits[receiver] = otherFund.lastSumDeposits(receiver);

        lastBalance = otherFund.lastBalance();
        sumDeposits = otherFund.sumDeposits();
    }


    function deposits() public constant returns (uint) {
        return safeAdd(sumDeposits, safeSub(this.balance, lastBalance));
    }


    function etherBalanceOf(address receiver) public constant returns (uint) {
        return safeAdd(etherBalance[receiver], claimableEther(receiver));
    }   


    function withdraw(uint amount) public {
        withdrawTo(msg.sender, amount);
    }

    function withdrawTo(address to, uint amount) public {
        update(msg.sender);


        require(amount <= etherBalance[msg.sender]);

        etherBalance[msg.sender] = safeSub(etherBalance[msg.sender], amount);
        lastBalance = safeSub(lastBalance, amount);

        EtherWithdrawn(msg.sender, to, amount);
        to.transfer(amount);        
    }    


    function changeReceiver(address oldReceiver, address newReceiver) 
        public
        ownerOnly
    {
        sharePermille[newReceiver] = sharePermille[oldReceiver];
        sharePermille[oldReceiver] = 0;

        etherBalance[newReceiver] = etherBalance[oldReceiver];
        etherBalance[oldReceiver] = 0;

        lastSumDeposits[newReceiver] = lastSumDeposits[oldReceiver];
        lastSumDeposits[oldReceiver] = 0;

        ReceiverChanged(oldReceiver, newReceiver);
    }


    function changeShares(address receiver1, uint16 share1, address receiver2, uint16 share2)
        public 
        ownerOnly
    {

        require(share1 + share2 == sharePermille[receiver1] + sharePermille[receiver2]);

        update(receiver1);
        update(receiver2);

        sharePermille[receiver1] = share1;
        sharePermille[receiver2] = share2;

        ShareChanged(receiver1, share1);
        ShareChanged(receiver2, share2);        
    }


    function changeShares3(address receiver1, uint16 share1, address receiver2, uint16 share2, address receiver3, uint16 share3)
        public 
        ownerOnly
    {

        require(share1 + share2 + share3 == sharePermille[receiver1] + sharePermille[receiver2] + sharePermille[receiver3]);

        update(receiver1);
        update(receiver2);
        update(receiver3);

        sharePermille[receiver1] = share1;
        sharePermille[receiver2] = share2;
        sharePermille[receiver3] = share3;

        ShareChanged(receiver1, share1);
        ShareChanged(receiver2, share2);
        ShareChanged(receiver3, share3);
    }


    function update(address receiver) internal {

        if (lastBalance != this.balance) {
            sumDeposits = deposits(); 
            lastBalance = this.balance; 
        }


        etherBalance[receiver] = etherBalanceOf(receiver);


        lastSumDeposits[receiver] = sumDeposits;
    }


    function claimableEther(address receiver) internal constant returns (uint256) {
        return safeSub(deposits(), lastSumDeposits[receiver]) * sharePermille[receiver] / 1000;
    }
}

pragma solidity ^0.5.9;

import "@0x/contracts-utils/contracts/src/LibSafeMath.sol";
import "@0x/contracts-utils/contracts/src/LibRichErrors.sol";
import "./LibMathRichErrors.sol";


library LibMath {

    using LibSafeMath for uint256;







    function safeGetPartialAmountFloor(
        uint256 numerator,
        uint256 denominator,
        uint256 target
    )
        internal
        pure
        returns (uint256 partialAmount)
    {
        if (isRoundingErrorFloor(
                numerator,
                denominator,
                target
        )) {
            LibRichErrors.rrevert(LibMathRichErrors.RoundingError(
                numerator,
                denominator,
                target
            ));
        }


        partialAmount = numerator.safeMul(target).safeDiv(denominator);
        return partialAmount;
    }







    function safeGetPartialAmountCeil(
        uint256 numerator,
        uint256 denominator,
        uint256 target
    )
        internal
        pure
        returns (uint256 partialAmount)
    {
        if (isRoundingErrorCeil(
                numerator,
                denominator,
                target
        )) {
            LibRichErrors.rrevert(LibMathRichErrors.RoundingError(
                numerator,
                denominator,
                target
            ));
        }




        partialAmount = numerator.safeMul(target)
            .safeAdd(denominator.safeSub(1))
            .safeDiv(denominator);

        return partialAmount;
    }






    function getPartialAmountFloor(
        uint256 numerator,
        uint256 denominator,
        uint256 target
    )
        internal
        pure
        returns (uint256 partialAmount)
    {
        partialAmount = numerator.safeMul(target).safeDiv(denominator);
        return partialAmount;
    }






    function getPartialAmountCeil(
        uint256 numerator,
        uint256 denominator,
        uint256 target
    )
        internal
        pure
        returns (uint256 partialAmount)
    {



        partialAmount = numerator.safeMul(target)
            .safeAdd(denominator.safeSub(1))
            .safeDiv(denominator);

        return partialAmount;
    }






    function isRoundingErrorFloor(
        uint256 numerator,
        uint256 denominator,
        uint256 target
    )
        internal
        pure
        returns (bool isError)
    {
        if (denominator == 0) {
            LibRichErrors.rrevert(LibMathRichErrors.DivisionByZeroError());
        }














        if (target == 0 || numerator == 0) {
            return false;
        }










        uint256 remainder = mulmod(
            target,
            numerator,
            denominator
        );
        isError = remainder.safeMul(1000) >= numerator.safeMul(target);
        return isError;
    }






    function isRoundingErrorCeil(
        uint256 numerator,
        uint256 denominator,
        uint256 target
    )
        internal
        pure
        returns (bool isError)
    {
        if (denominator == 0) {
            LibRichErrors.rrevert(LibMathRichErrors.DivisionByZeroError());
        }


        if (target == 0 || numerator == 0) {



            return false;
        }

        uint256 remainder = mulmod(
            target,
            numerator,
            denominator
        );
        remainder = denominator.safeSub(remainder) % denominator;
        isError = remainder.safeMul(1000) >= numerator.safeMul(target);
        return isError;
    }
}

pragma solidity ^0.4.15;




contract MultiSigWallet {


    event Confirmation(address indexed sender, uint indexed transactionId);
    event Revocation(address indexed sender, uint indexed transactionId);
    event Submission(uint indexed transactionId);
    event Execution(uint indexed transactionId);
    event ExecutionFailure(uint indexed transactionId);
    event Deposit(address indexed sender, uint value);
    event OwnerAddition(address indexed owner);
    event OwnerRemoval(address indexed owner);
    event RequirementChange(uint required);


    uint constant public MAX_OWNER_COUNT = 50;


    mapping (uint => Transaction) public transactions;
    mapping (uint => mapping (address => bool)) public confirmations;
    mapping (address => bool) public isOwner;
    address[] public owners;
    uint public required;
    uint public transactionCount;

    struct Transaction {
        address destination;
        uint value;
        bytes data;
        bool executed;
    }


    modifier onlyWallet() {
        require(msg.sender == address(this));
        _;
    }

    modifier ownerDoesNotExist(address owner) {
        require(!isOwner[owner]);
        _;
    }

    modifier ownerExists(address owner) {
        require(isOwner[owner]);
        _;
    }

    modifier transactionExists(uint transactionId) {
        require(transactions[transactionId].destination != 0);
        _;
    }

    modifier confirmed(uint transactionId, address owner) {
        require(confirmations[transactionId][owner]);
        _;
    }

    modifier notConfirmed(uint transactionId, address owner) {
        require(!confirmations[transactionId][owner]);
        _;
    }

    modifier notExecuted(uint transactionId) {
        require(!transactions[transactionId].executed);
        _;
    }

    modifier notNull(address _address) {
        require(_address != 0);
        _;
    }

    modifier validRequirement(uint ownerCount, uint _required) {
        require(ownerCount <= MAX_OWNER_COUNT
            && _required <= ownerCount
            && _required != 0
            && ownerCount != 0);
        _;
    }


    function()
        payable
    {
        if (msg.value > 0)
            Deposit(msg.sender, msg.value);
    }





    function MultiSigWallet(address[] _owners, uint _required)
        public
        validRequirement(_owners.length, _required)
    {
        for (uint i=0; i<_owners.length; i++) {
            require(!isOwner[_owners[i]] && _owners[i] != 0);
            isOwner[_owners[i]] = true;
        }
        owners = _owners;
        required = _required;
    }



    function addOwner(address owner)
        public
        onlyWallet
        ownerDoesNotExist(owner)
        notNull(owner)
        validRequirement(owners.length + 1, required)
    {
        isOwner[owner] = true;
        owners.push(owner);
        OwnerAddition(owner);
    }



    function removeOwner(address owner)
        public
        onlyWallet
        ownerExists(owner)
    {
        isOwner[owner] = false;
        for (uint i=0; i<owners.length - 1; i++)
            if (owners[i] == owner) {
                owners[i] = owners[owners.length - 1];
                break;
            }
        owners.length -= 1;
        if (required > owners.length)
            changeRequirement(owners.length);
        OwnerRemoval(owner);
    }




    function replaceOwner(address owner, address newOwner)
        public
        onlyWallet
        ownerExists(owner)
        ownerDoesNotExist(newOwner)
    {
        for (uint i=0; i<owners.length; i++)
            if (owners[i] == owner) {
                owners[i] = newOwner;
                break;
            }
        isOwner[owner] = false;
        isOwner[newOwner] = true;
        OwnerRemoval(owner);
        OwnerAddition(newOwner);
    }



    function changeRequirement(uint _required)
        public
        onlyWallet
        validRequirement(owners.length, _required)
    {
        required = _required;
        RequirementChange(_required);
    }






    function submitTransaction(address destination, uint value, bytes data)
        public
        returns (uint transactionId)
    {
        transactionId = _addTransaction(destination, value, data);
        confirmTransaction(transactionId);
    }



    function confirmTransaction(uint transactionId)
        public
        ownerExists(msg.sender)
        transactionExists(transactionId)
        notConfirmed(transactionId, msg.sender)
    {
        confirmations[transactionId][msg.sender] = true;
        Confirmation(msg.sender, transactionId);
        executeTransaction(transactionId);
    }



    function revokeConfirmation(uint transactionId)
        public
        ownerExists(msg.sender)
        confirmed(transactionId, msg.sender)
        notExecuted(transactionId)
    {
        confirmations[transactionId][msg.sender] = false;
        Revocation(msg.sender, transactionId);
    }



    function executeTransaction(uint transactionId)
        public
        ownerExists(msg.sender)
        confirmed(transactionId, msg.sender)
        notExecuted(transactionId)
    {
        if (isConfirmed(transactionId)) {
            Transaction storage txn = transactions[transactionId];
            txn.executed = true;
            if (_externalCall(txn.destination, txn.value, txn.data.length, txn.data))
                Execution(transactionId);
            else {
                ExecutionFailure(transactionId);
                txn.executed = false;
            }
        }
    }



    function _externalCall(address destination, uint value, uint dataLength, bytes data) internal returns (bool) {
        bool result;
        assembly {
            let x := mload(0x40)   
            let d := add(data, 32) 
            result := call(
                sub(gas, 34710),   


                destination,
                value,
                d,
                dataLength,        
                x,
                0                  
            )
        }
        return result;
    }




    function isConfirmed(uint transactionId)
        public
        constant
        returns (bool)
    {
        uint count = 0;
        for (uint i=0; i<owners.length; i++) {
            if (confirmations[transactionId][owners[i]])
                count += 1;
            if (count == required)
                return true;
        }
    }







    function _addTransaction(address destination, uint value, bytes data)
        internal
        notNull(destination)
        returns (uint transactionId)
    {
        transactionId = transactionCount;
        transactions[transactionId] = Transaction({
            destination: destination,
            value: value,
            data: data,
            executed: false
        });

        transactionCount += 1;
        Submission(transactionId);
    }





    function getConfirmationCount(uint transactionId)
        public
        constant
        returns (uint count)
    {
        for (uint i=0; i<owners.length; i++)
            if (confirmations[transactionId][owners[i]])
                count += 1;
    }





    function getTransactionCount(bool pending, bool executed)
        public
        constant
        returns (uint count)
    {
        for (uint i=0; i<transactionCount; i++)
            if (   pending && !transactions[i].executed
                || executed && transactions[i].executed)
                count += 1;
    }



    function getOwners()
        public
        constant
        returns (address[])
    {
        return owners;
    }




    function getConfirmations(uint transactionId)
        public
        constant
        returns (address[] _confirmations)
    {
        address[] memory confirmationsTemp = new address[](owners.length);
        uint count = 0;
        uint i;
        for (i=0; i<owners.length; i++)
            if (confirmations[transactionId][owners[i]]) {
                confirmationsTemp[count] = owners[i];
                count += 1;
            }
        _confirmations = new address[](count);
        for (i=0; i<count; i++)
            _confirmations[i] = confirmationsTemp[i];
    }







    function getTransactionIds(uint from, uint to, bool pending, bool executed)
        public
        constant
        returns (uint[] _transactionIds)
    {
        uint[] memory transactionIdsTemp = new uint[](transactionCount);
        uint count = 0;
        uint i;
        for (i=0; i<transactionCount; i++)
            if (   pending && !transactions[i].executed
                || executed && transactions[i].executed)
            {
                transactionIdsTemp[count] = i;
                count += 1;
            }
        _transactionIds = new uint[](to - from);
        for (i=from; i<to; i++)
            _transactionIds[i - from] = transactionIdsTemp[i];
    }
}

pragma solidity 0.4.24;

import "./MultiSigWallet.sol";





contract MultiSigWalletWithTimeLock is
    MultiSigWallet
{
    event ConfirmationTimeSet(uint256 indexed transactionId, uint256 confirmationTime);
    event TimeLockChange(uint256 secondsTimeLocked);

    uint256 public secondsTimeLocked;

    mapping (uint256 => uint256) public confirmationTimes;

    modifier notFullyConfirmed(uint256 transactionId) {
        require(
            !isConfirmed(transactionId),
            "TX_FULLY_CONFIRMED"
        );
        _;
    }

    modifier fullyConfirmed(uint256 transactionId) {
        require(
            isConfirmed(transactionId),
            "TX_NOT_FULLY_CONFIRMED"
        );
        _;
    }

    modifier pastTimeLock(uint256 transactionId) {

        require(
            block.timestamp >= confirmationTimes[transactionId] + secondsTimeLocked,
            "TIME_LOCK_INCOMPLETE"
        );
        _;
    }





    constructor (
        address[] _owners,
        uint256 _required,
        uint256 _secondsTimeLocked
    )
        public
        MultiSigWallet(_owners, _required)
    {
        secondsTimeLocked = _secondsTimeLocked;
    }



    function changeTimeLock(uint256 _secondsTimeLocked)
        public
        onlyWallet
    {
        secondsTimeLocked = _secondsTimeLocked;
        emit TimeLockChange(_secondsTimeLocked);
    }



    function confirmTransaction(uint256 transactionId)
        public
        ownerExists(msg.sender)
        transactionExists(transactionId)
        notConfirmed(transactionId, msg.sender)
        notFullyConfirmed(transactionId)
    {
        confirmations[transactionId][msg.sender] = true;
        emit Confirmation(msg.sender, transactionId);
        if (isConfirmed(transactionId)) {
            _setConfirmationTime(transactionId, block.timestamp);
        }
    }



    function executeTransaction(uint256 transactionId)
        public
        notExecuted(transactionId)
        fullyConfirmed(transactionId)
        pastTimeLock(transactionId)
    {
        Transaction storage txn = transactions[transactionId];
        txn.executed = true;
        if (_externalCall(txn.destination, txn.value, txn.data.length, txn.data)) {
            emit Execution(transactionId);
        } else {
            emit ExecutionFailure(transactionId);
            txn.executed = false;
        }
    }


    function _setConfirmationTime(uint256 transactionId, uint256 confirmationTime)
        internal
    {
        confirmationTimes[transactionId] = confirmationTime;
        emit ConfirmationTimeSet(transactionId, confirmationTime);
    }
}

pragma solidity 0.4.24;

import "openzeppelin-solidity/contracts/math/SafeMath.sol";
import "openzeppelin-solidity/contracts/ownership/Ownable.sol";

import "./MarketSource.sol";



contract MarketOracle is Ownable {
    using SafeMath for uint256;


    MarketSource[] public _whitelist;

    event LogSourceAdded(MarketSource source);
    event LogSourceRemoved(MarketSource source);
    event LogSourceExpired(MarketSource source);



    function getPriceAnd24HourVolume()
        external
        returns (uint256, uint256)
    {
        uint256 volumeWeightedSum = 0;
        uint256 volumeSum = 0;
        uint256 partialRate = 0;
        uint256 partialVolume = 0;
        bool isSourceFresh = false;

        for (uint256 i = 0; i < _whitelist.length; i++) {
            (isSourceFresh, partialRate, partialVolume) = _whitelist[i].getReport();

            if (!isSourceFresh) {
                emit LogSourceExpired(_whitelist[i]);
                continue;
            }

            volumeWeightedSum = volumeWeightedSum.add(partialRate.mul(partialVolume));
            volumeSum = volumeSum.add(partialVolume);
        }



        uint256 exchangeRate = volumeWeightedSum.div(volumeSum);
        return (exchangeRate, volumeSum);
    }


    function addSource(MarketSource source)
        external
        onlyOwner
    {
        _whitelist.push(source);
        emit LogSourceAdded(source);
    }


    function removeSource(MarketSource source)
        external
        onlyOwner
    {
        for (uint256 i = 0; i < _whitelist.length; i++) {
            if (_whitelist[i] == source) {
                removeSourceAtIndex(i);
                break;
            }
        }
    }


    function removeDestructedSources()
        external
    {
        uint256 i = 0;
        while (i < _whitelist.length) {
            if (isContractDestructed(_whitelist[i])) {
                removeSourceAtIndex(i);
            } else {
                i++;
            }
        }
    }


    function whitelistSize()
        public
        view
        returns (uint256)
    {
        return _whitelist.length;
    }


    function isContractDestructed(address contractAddress)
        private
        view
        returns (bool)
    {
        uint256 size;
        assembly { size := extcodesize(contractAddress) }
        return size == 0;
    }


    function removeSourceAtIndex(uint256 index)
        private
    {
        emit LogSourceRemoved(_whitelist[index]);
        if (index != _whitelist.length-1) {
            _whitelist[index] = _whitelist[_whitelist.length-1];
        }

        _whitelist.length--;
    }
}

