pragma solidity 0.8.13;


import {
    ConsiderationInterface
} from "./interfaces/ConsiderationInterface.sol";


import {
    OrderType,
    ItemType,
    BasicOrderRouteType
} from "./lib/ConsiderationEnums.sol";


import {
    BasicOrderParameters,
    OfferItem,
    ConsiderationItem,
    OrderParameters,
    OrderComponents,
    Fulfillment,
    FulfillmentComponent,
    Execution,
    Order,
    AdvancedOrder,
    OrderStatus,
    CriteriaResolver,
    BatchExecution
} from "./lib/ConsiderationStructs.sol";

import { ConsiderationInternal } from "./lib/ConsiderationInternal.sol";


contract Consideration is ConsiderationInterface, ConsiderationInternal {

    constructor(
        address legacyProxyRegistry,
        address legacyTokenTransferProxy,
        address requiredProxyImplementation
    )
        ConsiderationInternal(
            legacyProxyRegistry,
            legacyTokenTransferProxy,
            requiredProxyImplementation
        )
    {}


    function fulfillBasicOrder(BasicOrderParameters calldata parameters)
        external
        payable
        override
        returns (bool)
    {

        BasicOrderRouteType route;
        OrderType orderType;


        ItemType additionalRecipientsItemType;


        assembly {

            orderType := and(calldataload(0x124), 3)


            route := div(calldataload(0x124), 4)


            additionalRecipientsItemType := gt(route, 1)
        }

        {

            bool correctPayableStatus;


            assembly {

                correctPayableStatus := eq(
                    additionalRecipientsItemType,
                    iszero(callvalue())
                )
            }



            if (!correctPayableStatus) {
                revert InvalidMsgValue(msg.value);
            }
        }


        address additionalRecipientsToken;
        ItemType receivedItemType;
        ItemType offeredItemType;


        assembly {

            let offerTypeIsAdditionalRecipientsType := gt(route, 3)


            additionalRecipientsToken := calldataload(
                add(0x24, mul(0xa0, offerTypeIsAdditionalRecipientsType))
            )



            receivedItemType := add(
                mul(sub(route, 2), gt(route, 2)),
                eq(route, 2)
            )



            offeredItemType := sub(
                add(route, mul(iszero(additionalRecipientsItemType), 2)),
                mul(
                    offerTypeIsAdditionalRecipientsType,
                    add(receivedItemType, 1)
                )
            )
        }


        _prepareBasicFulfillmentFromCalldata(
            parameters,
            orderType,
            receivedItemType,
            additionalRecipientsItemType,
            additionalRecipientsToken,
            offeredItemType
        );


        address payable offerer = parameters.offerer;


        address conduit;


        assembly {

            conduit := calldataload(add(0x1c4, mul(gt(route, 3), 0x20)))
        }


        if (route == BasicOrderRouteType.ETH_TO_ERC721) {

            _transferERC721(
                parameters.offerToken,
                offerer,
                msg.sender,
                parameters.offerIdentifier,
                parameters.offerAmount,
                conduit
            );


            _transferEthAndFinalize(parameters.considerationAmount, parameters);
        } else if (route == BasicOrderRouteType.ETH_TO_ERC1155) {

            _transferERC1155(
                parameters.offerToken,
                offerer,
                msg.sender,
                parameters.offerIdentifier,
                parameters.offerAmount,
                conduit
            );


            _transferEthAndFinalize(parameters.considerationAmount, parameters);
        } else if (route == BasicOrderRouteType.ERC20_TO_ERC721) {

            _transferERC721(
                parameters.offerToken,
                offerer,
                msg.sender,
                parameters.offerIdentifier,
                parameters.offerAmount,
                conduit
            );


            _transferERC20AndFinalize(
                msg.sender,
                offerer,
                parameters.considerationToken,
                parameters.considerationAmount,
                parameters,
                false 
            );
        } else if (route == BasicOrderRouteType.ERC20_TO_ERC1155) {

            _transferERC1155(
                parameters.offerToken,
                offerer,
                msg.sender,
                parameters.offerIdentifier,
                parameters.offerAmount,
                conduit
            );


            _transferERC20AndFinalize(
                msg.sender,
                offerer,
                parameters.considerationToken,
                parameters.considerationAmount,
                parameters,
                false 
            );
        } else if (route == BasicOrderRouteType.ERC721_TO_ERC20) {

            _transferERC721(
                parameters.considerationToken,
                msg.sender,
                offerer,
                parameters.considerationIdentifier,
                parameters.considerationAmount,
                conduit
            );


            _transferERC20AndFinalize(
                offerer,
                msg.sender,
                parameters.offerToken,
                parameters.offerAmount,
                parameters,
                true 
            );
        } else {



            _transferERC1155(
                parameters.considerationToken,
                msg.sender,
                offerer,
                parameters.considerationIdentifier,
                parameters.considerationAmount,
                conduit
            );


            _transferERC20AndFinalize(
                offerer,
                msg.sender,
                parameters.offerToken,
                parameters.offerAmount,
                parameters,
                true 
            );
        }

        return true;
    }


    function fulfillOrder(Order calldata order, address fulfillerConduit)
        external
        payable
        override
        returns (bool)
    {


        return _validateAndFulfillAdvancedOrder(
            _convertOrderToAdvanced(order),
            new CriteriaResolver[](0), 
            fulfillerConduit
        );
    }



    function fulfillAdvancedOrder(
        AdvancedOrder calldata advancedOrder,
        CriteriaResolver[] calldata criteriaResolvers,
        address fulfillerConduit
    ) external payable override returns (bool) {

        return
            _validateAndFulfillAdvancedOrder(
                advancedOrder,
                criteriaResolvers,
                fulfillerConduit
            );
    }


    function fulfillAvailableAdvancedOrders(
        AdvancedOrder[] memory advancedOrders,
        CriteriaResolver[] memory criteriaResolvers,
        FulfillmentComponent[][] memory offerFulfillments,
        FulfillmentComponent[][] memory considerationFulfillments,
        address fulfillerConduit
    )
        external
        payable
        override
        returns (
            bool[] memory availableOrders,
            Execution[] memory standardExecutions,
            BatchExecution[] memory batchExecutions
        )
    {

        _validateOrdersAndPrepareToFulfill(
            advancedOrders,
            criteriaResolvers,
            false 
        );


        (
            availableOrders,
            standardExecutions,
            batchExecutions
        ) = _fulfillAvailableOrders(
            advancedOrders,
            offerFulfillments,
            considerationFulfillments,
            fulfillerConduit
        );


        return (availableOrders, standardExecutions, batchExecutions);
    }


    function matchOrders(
        Order[] calldata orders,
        Fulfillment[] calldata fulfillments
    )
        external
        payable
        override
        returns (
            Execution[] memory standardExecutions,
            BatchExecution[] memory batchExecutions
        )
    {

        AdvancedOrder[] memory advancedOrders = _convertOrdersToAdvanced(
            orders
        );


        _validateOrdersAndPrepareToFulfill(
            advancedOrders,
            new CriteriaResolver[](0), 
            true 
        );


        return _fulfillAdvancedOrders(advancedOrders, fulfillments);
    }


    function matchAdvancedOrders(
        AdvancedOrder[] memory advancedOrders,
        CriteriaResolver[] memory criteriaResolvers,
        Fulfillment[] calldata fulfillments
    )
        external
        payable
        override
        returns (
            Execution[] memory standardExecutions,
            BatchExecution[] memory batchExecutions
        )
    {

        _validateOrdersAndPrepareToFulfill(
            advancedOrders,
            criteriaResolvers,
            true 
        );


        return _fulfillAdvancedOrders(advancedOrders, fulfillments);
    }


    function cancel(OrderComponents[] calldata orders)
        external
        override
        returns (bool)
    {

        _assertNonReentrant();

        address offerer;
        address zone;


        unchecked {

            uint256 totalOrders = orders.length;


            for (uint256 i = 0; i < totalOrders; ) {

                OrderComponents calldata order = orders[i];

                offerer = order.offerer;
                zone = order.zone;


                if (msg.sender != offerer && msg.sender != zone) {
                    revert InvalidCanceller();
                }


                bytes32 orderHash = _getOrderHash(
                    OrderParameters(
                        offerer,
                        zone,
                        order.offer,
                        order.consideration,
                        order.orderType,
                        order.startTime,
                        order.endTime,
                        order.zoneHash,
                        order.salt,
                        order.conduit,
                        order.consideration.length
                    ),
                    order.nonce
                );


                _orderStatus[orderHash].isValidated = false;
                _orderStatus[orderHash].isCancelled = true;


                emit OrderCancelled(orderHash, offerer, zone);


                ++i;
            }
        }

        return true;
    }


    function validate(Order[] calldata orders)
        external
        override
        returns (bool)
    {

        _assertNonReentrant();


        bytes32 orderHash;
        address offerer;


        unchecked {

            uint256 totalOrders = orders.length;


            for (uint256 i = 0; i < totalOrders; ) {

                Order calldata order = orders[i];


                OrderParameters calldata orderParameters = order.parameters;


                offerer = orderParameters.offerer;


                orderHash = _assertConsiderationLengthAndGetNoncedOrderHash(
                    orderParameters
                );


                OrderStatus memory orderStatus = _orderStatus[orderHash];


                _verifyOrderStatus(
                    orderHash,
                    orderStatus,
                    false, 
                    true 
                );


                if (!orderStatus.isValidated) {

                    _verifySignature(offerer, orderHash, order.signature);


                    _orderStatus[orderHash].isValidated = true;


                    emit OrderValidated(
                        orderHash,
                        offerer,
                        orderParameters.zone
                    );
                }


                ++i;
            }
        }

        return true;
    }


    function incrementNonce() external override returns (uint256 newNonce) {

        _assertNonReentrant();


        unchecked {

            newNonce = ++_nonces[msg.sender];
        }


        emit NonceIncremented(newNonce, msg.sender);
    }


    function getOrderHash(OrderComponents memory order)
        external
        view
        override
        returns (bytes32)
    {


        return _getOrderHash(
            OrderParameters(
                order.offerer,
                order.zone,
                order.offer,
                order.consideration,
                order.orderType,
                order.startTime,
                order.endTime,
                order.zoneHash,
                order.salt,
                order.conduit,
                order.consideration.length
            ),
            order.nonce
        );
    }


    function getOrderStatus(bytes32 orderHash)
        external
        view
        override
        returns (
            bool isValidated,
            bool isCancelled,
            uint256 totalFilled,
            uint256 totalSize
        )
    {

        OrderStatus memory orderStatus = _orderStatus[orderHash];


        return (
            orderStatus.isValidated,
            orderStatus.isCancelled,
            orderStatus.numerator,
            orderStatus.denominator
        );
    }


    function getNonce(address offerer)
        external
        view
        override
        returns (uint256)
    {

        return _nonces[offerer];
    }


    function DOMAIN_SEPARATOR() external view override returns (bytes32) {

        return _domainSeparator();
    }


    function name() external pure override returns (string memory) {

        return _NAME;
    }


    function version() external pure override returns (string memory) {

        return _VERSION;
    }
}

pragma solidity 0.5.4;


library AddressArrayUtils {


    function indexOf(address[] memory A, address a) internal pure returns (uint256, bool) {
        uint256 length = A.length;
        for (uint256 i = 0; i < length; i++) {
            if (A[i] == a) {
                return (i, true);
            }
        }
        return (0, false);
    }


    function contains(address[] memory A, address a) internal pure returns (bool) {
        bool isIn;
        (, isIn) = indexOf(A, a);
        return isIn;
    }



    function indexOfFromEnd(address[] memory A, address a) internal pure returns (uint256, bool) {
        uint256 length = A.length;
        for (uint256 i = length; i > 0; i--) {
            if (A[i - 1] == a) {
                return (i, true);
            }
        }
        return (0, false);
    }


    function extend(address[] memory A, address[] memory B) internal pure returns (address[] memory) {
        uint256 aLength = A.length;
        uint256 bLength = B.length;
        address[] memory newAddresses = new address[](aLength + bLength);
        for (uint256 i = 0; i < aLength; i++) {
            newAddresses[i] = A[i];
        }
        for (uint256 j = 0; j < bLength; j++) {
            newAddresses[aLength + j] = B[j];
        }
        return newAddresses;
    }


    function append(address[] memory A, address a) internal pure returns (address[] memory) {
        address[] memory newAddresses = new address[](A.length + 1);
        for (uint256 i = 0; i < A.length; i++) {
            newAddresses[i] = A[i];
        }
        newAddresses[A.length] = a;
        return newAddresses;
    }


    function sExtend(address[] storage A, address[] storage B) internal {
        uint256 length = B.length;
        for (uint256 i = 0; i < length; i++) {
            A.push(B[i]);
        }
    }


    function intersect(address[] memory A, address[] memory B) internal pure returns (address[] memory) {
        uint256 length = A.length;
        bool[] memory includeMap = new bool[](length);
        uint256 newLength = 0;
        for (uint256 i = 0; i < length; i++) {
            if (contains(B, A[i])) {
                includeMap[i] = true;
                newLength++;
            }
        }
        address[] memory newAddresses = new address[](newLength);
        uint256 j = 0;
        for (uint256 k = 0; k < length; k++) {
            if (includeMap[k]) {
                newAddresses[j] = A[k];
                j++;
            }
        }
        return newAddresses;
    }


    function union(address[] memory A, address[] memory B) internal pure returns (address[] memory) {
        address[] memory leftDifference = difference(A, B);
        address[] memory rightDifference = difference(B, A);
        address[] memory intersection = intersect(A, B);
        return extend(leftDifference, extend(intersection, rightDifference));
    }


    function unionB(address[] memory A, address[] memory B) internal pure returns (address[] memory) {
        bool[] memory includeMap = new bool[](A.length + B.length);
        uint256 count = 0;
        for (uint256 i = 0; i < A.length; i++) {
            includeMap[i] = true;
            count++;
        }
        for (uint256 j = 0; j < B.length; j++) {
            if (!contains(A, B[j])) {
                includeMap[A.length + j] = true;
                count++;
            }
        }
        address[] memory newAddresses = new address[](count);
        uint256 k = 0;
        for (uint256 m = 0; m < A.length; m++) {
            if (includeMap[m]) {
                newAddresses[k] = A[m];
                k++;
            }
        }
        for (uint256 n = 0; n < B.length; n++) {
            if (includeMap[A.length + n]) {
                newAddresses[k] = B[n];
                k++;
            }
        }
        return newAddresses;
    }


    function difference(address[] memory A, address[] memory B) internal pure returns (address[] memory) {
        uint256 length = A.length;
        bool[] memory includeMap = new bool[](length);
        uint256 count = 0;

        for (uint256 i = 0; i < length; i++) {
            address e = A[i];
            if (!contains(B, e)) {
                includeMap[i] = true;
                count++;
            }
        }
        address[] memory newAddresses = new address[](count);
        uint256 j = 0;
        for (uint256 k = 0; k < length; k++) {
            if (includeMap[k]) {
                newAddresses[j] = A[k];
                j++;
            }
        }
        return newAddresses;
    }


    function sReverse(address[] storage A) internal {
        address t;
        uint256 length = A.length;
        for (uint256 i = 0; i < length / 2; i++) {
            t = A[i];
            A[i] = A[A.length - i - 1];
            A[A.length - i - 1] = t;
        }
    }


    function pop(address[] memory A, uint256 index)
        internal
        pure
        returns (address[] memory, address)
    {
        uint256 length = A.length;
        address[] memory newAddresses = new address[](length - 1);
        for (uint256 i = 0; i < index; i++) {
            newAddresses[i] = A[i];
        }
        for (uint256 j = index + 1; j < length; j++) {
            newAddresses[j - 1] = A[j];
        }
        return (newAddresses, A[index]);
    }


    function remove(address[] memory A, address a)
        internal
        pure
        returns (address[] memory)
    {
        (uint256 index, bool isIn) = indexOf(A, a);
        if (!isIn) {
            revert();
        } else {
            (address[] memory _A,) = pop(A, index);
            return _A;
        }
    }

    function sPop(address[] storage A, uint256 index) internal returns (address) {
        uint256 length = A.length;
        if (index >= length) {
            revert("Error: index out of bounds");
        }
        address entry = A[index];
        for (uint256 i = index; i < length - 1; i++) {
            A[i] = A[i + 1];
        }
        A.length--;
        return entry;
    }


    function sPopCheap(address[] storage A, uint256 index) internal returns (address) {
        uint256 length = A.length;
        if (index >= length) {
            revert("Error: index out of bounds");
        }
        address entry = A[index];
        if (index != length - 1) {
            A[index] = A[length - 1];
            delete A[length - 1];
        }
        A.length--;
        return entry;
    }


    function sRemoveCheap(address[] storage A, address a) internal {
        (uint256 index, bool isIn) = indexOf(A, a);
        if (!isIn) {
            revert("Error: entry not found");
        } else {
            sPopCheap(A, index);
            return;
        }
    }



    function hasDuplicate(address[] memory A) internal pure returns (bool) {
        if (A.length == 0) { 
            return false;
        }
        for (uint256 i = 0; i < A.length - 1; i++) {
            for (uint256 j = i + 1; j < A.length; j++) {
                if (A[i] == A[j]) {
                    return true;
                }
            }
        }
        return false;
    }


    function isEqual(address[] memory A, address[] memory B) internal pure returns (bool) {
        if (A.length != B.length) {
            return false;
        }
        for (uint256 i = 0; i < A.length; i++) {
            if (A[i] != B[i]) {
                return false;
            }
        }
        return true;
    }


    function argGet(address[] memory A, uint256[] memory indexArray)
        internal
        pure
        returns (address[] memory)
    {
        address[] memory array = new address[](indexArray.length);
        for (uint256 i = 0; i < indexArray.length; i++) {
            array[i] = A[indexArray[i]];
        }
        return array;
    }

}

pragma solidity 0.5.4;

import { SafeMath } from "openzeppelin-solidity/contracts/math/SafeMath.sol";

import { CommonMath } from "../../../lib/CommonMath.sol";
import { ExchangeHeaderLibrary } from "../../lib/ExchangeHeaderLibrary.sol";
import { ExchangeIssuanceLibrary } from "./ExchangeIssuanceLibrary.sol";
import { ExchangeWrapperLibrary } from "../../lib/ExchangeWrapperLibrary.sol";
import { ISetToken } from "../../interfaces/ISetToken.sol";
import { ModuleCoreState } from "./ModuleCoreState.sol";



contract ExchangeExecution is
    ModuleCoreState
{
    using SafeMath for uint256;




    function executeExchangeOrders(
        bytes memory _orderData
    )
        internal
    {

        uint256 calledExchanges = 0;

        uint256 scannedBytes = 0;
        while (scannedBytes < _orderData.length) {

            ExchangeHeaderLibrary.ExchangeHeader memory header = ExchangeHeaderLibrary.parseExchangeHeader(
                _orderData,
                scannedBytes
            );


            address exchangeWrapper = coreInstance.exchangeIds(header.exchange);


            require(
                exchangeWrapper != address(0),
                "ExchangeExecution.executeExchangeOrders: Invalid or disabled Exchange address"
            );




            uint256 exchangeBitIndex = CommonMath.safePower(2, header.exchange);
            require(
                (calledExchanges & exchangeBitIndex) == 0,
                "ExchangeExecution.executeExchangeOrders: Exchange already called"
            );


            uint256 exchangeDataLength = header.orderDataBytesLength.add(
                ExchangeHeaderLibrary.EXCHANGE_HEADER_LENGTH()
            );


            bytes memory bodyData = ExchangeHeaderLibrary.sliceBodyData(
                _orderData,
                scannedBytes,
                exchangeDataLength
            );


            ExchangeWrapperLibrary.ExchangeData memory exchangeData = ExchangeWrapperLibrary.ExchangeData({
                caller: msg.sender,
                orderCount: header.orderCount
            });


            ExchangeWrapperLibrary.callExchange(
                core,
                exchangeData,
                exchangeWrapper,
                bodyData
            );


            scannedBytes = scannedBytes.add(exchangeDataLength);


            calledExchanges = calledExchanges.add(exchangeBitIndex);
        }
    }


    function calculateReceiveTokenBalances(
        ExchangeIssuanceLibrary.ExchangeIssuanceParams memory _exchangeIssuanceParams
    )
        internal
        view
        returns (uint256[] memory)
    {

        uint256[] memory requiredBalances = new uint256[](_exchangeIssuanceParams.receiveTokens.length);
        for (uint256 i = 0; i < _exchangeIssuanceParams.receiveTokens.length; i++) {

            uint256 tokenBalance = vaultInstance.getOwnerBalance(
                _exchangeIssuanceParams.receiveTokens[i],
                msg.sender
            );


            uint256 requiredAddition = _exchangeIssuanceParams.receiveTokenAmounts[i];


            requiredBalances[i] = tokenBalance.add(requiredAddition);
        }

        return requiredBalances;
    }


    function validateExchangeIssuanceParams(
        ExchangeIssuanceLibrary.ExchangeIssuanceParams memory _exchangeIssuanceParams
    )
        internal
        view
    {

        require(
            coreInstance.validSets(_exchangeIssuanceParams.setAddress),
            "ExchangeExecution.validateExchangeIssuanceParams: Invalid or disabled SetToken address"
        );


        ExchangeIssuanceLibrary.validateQuantity(
            _exchangeIssuanceParams.setAddress,
            _exchangeIssuanceParams.quantity
        );


        ExchangeIssuanceLibrary.validateSendTokenParams(
            core,
            _exchangeIssuanceParams.sendTokenExchangeIds,
            _exchangeIssuanceParams.sendTokens,
            _exchangeIssuanceParams.sendTokenAmounts
        );


        ExchangeIssuanceLibrary.validateReceiveTokens(
            _exchangeIssuanceParams.receiveTokens,
            _exchangeIssuanceParams.receiveTokenAmounts
        );
    }
}

